-- ── Hops ──────────────────────────────────────────────────────────────────────

INSERT INTO hops (id, name, alpha_pct, beta_pct, form, type, origin, notes, substitutes, hsi_pct, humulene_pct, caryophyllene_pct, cohumulone_pct, myrcene_pct) VALUES
  ('bm-hop-adeena', 'Adeena', 4.25, 3.5, 'pellet', 'Aroma', 'United States of America', 'Adeena has shown herbal and spicy flavor characteristics, with light floral, lemon and pine notes. It lends a low, smooth bitterness with a clean finish', 'Hallertau Mittelfruh, Styrian Golding', NULL, 38.0, 18.5, 36.0, 28.5),
  ('bm-hop-admiral', 'Admiral', 14.6, 5.45, 'pellet', 'Bittering', 'United Kingdom', 'Admiral hops have aroma descriptors that include pleasant, resinous hop aroma with hints of citrus (orange) and herbal flavors.  Its mild aroma characteristics make it suitable for late-hopping and dry hopping applications in combination with other varieties.', 'Target, Northdown, Challenger', 0.85, 24.5, 7.0, 41.0, 43.5),
  ('bm-hop-african-queen', 'African Queen', 13.5, 5.05, 'pellet', 'Dual', 'South Africa', 'The aroma profile of the African Queen hop includes dank, blueberries, stone fruit, black currant, gooseberries, bubble gum, lemongrass, and chilies. This hop also works well with subtle blended beers such as those with coffee, fruit, and spices. ', 'Amarillo, Cascade, Simcoe, Citra, Mosaic', NULL, 25.5, 13.5, 26.0, 24.5),
  ('bm-hop-agnus', 'Agnus', 11.5, 5.25, 'pellet', 'Bittering', 'Czech Replublic', 'Agnus hops have key flavors that include lavender, leather and tobacco.', 'Magnum (US), Nugget, Target, Columbus', NULL, 17.5, NULL, 33.5, 47.5),
  ('bm-hop-ahhhroma', 'Ahhhroma', 17.1, 7.5, 'pellet', 'Dual', 'United States of America', 'With high oil content and unusually high percentages of myrcene, Ahhhroma is an ideal hop for dry hopping. Together, its complex tropical fruit aromas are often described as “pina colada.”', NULL, NULL, 12.5, 6.5, 34.5, 55.5),
  ('bm-hop-ahtanum', 'Ahtanum', 5.0, 5.25, 'pellet', 'Aroma', 'United States of America', 'Ahtanum hops have aroma descriptors of citrus grapefruit and geranium and along with floral, piney and earth tones. Not as bitter as other hops, and used primarily for its aromatic properties.', 'Amarillo, Cascade, Centennial, Willamette', 0.7, 18.5, 10.5, 32.5, 50.0),
  ('bm-hop-akoya', 'Akoya', 9.5, 4.5, 'pellet', 'Aroma', 'Germany', 'A classic aroma hop and was crossed in the Hopsteiner breeding program from the English variety Zenith and a male Hopsteiner breeding line. The aroma of raw hops can be described as herbal, citrus and tea-like, as well as slightly fruity with mint notes. Good resistance to diseases such as downy mildew and powdery mildew and Vertilicium wilt as well as drought stress. Main growing country is Germany. ', 'Perle (US), Perle (GR), Aurora, Hallertau Tradition, Northern Brewer (US), Northern Brewer', NULL, NULL, NULL, 28.5, NULL),
  ('bm-hop-aloha', 'Aloha Blend', 9.55, NULL, 'pellet', 'Dual', 'United States of America', 'This unique BarthHaas Hop blend gives your beer an exotic boost with a flavor coming directly from Hawaii.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-altus', 'Altus', 16.75, 4.6, 'pellet', 'Aroma', 'United States of America', 'Altus has massive resinous, as well as spicy and tangerine aromas. ', 'Apollo', NULL, NULL, NULL, 27.5, NULL),
  ('bm-hop-amarillo', 'Amarillo', 9.0, 6.75, 'pellet', 'Aroma', 'United States of America', 'Amarillo hops impart a distinct flowery, spicy, tropical, citrus-like flavor and aroma in beer. The citrus has qualities of orange and lemon, like Cascade, but much stronger. Other aroma descriptors include grapefruit, melon, apricot and peach.

Amarillo hops offer solid bittering properties in the 9-11% Alpha Acid range. It also packs one of the highest myrcene oil contents (60-70% of total oils) of any hop. This extremely high Myrcene content gives it a very sweet citrus flavor and aroma that is closer to oranges than grapefruit.

Amarillo has become one of craft brewer''s most favorite hops. It is often paired with Citra, Simcoe, and Mosaic in many juicy IPAs and pale ales.', 'Cascade, Centennial, Chinook, Summer, Simcoe', 0.3195, 21.5, 8.5, 22.5, 55.0),
  ('bm-hop-amethyst', 'Amethyst', 4.75, 7.5, 'pellet', 'Aroma', 'Czech Replublic', 'The Amethyst hops have aroma characters that include subtl citrus, earthy and spicy notes.', NULL, NULL, 19.0, 6.0, 24.0, 42.0),
  ('bm-hop-apollo', 'Apollo', 17.75, 6.75, 'pellet', 'Bittering', 'United States of America', 'Apollo is a super high-alpha variety with a low cohumulone level that makes it an excellent bittering hop. When Apollo is used toward the end of the boil it can contribute flavors and aromas of citrus (lime), grapefruit, orange, pine, resin, and cannabis.', 'Magnum (US), Magnum (GR), Columbus, Tomahawk, Zeus, CTZ, Nugget', 0.15, 27.5, 17.0, 25.5, 40.0),
  ('bm-hop-apolon', 'Apolon', 11.0, 4.0, 'pellet', 'Dual', 'Slovenia', 'Traditionally used solely for bittering, Apolon hops can be used as both an aroma and a bittering hop and is considered excellent for both. ', NULL, 0.43, 26.0, 4.0, 2.25, 63.0),
  ('bm-hop-aquila', 'Aquila', 7.7, 3.95, 'pellet', 'Aroma', 'United States of America', 'No longer in production. 

Aquila hops had limited use due to high cohumolone levels.', 'Cluster, Galena', 0.6, 2.0, 5.0, 46.0, 62.0),
  ('bm-hop-aramis', 'Aramis', 7.0, 4.25, 'pellet', 'Aroma', 'France', 'Aramis is an aroma variety with sweet and spicy characteristics. It resembles Strisselspalt, but contains higher oil and alpha content. Specific aroma descriptors include spicy, herbal and subtle citrus.', 'Willamette, Challenger, Ahtanum, Centennial, Strisselspalt, EKG, Saaz (US), Hallertau Mittelfruh', NULL, 20.5, 5.0, 31.0, 39.5),
  ('bm-hop-arcadian', 'Arcadian', 9.8, 7.5, 'pellet', 'Aroma', 'United States of America', 'Noted aromas of the Arcadian hop includes light floral and orange and/or tangerine.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-archer', 'Archer', 5.0, 2.5, 'pellet', 'Aroma', 'United Kingdom', 'Archer hops are said to have delicate and soft apricot, floral, lime and peach aromas. It combines classic assertive British aroma with a citrus twist. This hop can be useful when used as a dry hop addition.', NULL, NULL, 28.0, NULL, 35.0, 22.5),
  ('bm-hop-ariana', 'Ariana', 11.0, 5.25, 'pellet', 'Aroma', 'Germany', 'Ariana hops have key flavors that include passion fruit, pineapple, jasmine and tangerine. It is also fruity, with intense berry character of black currant and gooseberry. Also has citrus high notes (particularly grapefruit) with slight resinous and herbal tones', 'Huell Melon, Mandarina Bavaria, Hallertau Blanc', NULL, NULL, NULL, 41.0, 58.0),
  ('bm-hop-astra', 'Astra', 8.5, 5.0, 'pellet', 'Dual', 'Australia', 'Astra hops have sweet tropical fruit flavors and New World characteristics. Flavor profiles with green melon, white peaches, white wine and a light grassiness, grapefruit and honey, the hop balances out nicely between a sweetness with a bit of a bite.', NULL, NULL, 7.0, 2.5, 27.0, NULL),
  ('bm-hop-atlas', 'Atlas', 8.0, 4.0, 'pellet', 'Dual', 'Slovenia', 'Atlas has intense aroma notes of lime, floral (blossom) and pine.', NULL, NULL, 9.0, 4.0, 37.0, 58.5),
  ('bm-hop-aurora', 'Aurora', 9.75, 4.1, 'pellet', 'Dual', 'Slovenia', 'Aurora hops have aroma descriptors that include floral, spice and lemongrass. It displays intense yet pleasant aroma in finished beers.', 'Styrian Golding, Perle (GR), Perle (US), Northern Brewer (US), Northern Brewer (GR)', 0.275, 22.5, 7.5, 23.0, 22.5),
  ('bm-hop-aurum', 'Aurum', 4.6, 3.1, 'pellet', 'Aroma', 'Germany', 'Aurum hops combine hoppy nuances with a fruity taste. They are suitable for classic German beers with spicy, fruity and floral aromas. It has exceptionally fine and delicate classic hop aromas with spicy-herbal notes and - depending on the timing of its addition - fresh citrus aromas. ', NULL, NULL, NULL, NULL, 21.5, NULL),
  ('bm-hop-azacca', 'Azacca', 15.0, 4.75, 'pellet', 'Dual', 'United States of America', 'Azacca has an amazingly refreshing aroma. It''s descriptions usually include aromas and flavors of mango, papaya, orange, grapefruit, lemon, pine, spice, pineapple, grassy, tropical fruit, and citrus. However, the Azacca hop has a very delicate hop aroma that can be easily overpowered by other hops and flavors. ', 'Amarillo, Citra, Delta, Pekko', 0.241, 16.0, 10.0, 41.5, 50.5),
  ('bm-hop-banner', 'Banner', 10.75, 6.65, 'pellet', 'Bittering', 'United States of America', 'Banner is no longer in production.

It had high alpha-acids and a pleasant aroma, but due to poor stability and disease susceptibility, it was never commercially viable.', 'Aquila, Cluster, Galena', 0.57, NULL, NULL, 34.0, NULL),
  ('bm-hop-barbe-rouge', 'Barbe Rouge', 6.9, 3.95, 'pellet', 'Aroma', 'France', 'The Barbe Rouge hop is an aroma variety that features notes of citrus fruit and fine red berries. Kumquat, orange, lime, redcurrant, strawberry, and raspberry are all represented in Barbe Rouge’s delicate aromatic attributes.', NULL, NULL, 20.0, 3.0, 26.0, 47.5),
  ('bm-hop-beata', 'Beata', 6.0, 10.0, 'pellet', 'Bittering', 'United Kingdom', 'The high beta acid of the Beata hop means that its bitterness utilization is very good. It also has notes of almonds, honey and apricots.', NULL, NULL, 6.0, NULL, 25.5, 28.0),
  ('bm-hop-belma', 'Belma', 10.3, 6.0, 'pellet', 'Dual', 'United States of America', 'Belma has been tested as a dual-use hop and found to have an ambrosial mix of orange, melon, strawberry and pineapple with a slight hint of grapefruit', 'Huell Melon, Pacific Gem', 0.275, NULL, NULL, NULL, 66.5),
  ('bm-hop-bergamot', 'Bergamot', 9.35, 7.45, 'pellet', 'Dual', 'United States of America', 'Bergamot subtly nicknamed "O.A.F." by the brewers in the GLH Brew Group that have crafted incredible first round trial brews with this hop.  There is no lack of orange in this hop.  You won''t need to garnish your beer with an orange slice ever again.  ', 'XJA2-436', NULL, 14.5, 9.5, 39.5, 44.5),
  ('bm-hop-bianca', 'Bianca', 7.5, 3.4, 'pellet', 'Aroma', 'United States of America', 'While not bred for commercial use, it is said that the Bianca cones can be used for flavoring if a Saazer-style aroma and taste is desired. Sunbeam, Bianca’s half-sister has similar characteristics. ', 'Sunbeam', NULL, NULL, NULL, 24.0, NULL),
  ('bm-hop-bitter-gold', 'Bitter Gold', 15.4, 6.25, 'pellet', 'Dual', 'United States of America', 'Bitter Gold offers limited aroma when used as a bittering hop but delivers diverse stone and tropical fruit flavors in later additions.', 'Galena, Nugget', NULL, 12.5, 9.0, 38.5, 56.5),
  ('bm-hop-boadicea', 'Boadicea', 8.75, 3.85, 'pellet', 'Dual', 'United Kingdom', 'Boadicea hops have aroma descriptors that include floral, orchard blossom and ripe fruit.', 'Green Bullet, Cascade, Chinook', NULL, 20.0, 17.0, 26.0, 35.0),
  ('bm-hop-bobek', 'Bobek', 6.4, 5.3, 'pellet', 'Bittering', 'Slovenia', 'Bobek has aroma descriptors that include intense and pleasant with floral and pine overtones.', 'Fuggle, Styrian Golding, Willamette', NULL, 16.0, 5.0, 28.5, 37.5),
  ('bm-hop-bohemie', 'Bohemie', 6.5, 7.5, 'pellet', 'Aroma', 'Czech Replublic', 'Bohemie hops are suitable for second hop addition.', NULL, NULL, 20.0, 8.5, 24.5, 37.5),
  ('bm-hop-boomerang', 'Boomerang', 12.0, 7.5, 'pellet', 'Dual', 'Czech Replublic', 'The Boomerang hop aroma is intensively spicy and citrusy. Boomerang is suitable for all hop additions.', NULL, NULL, 20.5, 9.0, 29.5, 41.5),
  ('bm-hop-bor', 'Bor', 7.5, 4.25, 'pellet', 'Dual', 'Czech Replublic', 'Bor, which means pine, is a dual purpose variety named after the pinewoods which are typical for a region in the Czech Republic. ', NULL, NULL, NULL, NULL, 24.5, NULL),
  ('bm-hop-bouclier', 'Bouclier', 6.15, 2.85, 'pellet', 'Aroma', 'France', 'Bouclier’ s combination of French and English aromas allows it to bring a French touch to English-style beers. It has aroma descriptors that include herbal, grass and spicy. Sometime referred to as "Shield".', NULL, NULL, 34.0, 3.5, 44.5, 38.0),
  ('bm-hop-bramling-cross', 'Bramling Cross', 6.5, 2.75, 'pellet', 'Dual', 'United Kingdom', 'Bramling Cross hops have aroma descriptors that include strong spice, blackcurrant, loganberry and lemon.  It is often used in traditional cask conditioned beers due to its distinct characteristics.', 'East Kent Goldings, Bullion, Northern Brewer (US), Northern Brewer (GR), Galena', NULL, 30.0, 15.0, 34.0, 36.0),
  ('bm-hop-bravo', 'Bravo', 15.5, 4.25, 'pellet', 'Bittering', 'United States of America', 'The Bravo hops have aroma descriptors include orange, vanilla and floral.  It is an excellent bittering variety and can provide pleasant fruit and sweet floral aroma characteristics in some applications.', 'Columbus, Tomahawk, Zeus, CTZ, Zeus, Chinook, Centennial, Nugget', 0.3, 14.0, 7.0, 31.5, 42.5),
  ('bm-hop-brewers-gold', 'Brewer''s Gold (GR)', 6.15, 3.3, 'pellet', 'Bittering', 'Germany', 'Brewer''s Gold hops have aroma descriptors that include blackcurrant, fruity, and spicy.', 'Chinook, Galena, Nugget, Brewer''s Gold (US)', 0.258, 30.0, 7.5, 43.5, 45.0),
  ('bm-hop-brewers-gold-us', 'Brewer''s Gold (US)', 9.5, 5.25, 'pellet', 'Bittering', 'United States of America', 'It is an English variety, however American-grown Brewer’s Gold contains higher levels of alpha acids than its English counterpart. This hop has hints of black currant and spicy aromas.', 'Galena, Brewer''s Gold, Chinook, Galena, Nugget', NULL, 15.0, 10.0, 44.0, 50.0),
  ('bm-hop-brooklyn', 'Brooklyn', 18.5, 9.0, 'pellet', 'Dual', 'New Zealand', 'Brooklyn was renamed Moutere (due to a certain brewery in NYC taking notice).

Brooklyn is a big hop with high alpha acid content, however, sensory panels have also indicated the presence of grapefruit, tropical fruit and passion fruit characteristics. Delivers intense fruity oils with top notes of baking spice and sweet hay.', 'Moutere', NULL, NULL, NULL, 26.0, NULL),
  ('bm-hop-bru-1', 'BRU-1', 14.0, 9.0, 'pellet', 'Aroma', 'United States of America', 'BRU-1 hops offer true pineapple flavor. BRU-1 is notable for its distinct sweet fruit aroma that is often described as pineapple. When used as a whirlpool or dry hop addition, BRU-1 delivers the aroma of freshly cut pineapple and green fruits. BRU-1 is synergistic with other hops creating a depth of fruit flavor. BRU-1 has also been shown to improve haze stability in certain beer styles.', NULL, NULL, 7.5, 10.0, 36.0, 52.5),
  ('bm-hop-bullion', 'Bullion', 8.9, 5.5, 'pellet', 'Dual', 'United States of America', 'Bullion hops have strong and zesty blackcurrant characteristics.', 'Brewers Gold, Northern Brewer (US), Northern Brewer (GR), Galena, Bramling Cross, Mount Ranier', NULL, 20.0, 11.5, 48.5, 47.5),
  ('bm-hop-buzz-bullets', 'Buzz Bullets', 9.0, 5.5, 'pellet', 'Dual', 'United States of America', 'Buzz Bullets is a hop blend with citrus and floral notes. It is also known to have clean bitterness.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-caliente', 'Caliente', 15.0, 4.3, 'pellet', 'Dual', 'United States of America', 'Caliente hops have flavors of citrus (lemon zest), peach and pine, with aromas of stone fruit and mandarin. While "caliente" means "hot" in Spanish, this hop is not spicy.', NULL, NULL, NULL, NULL, 35.0, NULL),
  ('bm-hop-callista', 'Callista', 3.5, 7.5, 'pellet', 'Aroma', 'Germany', 'Key flavors of the Callista hop include strawberry, pear, caramel, passion fruit and orange. Callista kicks off intense fruit flavors of passion fruit, apricot, peach, and blackberry, plus some pine. Low alpha acids ensure this will be a late-addition hop.', 'Hallertau Tradition, Grungeist', NULL, NULL, NULL, 18.5, 63.5),
  ('bm-hop-calypso', 'Calypso', 14.0, 5.5, 'pellet', 'Dual', 'United States of America', 'The Calypso hop has a crisp and fruity aroma. Flavors of apples, pears, stone fruit and lime citrus also are noted.', 'Galena, Cascade, Huell Melon, Belma', 0.325, 27.5, 12.0, 40.0, 37.5),
  ('bm-hop-canadian-redvine', 'Canadian Redvine', 5.5, 5.5, 'pellet', 'Aroma', 'Canada', 'Canadian Redvine has such a high cohumulone content and low alphas, it is not commonly used. It is said to impart mild flavors of cherry, berries, pine and even citrus like grapefruit. Some brewers have reported a catty character. ', 'Newport,Magnum,Galena,Cascade', 0.2, 2.0, 2.0, 47.0, 70.0),
  ('bm-hop-cascade', 'Cascade', 6.75, 6.15, 'pellet', 'Dual', 'United States of America', 'Cascade is the hop variety that made hops famous. It single-handedly defined the American Pale Ale style. 

Defined by its citrus, and often more specifically grapefruit flavor, this hop accounts for around 10% of the US''s harvest of hops. Cascade also has a medium-intense floral and spice citrus qualities. When used as a bittering hop, it imparts moderate bitterness. It is most famous for being the finishing hop in Sierra Nevada''s Pale Ale, widely considered the beer that launched the IPA and bitter beer craze.

Cascade hops are widely available and are grown in multiple countries. It is usually packaged hop pellets, but is sometimes available fresh around harvest time. Cascade hops can grown at home since they are not a trademarked variety.', 'Amarillo, Centennial, Ahtanum, Summit', 0.3605, 14.0, 6.0, 35.0, 52.5),
  ('bm-hop-cashmere', 'Cashmere', 8.4, 5.2, 'pellet', 'Dual', 'United States of America', 'Cashmere has a complex and intensely fruity aroma, with strong overtones of lemon, lime, peach, and melon. Secondary notes of coconut, lemongrass, candy, and herbs can show through in whirlpool or dry hop additions', 'Cascade', 0.2575, 27.5, 12.0, 23.0, 40.5),
  ('bm-hop-cekin', 'Cekin', 7.0, 2.5, 'pellet', 'Aroma', 'Slovenia', 'Cekin, along with its sibling, Cicero, is not grown in large quantities. Cekin is said to have a pleasing, distinctive and continental aroma comparable to Styrian Golding. Very little Cekin is grown commercially due to lack of acceptance by breweries.', 'Styrian Golding, Brewers Gold, Aurora', 0.245, 16.5, 6.5, 23.5, 47.5),
  ('bm-hop-celeia', 'Celeia', 4.5, 3.0, 'pellet', 'Aroma', 'Slovenia', 'Specific aroma descriptors of this hop include noble characteristics. It is distinctively more floral than Styrian Golding or Fuggle hops.', 'Styrian Golding, Bobek, Saaz (CZ)', NULL, 20.5, 8.5, 27.0, 30.5),
  ('bm-hop-centennial', 'Centennial', 9.5, 4.5, 'pellet', 'Dual', 'United States of America', 'Centennial hops are very similar to Cascade and are characterized by aromatic pine, citrus, and floral notes. It is characterized as having rounded and medium intense floral, citrus and grapefruit flavors and aromas. Other flavors of the Centennial hop include pine needles and tangerines.', 'Cascade, Chinook, Columbus, Tomahawk, Zeus, CTZ, Amarillo', 0.2925, 15.0, 6.0, 26.5, 60.0),
  ('bm-hop-challenger', 'Challenger', 7.75, 3.75, 'pellet', 'Dual', 'United Kingdom', 'Challenger hops have aroma descriptors that include cedar, green tea and sweet fruit.  It is a versatile variety with wide application in both
early and late kettle additions.', 'Northern Brewer (US), Northern Brewer (GR), Perle (US), Target, Northdown', NULL, 25.0, 9.5, 22.5, 36.0),
  ('bm-hop-chelan', 'Chelan', 13.5, 9.25, 'pellet', 'Bittering', 'United States of America', 'Chelan is a bittering hop that has mild fruity, floral and citrus aromas.', 'Galena, Nugget', NULL, 13.5, 10.5, 34.0, 50.0),
  ('bm-hop-chinook', 'Chinook', 13.25, 3.5, 'pellet', 'Dual', 'United States of America', 'Chinook can be slightly spicy and have a smoky earthiness quality. It has an impressive pine and resin character, with distinct spice and grapefruit. Use sparingly in the boil as it can add a harsh bitterness if overused.', 'Nugget, Columbus, Tomahawk, Zeus, CTZ, Northern Brewer (US), Galena', 0.287, 21.0, 10.0, 31.0, 25.0),
  ('bm-hop-citra', 'Citra', 12.5, 3.75, 'pellet', 'Dual', 'United States of America', 'The Citra hop is a high alpha acid hop with a strong, yet smooth floral and citrus aroma and flavor. It has specific aroma descriptors that include grapefruit, citrus, peach, melon, lime, gooseberry, passion fruit and lychee. These tropical fruit flavors have made Citra the most popular hop to craft brewers in the world. 

Citra adds a smooth bitterness when added to the boil. This is due to Citra having a fairly high alpha acids percentage, while also having enough flavor and aroma to be considered an aroma hop. 

Citra overtook Cascade as the most grown hop variety in 2018 and has yet to relinquish that title. Citra has redefined what could be expected out of a hop. It helped push IPAs to the forefront of craft brewing popularity with its extreme citrus flavors.', 'Simcoe, Mosaic, Centennial, Cascade', 0.2655, 10.0, 6.5, 27.5, 65.0),
  ('bm-hop-cluster', 'Cluster', 7.25, 5.25, 'pellet', 'Dual', 'United States of America', 'Cluster has specific aroma descriptors that include floral, earthy and sweet fruit. Cluster is an excellent dual-purpose hop and is often used in the reproduction of historical beer styles.', 'Galena, Chinook, Eroica, Nugget', NULL, 17.5, 9.0, 38.0, 42.0),
  ('bm-hop-cluster-fugget', 'Cluster Fugget Blend', 8.1, 4.1, 'pellet', 'Dual', 'United States of America', 'Cluster Fugget™ is a spontaneous hop blend that is just that...a cluster Fugget of Pacific Northwestern varieties, capturing the adventurous spirit of the home brewing community. Whether it is your first batch, or your one-hundredth, every home brewer has wound up brewing a beer with a cluster Fugget of aromas and flavors. This hop blend was created in celebration of these fortunate mistakes, reminding us that no brew should be taken too seriously.', 'Cluster, Fuggle, Nugget', NULL, 27.5, 11.5, 33.5, 26.5),
  ('bm-hop-columbia', 'Columbia', 7.0, 3.5, 'pellet', 'Dual', 'United States of America', 'The aroma of the Columbia hop is similar to that of Chinook, but not as strong. It includes crisp pineapple, bright and pungent lemon-citrus notes.', 'Centennial, Chinook', NULL, 17.0, 10.5, 40.0, 50.0),
  ('bm-hop-columbus', 'Columbus', 16.0, 5.25, 'pellet', 'Dual', 'United States of America', 'Specific aroma descriptors of the Columbus hop includes earthiness, black pepper, licorice, spice (curry) and subtle citrus. The floral and citrus notes from the Columbus hop come out in both aroma and flavor, but can be pungent. This strong flavor and aroma make the Columbus hop great for late additions to a boil or dry-hopping. ', 'CTZ, Tomahawk, Zeus, Centennial, Chinook, Galena, Nugget, Millennium', 0.45, 11.5, 8.0, 31.5, 50.0),
  ('bm-hop-comet', 'Comet', 10.2, 4.55, 'pellet', 'Dual', 'United States of America', 'Comet hops have aroma descriptors that include subtle, wild American grassy and grapefruit. ', 'Galena, Citra', 0.326, 1.5, 10.0, 39.5, 52.5),
  ('bm-hop-contessa', 'Contessa', 4.0, 6.2, 'pellet', 'Bittering', 'United States of America', 'This noble hop variety elicits aromas of green tea, floral, lemongrass and light pear. According to Hopsteiner, Contessa''s aroma lends a smooth and delicate bitterness while delivering an elegant fragrance, making it a perfect fit for the lager beer style and unique addition to many others.  ', NULL, NULL, NULL, NULL, 30.5, NULL),
  ('bm-hop-crystal', 'Crystal', 4.4, 6.5, 'pellet', 'Aroma', 'United States of America', 'The Crystal hop has aromas of woods, green, floral and fruity with herb and spice notes of cinnamon, nutmeg and black pepper.', 'Mount Hood, Hersbrucker, Strisselspalt, Liberty, Ultra, Hallertau', 0.3005, 25.0, 8.5, 23.0, 42.5),
  ('bm-hop-ctz', 'CTZ', 15.75, 5.0, 'pellet', 'Dual', 'United States of America', 'CTZ hops have aroma descriptors that include black pepper, licorice, curry and subtle citrus. CTZ stands for (Columbus Tomahawk and Zeus), which are three slightly different varieties. All have virtually identical brewing values and aromas. It can be used in the boil, whirlpool or via dry hopping. ', 'Columbus, Tomahawk, Zeus', 0.249, 11.5, 8.0, 31.5, 50.0),
  ('bm-hop-dana', 'Dana', 10.1, 4.35, 'pellet', 'Dual', 'Slovenia', 'The Dana hop displays subtle floral, lemon and pine aroma characteristics.', 'Fuggle, Willamette', NULL, 23.5, 6.0, 26.5, 44.0),
  ('bm-hop-defender', 'Defender', 4.65, 1.8, 'pellet', 'Aroma', 'United Kingdom', 'Defender hops add a pleasant, European-style aroma.', NULL, 0.41, 35.0, 14.0, 27.5, 31.0),
  ('bm-hop-delta', 'Delta', 6.25, 6.25, 'pellet', 'Aroma', 'United States of America', 'Delta hops have a mild and pleasant aroma that is slightly spicy with a hint of citrus and melon.', 'Fuggle, Willamette, Cascade', 0.15, 30.0, 12.0, 23.0, 32.5),
  ('bm-hop-diamant', 'Diamant', 7.25, NULL, 'pellet', 'Aroma', 'Germany', 'Diamant is a further extension of the Saaz range with improved plant health and higher agronomic performance compared to the mother "Spalter". With its classic fresh, hoppy aroma profile, Diamant is particularly suitable for harmonious lager beers with a fine hop aroma.', NULL, NULL, NULL, NULL, 19.0, NULL),
  ('bm-hop-diamond-springs', 'Diamond Springs', 4.83, 3.18, 'pellet', 'Aroma', 'United States of America', 'Diamond Springs hops have an interesting aroma according to their breeder GLH. Aromas include bright citrus, lemon and mint.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-dr-rudi', 'Dr. Rudi', 11.0, 7.75, 'pellet', 'Dual', 'New Zealand', 'Dr. Rudi hops have specific aroma descriptors that include resin, pine, and lemongrass.', 'Green Bullet', NULL, 33.5, 10.0, 37.5, 29.0),
  ('bm-hop-east-kent-goldings', 'East Kent Goldings', 5.25, 2.7, 'pellet', 'Bittering', 'United Kingdom', 'East Kent Golding hops have aroma descriptors that include smooth and delicate with floral, lavender, spice, honey, earth, lemon and thyme overtones.', 'Golding, Fuggle, Willamette', 0.22, 41.0, 14.0, 26.0, 30.0),
  ('bm-hop-eclipse', 'Eclipse', 17.35, 7.45, 'pellet', 'Dual', 'Australia', 'When Eclipse is used in the whirlpool and dry hop, it brings an unmistakably sweet mandarin flavor to beer with strong notes of citrus peel and fresh pine needles.', NULL, NULL, 1.0, 9.0, 35.0, 42.0),
  ('bm-hop-ekuanot', 'Ekuanot', 14.25, 4.75, 'pellet', 'Aroma', 'United States of America', 'Ekuanot has fruity aromatics such as lemon, lime, pithy orange, tropical fruit, berry, papaya, and sometimes apple. Along with these there may be more herbal notes, such as sage and eucalyptus.', 'Chinook, Summit, Galena, Cluster', NULL, 16.0, 10.0, 34.5, 37.5),
  ('bm-hop-el-dorado', 'El Dorado', 15.0, 7.2, 'pellet', 'Dual', 'United States of America', 'El Dorado hops elicit responses of fruity notes and tropical fruit flavors. When used as a bittering hop, El Dorado lends a soft and balanced bitterness. When used in later additions El Dorado brings bright tropical fruit flavors and aromas of pear, watermelon, candy and stone fruit.', 'Citra, Nelson Sauvin, Rakau', 0.3635, 12.5, 7.0, 30.5, 57.5),
  ('bm-hop-elixir', 'Elixir', 5.8, 5.55, 'pellet', 'Aroma', 'France', 'Elixir is a robust and complex hop that offers unique aromas of Cognac, leather, and tobacco. It has complementary aromas of sweet citrus and tropical fruits. Elixir is well suited for darker styles but can also be incorporated into fruit-forward styles or even spicy saisons.', NULL, NULL, 1.5, 26.5, 27.5, 70.0),
  ('bm-hop-ella', 'Ella', 16.25, 5.9, 'pellet', 'Dual', 'Australia', 'Ella a pleasant floral aroma that is backed by soft spice and also has described to include distinct grapefruit and tropical flavors.  It is reminiscent of a noble variety in lower doses, but imparts strong tropical fruit flavors in larger additions.', 'Perle (US), Palisade, Galaxy', NULL, 18.5, 11.5, 36.5, 42.0),
  ('bm-hop-emerald-spire', 'Emerald Spire', 10.8, 4.0, 'pellet', 'Dual', 'United States of America', 'The Emerald Spire hop is pleasant, fruit forward and delicious.  If the smell of the cones doesn''t make your mouth water the first sip of any beer with this hop as the star of the show sure will. ', NULL, NULL, 10.5, 7.5, 38.5, 36.5),
  ('bm-hop-endeavour', 'Endeavour', 7.8, 4.55, 'pellet', 'Dual', 'United Kingdom', 'Complex blackcurrant, loganberry and spice notes best describe Endeavour''s aroma, with a wonderful grapefruit and lime flavour. It is gentler than Cascade.', 'Bramling Cross, Pilgrim', NULL, 6.5, NULL, 33.0, 32.0),
  ('bm-hop-enigma', 'Enigma', 16.45, 5.8, 'pellet', 'Aroma', 'Australia', 'The Enigma hop has distinct tropical fruit, berry, stone fruit aroma descriptors. It also has hints of juicy red fruits like raspberries and red currants, but what sets it apart from other varieties are the white wine notes.', 'Nelson Sauvin, Hallertau Blanc', 0.295, 15.5, 7.0, 40.0, 26.5),
  ('bm-hop-epic', 'Epic', 4.0, 2.1, 'pellet', 'Aroma', 'United Kingdom', 'Early brewing with the Epic hop indicates medium intensity, deep fruit and berry-like aromas without any citrus or floral notes. Epic is an excellent late aroma hop. Well balanced, rounded, mild and fruity when used in bittering addition.', NULL, NULL, 42.0, 1.5, 31.5, 11.5),
  ('bm-hop-equinox', 'Equinox', 15.0, 5.0, 'pellet', 'Aroma', 'United States of America', 'Notes of lemon and lime citrus, fruits like papaya and apple, green peppers and herbs', 'Ekuanot', NULL, NULL, NULL, 35.0, NULL),
  ('bm-hop-ernest', 'Ernest', 5.35, 5.0, 'pellet', 'Aroma', 'United Kingdom', 'Aroma: Fruity - apricot, citrus and spice.
Bittering: It has clear ''New World'' characteristics producing a complex flavour with predominantly fruity notes, especially apricot, citrus and spice.', NULL, NULL, 10.0, 0.5, 52.5, 55.0),
  ('bm-hop-eroica', 'Eroica', 11.1, 4.15, 'pellet', 'Bittering', 'United States of America', 'Flavor-wise, the Eroica hop features a sharp fruity essence. It is primarily used as a bittering hop.', 'Brewer''s Gold, Chinook, Cluster, Galena, Nugget', NULL, 0.5, 10.0, 40.0, 60.0),
  ('bm-hop-eureka', 'Eureka', 18.5, 5.25, 'pellet', 'Dual', 'United States of America', 'The Eureka hop has bold aromas of herbal notes, mint, pine, and other dark fruits. Other flavors include citrus and peach, aromas of stone fruit, blackcurrant and mandarin. Hopsteiner''s Eureka! hop has high notes of fruit and citrus, but it is most well known for its herbal flavors. Coming in with an average of 3.5mL hop oils per 100g of hops, Eureka is loaded with flavorful oils to bring out it''s mint and dank aromas. ', 'Columbus, Tomahawk, Zeus, CTZ, Apollo, Merkur, Simcoe, Summit', NULL, 29.5, 0.5, 28.5, 43.0),
  ('bm-hop-evergreen', 'Evergreen Blend', 7.25, 4.4, 'pellet', 'Aroma', 'United States of America', 'Evergreen announces its presence with strong suggestions of fresh peach and apricot, bright citrus (lemon candy
orange zest, tangerine), and watermelon candy. Green notes of fresh hay and pine needles round out a classic American craft beer hop profi le. Secondary and tertiary notes include menthol, dank, geranium, herbs (basil, dill, thyme), cannabis, and green tea.
', NULL, NULL, 21.0, 11.0, NULL, 31.0),
  ('bm-hop-falconers-flight', 'Falconer''s Flight', 10.75, 4.5, 'pellet', 'Aroma', 'United States of America', 'Falconer’s Flight hop pellets are an exclusive proprietary hop blend created to honor and support the legacy of Northwest brewing legend, Glen Hay Falconer. Proceeds from each Falconer’s Flight purchase is contributed to the Glen Hay Falconer Foundation. These hop pellets are an excellent complement to many IPA and Pale Ale-oriented hop varieties. Specific aroma descriptors include distinct tropical, floral, lemon and grapefruit characteristics. ', 'Citra, Simcoe, Amarillo, Sorachi Ace, Summit, Cascade', 0.281, 14.0, 7.0, 24.5, 52.5),
  ('bm-hop-falconers-flight-7cs', 'Falconer''s Flight 7CS', 9.75, 4.9, 'pellet', 'Dual', 'United States of America', 'This hop blend includes the 7 American "C" hops: Cascade, Centennial, Chinook, Citra, Cluster, Columbus and Crystal in addition to other experimental varieties. Specific aroma descriptors include distinct tropical, floral, lemon, pine and grapefruit characteristics.', 'CTZ, Centennial, Citra, Columbus, Chinook, Cluster, Cascade, Crystal', NULL, 15.5, 8.5, 48.0, 47.5),
  ('bm-hop-fantasia', 'Fantasia Blend', 5.4, NULL, 'pellet', 'Dual', 'United States of America', 'This unique BarthHaas Group Hop Composition provides a silky touch of cream caramel and stone fruits.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-feux-coeur-francais', 'Feux-Coeur Francais', 14.0, 4.55, 'pellet', 'Bittering', 'Australia', NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-first-gold', 'First Gold', 7.8, 3.2, 'pellet', 'Dual', 'United Kingdom', 'First Gold hops have aroma descriptors that include tangerine, orange marmalade, apricot, magnolia, red berries, herbal, orange and herbal. First Gold - also known as Prima Donna - has excellent aroma qualities and much of the flavor characteristics of WGV and has proven a success in stronger flavored summer beers and IPAs. This variety is suitable as a general kettle hop and also for late and dry hopping in all types of beer.', 'Whitbread Golding Variety, East Kent Golding, Willamette', NULL, 22.0, 6.5, 32.0, 26.0),
  ('bm-hop-flyer', 'Flyer', 11.4, 5.05, 'pellet', 'Dual', 'United Kingdom', 'A citrus hop with aromas of stoned fruits, licorice, treacle-toffee and caramel with slight burnt notes. Its bittering characteristics can best be described as spicy, citrus, liquorice and resinous.', 'Willamette,East Kent Goldings', NULL, 22.5, 0.5, 30.5, 21.0),
  ('bm-hop-fuggle', 'Fuggle', 4.25, 2.8, 'pellet', 'Aroma', 'United Kingdom', 'Fuggle hops have aroma descriptors that include mild, wood, grass, and mint.', 'Willamette, Styrian Golding, East Kent Goldings', NULL, 35.0, 13.0, 28.5, 20.0),
  ('bm-hop-gaia', 'Gaia', 13.5, 7.5, 'pellet', 'Bittering', 'Czech Replublic', 'Gaia is characteristic for its hoppy and spicy aroma. Gaia is suitable not only for the first but for the second hopping as well. ', NULL, NULL, 3.0, 10.5, 24.5, 30.0),
  ('bm-hop-galaxy', 'Galaxy', 13.5, 7.0, 'pellet', 'Dual', 'Australia', 'Galaxy hops have one of the highest concentrations of essential oils known in hops, which has contributed to its meteoric rise in popularity. Galaxy is often described as having a strong passion fruit aroma and flavor as well as blasts of clean citrus and peach. At times, you can also experience pineapple and tropical fruit hints. Galaxy hops are all tropical fruit with little to no floral, pine, or spice flavors or aromas.

Galaxy is an extremely versatile hop variety. They can work compliment other hops perfectly, or take center stage as the primary flavor. Their high alpha acid content make them especially suited to late boil and dry hopping. Their distinctive mixture of citrus, passion fruit, peach and hints of grass is sure to stand out and create a beer like no other.', 'Simcoe, Citra, Amarillo', NULL, 1.5, 10.0, 37.0, 51.0),
  ('bm-hop-galena', 'Galena', 13.75, 7.95, 'pellet', 'Aroma', 'United States of America', 'Aroma descriptors of the Galena hop include sweet fruits, pear, pineapple, blackcurrant, grapefruit, lime, gooseberry and spicy wood.', 'Brewer''s Gold, Columbus, Tomahawk, Zeus, CTZ, Nugget', 0.232, 14.0, 7.0, 38.0, 45.0),
  ('bm-hop-gemini', 'Gemini', 8.2, 3.64, 'pellet', 'Dual', 'United States of America', 'Gemini is quickly becoming known as this year''s ultimate utility power house.  This hop is no "one trick pony", offering endless opportunities to enhance and expand the flavor profile of a brew. ', NULL, NULL, 11.5, 4.5, 31.5, 32.5),
  ('bm-hop-glacier', 'Glacier', 6.5, 7.7, 'pellet', 'Dual', 'United States of America', 'Glacier hops have aroma descriptors that include plum, blackberry and wood.', 'Fuggle, Styrian Golding, Willamette', 0.242, 30.0, 10.5, 13.5, 40.0),
  ('bm-hop-godiva', 'Godiva', 7.5, 2.45, 'pellet', 'Aroma', 'United Kingdom', 'The Godiva hop has tangerine, white grape and spice aromas. Sweet and smooth bittering characteristics.', 'Wai-iti, Hallertau Blanc', NULL, NULL, NULL, 27.0, NULL),
  ('bm-hop-golden-star', 'Golden Star', 5.4, 4.6, 'pellet', 'Aroma', 'Japan', 'Golden Star is grown commercially only in Japan as an aroma hop. It is very difficult to pick and shatters easily, particularly when grown seeded.', 'Fuggle', 0.36, NULL, NULL, 50.0, NULL),
  ('bm-hop-golding', 'Golding', 5.0, 2.5, 'pellet', 'Aroma', 'United States of America', 'Golding hops have aroma descriptors that include delicate and sweet floral.', 'East Kent Golding, Fuggle, Willamette, Styrian Golding, Progress, Whitbread Golding Variety', NULL, 40.0, 14.5, 20.0, 30.0),
  ('bm-hop-green-bullet', 'Green Bullet', 13.0, 6.75, 'pellet', 'Dual', 'New Zealand', 'Specific aroma descriptors of the Green Bullet hop includes black pepper, pine, plum and dried fruit characters; high levels of floral oil that complements and balances the piney resinous hop character. It has a resinous character reminiscent of Styrian Goldings, but layered with hints of musky Southern Hemisphere fruit.

It is traditionally considered a bittering variety for lagers, but also carries spicy characteristics typical of other Slovenian hop varieties.

This hop is regarded as a “workhorse” in its native New Zealand and is widely used there.  ', 'Liberty, Hallertau, Mount Hood, Ultra, Crystal', NULL, 28.5, 9.5, 40.5, 38.0),
  ('bm-hop-grungeist', 'Grungeist', 2.9, 9.0, 'pellet', 'Aroma', 'United States of America', 'The unique combination of peach and passion fruit are equally balanced with a hint of lemon zest and floral essence. Grüngeist adds aromas and flavors of kiwi, overripe peach and dried lavender', 'Callista', NULL, NULL, NULL, 19.2, NULL),
  ('bm-hop-hallertau', 'Hallertau (US)', 5.0, 4.5, 'pellet', 'Aroma', 'United States of America', 'US Hallertau is mild and pleasant, yet spicy, with herbal and floral characteristics.', 'Liberty, Mount Hood, Hallertau Mittelfruh, Crystal, Hallertau Tradition', NULL, 34.0, 11.0, 22.0, 39.5),
  ('bm-hop-hallertau-blanc', 'Hallertau Blanc', 10.5, 5.5, 'pellet', 'Aroma', 'Germany', 'The Hallertau Blanc hop has moderate to strong featuring pineapple, gooseberry, white grape, fresh lemongrass, and passion fruit flavors and aromas. It is reminiscent of many recent Southern Hemisphere varieties, but with a cleaner, less dank profile.', 'Nelson Sauvin, Enigma', NULL, 1.5, 1.0, 28.5, 62.5),
  ('bm-hop-hallertau-gold', 'Hallertau Gold', 8.5, 6.0, 'pellet', 'Aroma', 'Germany', 'Hallertau Gold hops feature a pleasant and mild hoppiness with traditional notes of floral, herb, and spice.', 'Hallertau Mittelfruh, Tettnanger, East Kent Golding, Crystal, Mount Hood', NULL, 17.0, 4.5, 20.0, 63.0),
  ('bm-hop-hallertau-mittelfruh', 'Hallertau Mittelfrüh', 4.25, 4.0, 'pellet', 'Aroma', 'Germany', 'Hallertau Mittelfrüh - or "Hall Mitt" - hops have a specific aroma descriptors include mild, yet spicy, with floral and citrus tones. Although it can be and is used throughout the boil, it is most prized for its fine, elegant aroma and flavor contribution. Mittelfrüh is, at least to some, the epitome of noble hops.', 'Hallertau, Liberty, Vanguard, Hallertau Tradition', NULL, 55.5, 14.5, 23.0, 15.5),
  ('bm-hop-hallertau-taurus', 'Hallertau Taurus', 14.95, 5.0, 'pellet', 'Dual', 'United Kingdom', 'Hallertau Taurus is a hop with earthy aromas and hints of chocolate, banana, spice, pepper, curry. This hop has the highest xanthohumol content of any hop, which is a potent antioxidant.', 'Magnum (GR),Magnum (US),Citra,Hallertau Tradition,Merkur,Herkules', 0.35, 30.5, 8.0, 22.5, 30.0),
  ('bm-hop-hallertau-tradition', 'Hallertau Tradition', 5.8, 4.5, 'pellet', 'Aroma', 'Germany', 'Hallertau Tradtion, or commonly referred to as just ''Tradition'', adds an earthy and grassy character atop a nose of nectar fruits. ', 'Hallertau Mittelfruh, Tettnanger, East Kent Golding, Crystal, Mount Hood', NULL, 42.5, 12.5, 26.5, 24.5),
  ('bm-hop-harlequin', 'Harlequin', 10.5, 8.0, 'pellet', 'Dual', 'United Kingdom', 'The Harlequin hop excels when used in late and dry hopping but also offers smooth bittering characteristics.', 'Mosaic', NULL, 5.0, NULL, 29.0, 60.0),
  ('bm-hop-harmonie', 'Harmonie', 6.0, 6.5, 'pellet', 'Aroma', 'Czech Replublic', 'Key flavors of the Harmonie hop include banana, creamy caramel, green tea and apricot.', NULL, NULL, 15.0, 8.5, 20.5, 35.0),
  ('bm-hop-hartwick', 'Hartwick', 12.28, 5.77, 'pellet', 'Aroma', 'United States of America', 'Hartwick hops have a piney and overripe pineapple aroma. GLH mentions that this hop''s aroma is markedly different from their other Field Grade hops. ', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-hbc472', 'HBC 472', 9.5, 8.0, 'pellet', 'Aroma', 'United States of America', 'The aroma of the HBC472 hop cones consists of floral, woody, earthy, and coconut. In beer, this hop delivers a surprising fruity note along with its distinctive coconut-woody character. When hopped aggressively in IPA style beers, citrus and grapefruit aromas rule, but a fascinating whiskey/bourbon and coconut character breaks into the background', NULL, NULL, 1.25, 29.0, 42.5, 40.0),
  ('bm-hop-hbc-586', 'HBC 586', 20.0, 12.5, 'pellet', 'Dual', 'United States of America', 'When used as a whirlpool or dry hop addition, HBC 586 brings a complex medley of tropical fruit flavors. The aroma of HBC 586 has been described as "a large medley of fruit flavors... Mango, guava, lychee, citrus, with slight sulfur and herbal notes."', NULL, NULL, 10.0, 9.0, 37.5, 60.0),
  ('bm-hop-hbc-630', 'HBC 630', 13.5, 6.0, 'pellet', 'Dual', 'United States of America', 'HBC 630 when used as a whirlpool or dry hop addition has distinct cherry candy like – think cherry ludens – aroma, with notes of other stone fruits, raspberry candy, tropical fruits and citrus. A unique variety that offers a different aroma and flavor profile than most varieties available today.', NULL, NULL, 17.5, 13.0, 23.0, 45.0),
  ('bm-hop-hbc692', 'HBC 692', 9.2, 9.25, 'pellet', 'Aroma', 'United States of America', 'HBC 692 exhibits grapefruit, floral, stone fruit, potpourri, woody, cream, pine, and resinous notes.

HBC 692 has been renamed Talus.', 'Talus', 0.2135, NULL, NULL, NULL, NULL),
  ('bm-hop-helga', 'Helga', 6.35, 6.0, 'pellet', 'Aroma', 'Australia', 'Specific aroma descriptors include pleasant, noble characteristics.  Its brewing characteristics resemble that of Hallertau Mittelfrüher, however it demonstrates a forgiving and refined character in a variety of beer styles and hop applications.', 'Hallertau, Hallertau Mittelfruh', NULL, 45.0, 27.5, 21.5, 7.0),
  ('bm-hop-helios', 'Helios', 18.9, 4.0, 'pellet', 'Dual', 'United States of America', 'Helios is described as low CoH, with a pleasant bitterness. It has a muted aroma with clean, soft accents. The aroma is resinous, spicy, and floral. For the farmers, it offers high yield and disease resistance. 

While it is listed as a dual purpose hop, it appears to be much closer to a bittering hop.', NULL, NULL, 21.5, 8.5, 27.5, 55.0),
  ('bm-hop-herald', 'Herald', 11.0, 5.0, 'pellet', 'Dual', 'United Kingdom', 'It is known for its clean bittering characteristics and fresh citrus flavors including orange and grapefruit.', 'Pioneer, Pilgrim', NULL, 15.0, 7.0, 36.0, 40.0),
  ('bm-hop-herkules', 'Herkules', 14.5, 4.75, 'pellet', 'Bittering', 'Germany', 'Herkules hops have aroma descriptors that include robust hoppy with some citrus and melon.', 'Taurus, Warrior', NULL, 37.5, 9.5, 35.0, 40.0),
  ('bm-hop-hersbrucker', 'Hersbrucker', 3.25, 4.25, 'pellet', 'Aroma', 'Germany', 'Hersbrucker hops have aroma descriptors that include hay, tobacco and orange.', 'Hallertau, Mount Hood, Liberty, Spalt', 0.4, 25.0, 10.5, 21.0, 22.5),
  ('bm-hop-horizon', 'Horizon', 10.4, 6.5, 'pellet', 'Dual', 'United States of America', 'Horizon hops have aroma descriptors that include floral bouquet, citrus and spicy.', 'Magnum (US), Magnum (GR), Nugget', NULL, 15.0, 11.0, 17.5, 50.0),
  ('bm-hop-hort9909', 'HORT9909', 8.0, 3.5, 'pellet', 'Dual', 'New Zealand', 'Hort9909 is a trial variety with pronounced forward citrus characters of lemon and lime, sweet hay and spices background in keeping with the selections breeding. ', NULL, NULL, 12.0, 4.5, 28.0, 50.0),
  ('bm-hop-hpa-016', 'HPA-016', 17.2, 7.45, 'pellet', 'Aroma', 'Australia', 'HPA''s newest proprietary flavor hop - tentatively called HPA-016 - is a big-hitting, fruit-forward flavor hop bursting with sweet mandarin, citrus peel and fresh pine needles. ', NULL, NULL, 1.0, 9.0, 35.0, 42.0),
  ('bm-hop-huell-melon', 'Huell Melon', 7.45, 7.0, 'pellet', 'Aroma', 'Germany', 'Huell Melon has a pleasantly sweet and fruity character similar to honeydew melon with hints of strawberries.', 'Belma, Jarrylo', NULL, 15.0, 7.5, 27.5, 36.0),
  ('bm-hop-huller-bitterer', 'Hüller Bitterer', 5.75, 5.0, 'pellet', 'Bittering', 'Germany', 'Hüller Bitterer has good bittering qualities, but production has decreased immensely over the years due to other hops having better storage.', NULL, NULL, 15.0, 6.5, 28.5, 39.5),
  ('bm-hop-hydra', 'Hydra', 12.1, 7.15, 'pellet', 'Dual', 'United States of America', 'Originally nicknamed "Befuddlement" for it''s unique yet unidentifiable characteristics, Hydra has emerged with an incredible ability to amplify and juice up a brew.  Hydra can not only accentuate other hops characteristics but can easily shine solo. ', NULL, NULL, 11.5, 8.5, 27.5, 54.5),
  ('bm-hop-idaho-7', 'Idaho 7', 12.2, 4.25, 'pellet', 'Aroma', 'United States of America', 'Idaho 7 hops are known for their juicy tropical fruit and citrus flavors (think apricot, orange, red grapefruit, papaya) with big notes of resin-y pine and hints of floral and black tea. Use the Idaho 7 hop as a single hop or as a late addition. The high oil content make this ideal for dry hopping and whirlpool. Playfully known as "007: The Golden Hop"', 'Azacca, El Dorado, Cashmere, Citra, Idaho Gem, Amarillo, Chinook, Columbus', NULL, 15.0, 8.0, 35.0, 50.0),
  ('bm-hop-idaho-gem', 'Idaho Gem', 12.5, 6.0, 'pellet', 'Dual', 'United States of America', 'Named after its home state, Idaho Gem has rich levels of sweet, fruit-forward aromatic oils make Idaho Gem optimal for late kettle additions or dry hopping in a wide variety of styles, whether alone or in a blend.

Idaho Gem shines with stone fruit, red berry, citrus, mojito, mint, and even powdered sugar aromas. Its flavors are soft and full with a remarkable smoothness, bright and forward impressions of fruit candy (think Juicy Fruit and Jolly Rancher) supported by citric grapefruit notes. ', 'Azacca, El Dorado, Cashmere, Citra, Idaho 7, Cascade', 0.276, NULL, NULL, 42.5, NULL),
  ('bm-hop-independence', 'Independence', 4.7, 1.5, 'pellet', 'Aroma', 'United States of America', 'Paying homage to the classic hops, Independence blend merges old world with new world spirit giving a truly American aroma and flavor profile. Bringing forth tobacco, earthy, pine and grassy notes with citrus and herbs to support the aroma profile, Independence symbolizes the pioneer spirit carried through the many generations of growers in the Pacific Northwest.', NULL, NULL, NULL, NULL, 20.5, NULL),
  ('bm-hop-jarrylo', 'Jarrylo', 16.0, 6.75, 'pellet', 'Dual', 'United States of America', 'Jarrylo hops have aroma descriptors that include strong lemon lime, orange, pear, banana and mild spice. Some reviewers also notice a clean bright white wine aroma.', 'Motueka, Nelson Sauvin, Mosaic', NULL, 16.5, 9.5, 35.5, 47.5),
  ('bm-hop-jester', 'Jester', 8.0, 5.0, 'pellet', 'Dual', 'United Kingdom', 'Blackcurrant, Grapefruit, Resinous', 'Cascade', NULL, NULL, NULL, 25.5, NULL),
  ('bm-hop-junga', 'Junga', 12.0, 6.5, 'pellet', 'Bittering', 'Poland', 'While some call Junga a dual-purpose hop, it is mainly used for bittering. Has limited potential for aroma or dry hopping use. Sometimes Iunga or Lunga. This varietal is high in alpha acids (10-13%) and most frequently utilized for bittering. However, if used for aroma, Junga hops give blackcurrant, grapefruit, and spice notes. Junga is comparable to German Magnum; not much taste but a great bittering hop.', 'Nugget, Target, Galena', NULL, NULL, NULL, 31.5, NULL),
  ('bm-hop-kazbek', 'Kazbek', 6.5, 5.0, 'pellet', 'Aroma', 'Czech Replublic', 'Kazbek can show a dominant bright citrus note of lemon or grapefruit, but never obscures the quintessential mixture of floral and earthy spice of its Saaz parent.', 'Saaz (CZ)', NULL, 27.5, 12.5, 37.5, 47.5),
  ('bm-hop-kohatu', 'Kohatu', 6.5, 5.0, 'pellet', 'Dual', 'New Zealand', 'Kohatu hops have aroma descriptors include fresh and intense tropical fruit characters and an excellent finish and bitterness.', 'Wai-iti, Motueka', NULL, 35.0, 13.5, 22.5, 27.5),
  ('bm-hop-lambic', 'Lambic', 1.5, 3.9, 'pellet', 'Aroma', 'United States of America', 'Floral and Fruity. These are aged hops that are perfect for making sours.', 'Fuggle', NULL, NULL, NULL, 32.0, NULL),
  ('bm-hop-lawton', 'Lawton', 3.75, 3.1, 'pellet', 'Bittering', 'United States of America', 'Lawton hops have pungent, woody & earthy aromas, not citrusy at all, but totally dank. ', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-lemondrop', 'Lemondrop', 6.0, 5.0, 'pellet', 'Aroma', 'United States of America', 'Lemondrop hops offer strong citrus, floral, fruity, herbal, lemon, mint, green tea, light melon aromas.', 'Cascade, Motueka, Liberty, Mandarina Bavaria, Centennial', NULL, 57.0, 9.5, 31.0, 46.0),
  ('bm-hop-liberty', 'Liberty', 4.75, 3.5, 'pellet', 'Bittering', 'United States of America', 'Liberty hops have aroma descriptors that include noble, delicate, floral bouquet and spice.  It displays mild floral and spice characteristics with some subtle citrus notes.', 'Hallertau, Mount Hood, Crystal', NULL, 40.0, 12.5, 26.0, 20.0),
  ('bm-hop-limbus', 'Limbus', 4.25, 3.0, 'pellet', 'Aroma', 'Poland', 'This is a Polish dwarf aroma hop.', NULL, NULL, NULL, NULL, 30.0, NULL),
  ('bm-hop-loral', 'Loral', 13.5, 4.0, 'pellet', 'Aroma', 'United States of America', 'Loral hops have a very pleasant, floral, peppery, citrus aroma with some dark fruit character. The floral, fruity, citrus, character tends to be more prominent in a beer made with this hop, while the qualities of earthy and herbal notes stay more subdued.', 'Glacier, Nugget, Strisselspalt, Tardif De Bourgogne', NULL, 17.5, 5.5, 22.0, 55.0),
  ('bm-hop-lotus', 'Lotus', 15.0, 5.5, 'pellet', 'Aroma', 'United States of America', 'Lotus is described  as having orange, vanilla, berry, and tropical fruits and was jokingly called orange creamsicle. This is a proprietary hop from Hopsteiner formerly called Experimental #06297.', NULL, NULL, 37.5, NULL, 36.0, 30.0),
  ('bm-hop-lublin', 'Lubelska', 4.0, 3.25, 'pellet', 'Aroma', 'Poland', 'Lubelska hops have a distinctive and very refreshing characters of spice and flowers (magnolia and lavender).', 'Saaz (CZ), Saaz (US), Tettnang, Stirling', NULL, 35.0, 8.5, 25.0, 28.5),
  ('bm-hop-lumberjack', 'Lumberjack', 10.5, NULL, 'pellet', 'Dual', 'Canada', 'BC Hop Co.’s proprietary hop, Lumberjack, aroma can be described as predominately bitter with notes of melon, sweet citrus, and spices like clove and allspice.  A slight earthiness softens this hop, producing a pleasant mouth-feel in the beer.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-mackinac', 'Mackinac', 11.5, 3.4, 'pellet', 'Aroma', 'United States of America', 'This super-aroma hop has proven to execute wide utility and flavorful new beer styles that are trending toward these aromas and flavors. The moderately low cohumulone offers brewers a smoother brewing profile with excellent foam characteristics. It has gained traction and praise across the United States since and has not only increased in demand but cannot be planted quickly enough to fulfill requests.', NULL, NULL, 11.5, 4.5, 31.5, 16.0),
  ('bm-hop-magnat', 'Magnat', 13.5, 4.9, 'pellet', 'Dual', 'Poland', 'Magnat hops have key flavors that include citrus, woody, chamomile and lemon. Despite being classical bitterness aroma it has quite high linalool content, so it can enrich the aroma with the notes of lilac and flowers.', 'Magnum (GR), Magnum (US), Lubelski', NULL, 18.0, 7.5, 23.0, 44.5),
  ('bm-hop-magnum-gr', 'Magnum (GR)', 13.5, 5.75, 'pellet', 'Bittering', 'Germany', 'German Magnum hops have aroma descriptors that include apple and pepper. It provides clean bitterness and subtle citrus flavors. ', 'Magnum (US), Nugget, Taurus, Columbus, Tomahawk, Zeus, CTZ', 0.175, 37.5, 10.0, 25.0, 37.5),
  ('bm-hop-magnum-us', 'Magnum (US)', 13.0, 5.75, 'pellet', 'Bittering', 'United States of America', 'US Magnum is a bittering hop with an excellent bittering profile and a nice, hoppy, floral aroma and subtle characters of citrus.', 'Galena, Magnum (GR), Nugget, Columbus, Horizon, Northdown, Northern Brewer (US)', 0.175, 37.5, 10.0, 25.5, 37.5),
  ('bm-hop-mandarina-bavaria', 'Mandarina Bavaria', 8.75, 6.0, 'pellet', 'Dual', 'Germany', 'Mandarina Bavaria hops are tropical, fruity and sweet with notes of tangerine and citrus. It is commonly used to balances earthy and herbal hops. This hop is very versatile and plays well in any beer style that would benefit from its distinctive fruity character. Also consider using as a dry hop/late addition in IPAs.', 'Cascade, Huell Melon, Lemondrop, Perle (US)', NULL, 12.5, 8.0, 33.0, 40.0),
  ('bm-hop-marco-polo', 'Marco Polo', 12.5, 5.0, 'pellet', 'Dual', 'China', 'Key flavors of the Marco Polo hop include lemon, gooseberry, oregano and elder flower.', 'CTZ, Columbus, Tomahawk, Zeus', NULL, 20.0, 10.0, 32.5, 45.0),
  ('bm-hop-marynka', 'Marynka', 9.75, 11.5, 'pellet', 'Dual', 'Poland', 'Key flavors of the Marynka hop include hay, licorice, lemon, grapefruit and aniseed. While it is primarily used for bittering, it can also be used to provide a strong earthy, herbal aroma.', 'Tettnanger', NULL, 34.5, 11.5, 29.5, 29.5),
  ('bm-hop-mckenzie', 'McKenzie', 10.0, 8.5, 'pellet', 'Aroma', 'United States of America', 'McKenzie hops are the first variety to be released by the West Coast Hop Breeding Company out of Oregon. McKenzie™ was specifically bred to be grown in Oregon and highlight the area''s terroir. McKenzie is "bright and fruity" with grapefruit, lemon, nectarine, and melon aromas that is backed by pine, resin, and wood. Fits really well in the classic West Coast IPA or American Pale Ale, but also plays well in fruit-forward and Hazy IPAs.
', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-medusa', 'Medusa', 4.0, 5.75, 'pellet', 'Aroma', 'United States of America', 'Medusa delivers strong flavor and aroma characteristics of intense guava, melon, apricot and citrus fruit. Also has intense lemon-lime flavors with subtle alfalfa and peach flavors.', 'Zappa', NULL, 9.5, 13.5, 42.0, 54.5),
  ('bm-hop-melba', 'Melba', 8.5, 3.75, 'pellet', 'Aroma', 'Australia', 'Melba hops have passion fruit, grapefruit, citrus and summery aroma characteristics. When used as an early addition, it is said to impart a clean and somewhat spicy bitterness. When used as a flavor or aroma addition though, properties of passion fruit, grapefruit and citrus come to the fore.', 'Galaxy', NULL, NULL, NULL, 30.0, NULL),
  ('bm-hop-meridian', 'Meridian', 6.0, 7.5, 'pellet', 'Aroma', 'United States of America', 'The Meridian hop has aromas that include citrus (lemon), mixed berry, tropical fruit, and spearmint. This hop can also be combined with more aggressive hops in IPAs to brighten the overall impression of the beer and lend a seductive finish.', 'Citra, Glacier, Centennial', NULL, 8.0, 3.5, 47.5, 30.0),
  ('bm-hop-merkur', 'Merkur', 14.1, 5.9, 'pellet', 'Dual', 'Germany', 'Merkur has aroma descriptors that include sugar, pineapple and mint.  In some dual-purpose applications, Merkur displays subtle earth and citrus notes.', 'Magnum (GR), Magnum (US), Hallertau Taurus, Hallertau Tradition', NULL, 30.0, 9.0, 18.5, 47.5),
  ('bm-hop-michigan-copper', 'Michigan Copper', 9.9, 2.75, 'pellet', 'Aroma', 'United States of America', 'Michigan Copper is described as a vigorous super-aroma hop with very fragrant floral and tropical fruit aromas and flavors. Rich in fruit and candy notes, this hop has been likened to Hawaiian fruit punch, black cherry, red hard candy, and hibiscus resin.', NULL, NULL, 17.5, 7.5, 34.0, 43.0),
  ('bm-hop-millennium', 'Millennium', 16.5, 5.4, 'pellet', 'Bittering', 'United States of America', 'Millennium hops have aroma descriptors that include resin, floral, toffee and pear.', 'Nugget, Columbus, Tomahawk, Zeus, CTZ', 0.24, 20.0, 9.0, 31.5, 45.0),
  ('bm-hop-mimosa', 'Mimosa', 3.35, 6.35, 'pellet', 'Aroma', 'Czech Replublic', 'Little is known at this time about the new Mimosa hop. It was created in 2019, and not yet available commercially.', NULL, NULL, 7.5, 6.5, 27.5, 29.0),
  ('bm-hop-minstrel', 'Minstrel', 6.0, 3.25, 'pellet', 'Dual', 'United Kingdom', 'The Minstrel hop has herbal, orange, and spiced berry aromas. It also has a mild bitterness, that is not unlike Challenger.', 'Challenger', NULL, 2.5, NULL, 24.0, 23.5),
  ('bm-hop-mistral', 'Mistral', 7.5, 3.45, 'pellet', 'Dual', 'France', 'When it is used in the kettle, the bitterness of the Mistral hop is very clean and sweet and not harsh. It is completely unique with a character that would be impossible to replicate without blending multiple varieties.  It has a melon and citrus-like character and also can have a Muscat grape or wine-like character and even a hint of pear. Ideal for late additions and dry hopping.', NULL, NULL, 11.0, 3.5, 34.0, 62.0),
  ('bm-hop-monroe', 'Monroe', 2.7, 7.0, 'pellet', 'Aroma', 'Germany', 'The Monroe hop starts out mild and smooth, then adds key flavors like strawberry, cherry, plum, passion fruit and red currant. Wonderful raspberry notes supplemented with orange syrup aromas. This is a very unique hop that is unlike any others. It is smooth and restrained in the German tradition, but with plenty of red-fruit character.', NULL, 0.252, NULL, NULL, NULL, NULL),
  ('bm-hop-mosaic', 'Mosaic', 12.5, 3.55, 'pellet', 'Dual', 'United States of America', 'Mosaic offers a unique and complex blend of floral, tropical, fruity, and earthy characteristics that translate very favorably into several different styles of beer, although it is primarily used in IPAs.

Mosaic''s complex flavor and aroma profile led to its name. This hop is most noted for its blueberry and tropical aromas, but is also known to have citrus, grassy, pine, spice, tangerine, papaya, rose, earthy, floral (blossoms), and bubble gum descriptors. 

The aroma/flavor descriptors for the wildly popular Mosaic hop commonly include fruity (blueberry), citrus (tangerine, grapefruit), tropical (mango, guava), floral, and earthy. The combination of these aroma/flavor descriptors with the relatively high alpha-acid levels allows this hop to serve a dual purpose, as both a bittering and flavor/aroma hop in the brewing process. Ultimately, Mosaic provides flavor and aroma profiles in beer that simply cannot be accomplished with other hop cultivars.

Mosaic hops are one of the most used - and recognizable - hop varieties in use today. It can be used in many different beer styles, but will usually be found in IPAs and pale ales. 

As for growing properties of this hop, Mosaic has a tight-knit appearance with a compact cone. Mosaic has a unique aroma combined with high α-acid content, powdery mildew tolerance, and exceptional yield. ', 'Citra, Simcoe', 0.2635, 13.0, 5.5, 25.0, 51.0),
  ('bm-hop-motueka', 'Motueka', 6.75, 5.25, 'pellet', 'Dual', 'New Zealand', 'The Motueka hop has specific aroma descriptors include distinctive fresh crushed citrus, mojito lime character, lively lemon and lime tones with background hints of tropical fruit. It also has fresh herbal notes (basil, rosemary) and hints of dried orchard fruit around the edges. Motueka was originally bred as a dual-purpose hop because of its balanced bitterness and new world “noble” type aroma. 

The weight of oil to alpha integrates it fully with higher gravity types to balance both malt sweetness and body. Extremely versatile in the brewery.', 'Saaz (US), Sterling', 0.35, 3.5, 2.0, 30.0, 47.5),
  ('bm-hop-mount-hood', 'Mount Hood', 5.95, 6.5, 'pellet', 'Aroma', 'United States of America', 'Mount Hood hops have aroma descriptors that include herbal, pungent and spicy notes.', 'Hallertau, Hersbrucker, Liberty, Crystal, Hallertau Mittelfruh', 0.3635, 25.0, 11.5, 22.0, 35.0),
  ('bm-hop-mount-rainier', 'Mount Rainier', 7.2, 7.1, 'pellet', 'Dual', 'United States of America', 'Mount Rainier hops have aroma descriptors that include noble, licorice and floral bouquet. It also has a hint of citrus and spice.', 'Fuggle, Hallertau', NULL, 17.5, 7.5, 27.5, 58.5),
  ('bm-hop-moutere', 'Moutere', 18.5, 9.0, 'pellet', 'Dual', 'New Zealand', 'Moutere hops have intensely tropical and fruity with dominant grapefruit and passion fruit notes. It also has undertones of spry hay, earthy baking spice, and resinous pine.', NULL, NULL, 15.5, 5.5, 26.0, 22.5),
  ('bm-hop-multihead', 'Multihead', 4.0, 6.75, 'pellet', 'Aroma', 'United States of America', 'Multihead is a neomexicanus breed so named for its tendency to produce dual cones. Low alpha acid levels and high oil content make this hop perfect for packing flavor and aroma into your beer. Known for imparting intense tropical flavors of melon, guava, apricot and citrus. Although primarily used as a late addition, Multihead is known to contribute a mellow, peachy character when added early in the boil.', 'Medusa', NULL, NULL, NULL, 45.0, 48.0),
  ('bm-hop-mystic', 'Mystic', 5.5, 3.0, 'pellet', 'Aroma', 'United Kingdom', 'Mystic is a lower alpha acid variety that provides clean bittering in lighter styles, but is mostly used as an aroma variety because of its fruit-forward character. Mystic is not as big and bold as fellow UK variety Harlequin, but Mystic offers a unique combination of black currant, citrus, and passion fruit. Mystic is the daughter of Jester and was selected primarily for its amazing aroma, but also because of disease resistance and yield potential.', 'Barbe Rouge, Styrian Dragon, Huell Melon', NULL, 35.0, 0.0, 35.0, 35.0),
  ('bm-hop-nectaron', 'Nectaron', 10.75, 4.75, 'pellet', 'Aroma', 'New Zealand', 'Nectaron has intense tropical fruit and citrus aroma characters evident during selection. Over successive commercial brewing trials in styles such as Strong Pale Ales and India Pale Ales, Nectaron has displayed high levels of tropical fruit characters of pineapple and passionfruit as well as stone fruit (peach) and citrus (grapefruit).', 'Waimea, Citra, Mosaic', NULL, 15.0, 4.5, 27.0, 62.0),
  ('bm-hop-nelson-sauvin', 'Nelson Sauvin', 11.5, 6.5, 'pellet', 'Aroma', 'New Zealand', 'The Nelson Sauvin hop aroma descriptors include distinctive white wine characters along with fruity flavors, such as fresh crushed gooseberry and grape. The essential oil profile displays characteristics of fresh crushed gooseberries, which is a descriptor often used for the grape variety Sauvignon Blanc, which is the reason for this variety''s name.

This is a hop that may require efficient application in the brew house, this truly unique dual-purpose variety can be used to produce big punchy Ales as well as subtle aroma driven Lagers. The fruitiness may be a little overpowering for the uninitiated, however those with a penchant for bold hop character will find several applications for this true brewer''s hop.', 'Hallertau Blanc, Enigma, Motueka, Riwaka', NULL, 31.0, 8.5, 22.5, 32.5),
  ('bm-hop-newport', 'Newport', 13.75, 7.3, 'pellet', 'Bittering', 'United States of America', 'Newport hops have aroma descriptors that include earth, citrus, wine and balsamic. It contains high alpha acid, co-humulone and myrcene content, offering more distinct aroma characteristics than its parents.', 'Brewer''s Gold, Fuggle, Galena, Magnum (GR), Magnum (US), Nugget', 0.225, 17.5, 9.0, 37.0, 50.0),
  ('bm-hop-nobility', 'Nobility Blend', 4.35, 5.1, 'pellet', 'Dual', 'United States of America', 'Nobility was developed specifically for lager brewing, with a focus on a balanced noble-style hop character.  Primary aromas and flavors of citrus (lemon, orange), lemongrass, green tea, and herbaceous, with a mixture of floral and spice. ', NULL, NULL, 22.5, 27.0, 27.0, 36.0),
  ('bm-hop-northdown', 'Northdown', 8.5, 4.75, 'pellet', 'Dual', 'United States of America', 'Northdown hops have aroma descriptors that include pleasant spice, cedar and pine characteristics with hints of floral and berry flavors.  It is known for its fresh, yet rich flavor.', 'Northern Brewer (US), Northern Brewer (GR), Target, Challenger, Admiral', NULL, 42.5, 15.0, 28.0, 26.0),
  ('bm-hop-northern-brewer-gr', 'Northern Brewer (GR)', 8.0, 4.0, 'pellet', 'Bittering', 'Germany', 'German Northern Brewer hops have aroma descriptors that include mint, pine and grass. It displays pleasant pine and mint characteristics most in dual purpose brewing applications.', 'Northern Brewer (US), Brewers Gold, Chinook, Perle (US), Perle (GR)', NULL, 42.5, 15.0, 30.0, 35.0),
  ('bm-hop-northern-brewer-us', 'Northern Brewer (US)', 8.5, 4.25, 'pellet', 'Bittering', 'United States of America', 'US Northern Brewer hops have aroma descriptors that include evergreen, wood and mint.   US Northern Brewer contains slightly higher alpha acids and high myrcene oil content than the German variety, resulting in a herbal, wood and peppery aroma. It is suitable for any stage of the brewing process.', 'Galena, Perle (US), Magnum (GR), Magnum (US), Chinook, Northern Brewer (GR)', NULL, 29.0, 13.0, 30.5, 40.0),
  ('bm-hop-nugget', 'Nugget', 12.75, 4.4, 'pellet', 'Dual', 'United States of America', 'Nugget is an excellent high-alpha bittering hop for most craft styles that can also be used for its mild, pleasant and herbal aroma notes.', 'Galena, Magnum (US), Columbus, Tomahawk, Zeus, CTZ', 0.25, 17.0, 8.5, 26.0, 53.5),
  ('bm-hop-nzh-107', 'NZH-107', 9.5, 6.0, 'pellet', 'Dual', 'New Zealand', 'NZH-107 is a proprietary experimental hop blend developed jointly between New Zealand Hops, Ltd. and Brewers Supply Group and showcases intense tropical fruit (guava/passion fruit) and citrus (grapefruit/lime) aroma characteristics.

NZH-107 is an excellent hop solution for many applications from first kettle to dry hop additions. Given the big character of NZH-107, early trials are focused on intensely hop-forward styles like IPAs, pale ales, and dry-hopped pale lagers.', NULL, NULL, 8.5, 6.0, 29.0, 60.0),
  ('bm-hop-old-mission', 'Old Mission', 4.33, 3.7, 'pellet', 'Aroma', 'United States of America', 'Noted aromas of the Old Mission hop includes citrus, light pine, tea spice, herbal, pepper & tartness.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-olicana', 'Olicana', 8.0, 5.0, 'pellet', 'Dual', 'United Kingdom', 'Olicana hops exhibit flavors and aromas of grapefruit, mango and passion fruit.', NULL, NULL, 8.5, NULL, 30.0, 19.5),
  ('bm-hop-olympic', 'Olympic', 12.2, 4.95, 'pellet', 'Dual', 'United States of America', 'Olympic hops are primarily used as a bittering hop, however some subtle citrus and spice aroma characteristics have been noted. ', 'Brewers Gold, Chinook, Galena', NULL, 11.0, 9.5, 31.0, 50.0),
  ('bm-hop-omega', 'Omega', 9.5, 3.5, 'pellet', 'Aroma', 'United Kingdom', 'The Omega hop has been described as “pleasantly European in style”.', 'Super Galena, Challenger', 0.22, 17.0, 5.0, 29.0, 53.0),
  ('bm-hop-opal', 'Opal', 9.5, 4.5, 'pellet', 'Dual', 'Germany', 'Opal hops have aroma descriptors that include spice, pepper, citrus and an even dispersal of fruity, floral and herbal.  It is specifically known for its sweet and spicy characteristics, providing subtle pepper and clean citrus flavors.', 'East Kent Golding, Styrian Golding, Tettnanger', NULL, 40.0, 11.5, 23.5, 32.5),
  ('bm-hop-orion', 'Orion', 7.5, 4.125, 'pellet', 'Dual', 'Germany', 'Orion hops have pleasant European bittering and aroma qualities. It is not widely grown, and is very hard to find outside of Germany.', 'Northern Brewer (GR), Perle (GR), Challenger', NULL, 21.0, 9.5, 27.5, 48.5),
  ('bm-hop-pacific-crest', 'Pacific Crest', 3.9, 3.0, 'pellet', 'Aroma', 'United States of America', 'This blend connects the classic noble varieties with an American influence. Bringing together grassy, earthy and tobacco characteristics with mild floral, spicy, herbal and pine.  The Pacific Crest Blend is a specifically formulated hop blend that targets the hallmark profiles and terpene ratios of noble varieties.', 'Saaz (US), Saaz (CZ), Fuggle, Tettnang', NULL, 20.0, 8.0, 27.0, 50.0),
  ('bm-hop-pacific-gem', 'Pacific Gem', 14.0, 8.0, 'pellet', 'Bittering', 'New Zealand', 'The Pacific Gem has specific aroma descriptors that include spicy black pepper and berry fruit aroma characteristics. Some brewers have noted delicate blackberry, floral, pine or oak tones as well.', 'Cluster, Magnum (GR), Magnum (US), Galena, Belma', 0.22, 25.0, 9.0, 37.5, 35.0),
  ('bm-hop-pacific-jade', 'Pacific Jade', 13.0, 7.5, 'pellet', 'Dual', 'New Zealand', 'Pacific Jade hops have descriptors that include fresh citrus and complex spice characters with some bold herbal aromas and hints of black pepper. It is suited for use as a bittering hop but also delivers bold aroma characteristics.', 'Hallertau, Saaz (CZ), Cluster', NULL, 32.5, 10.5, 24.0, 33.5),
  ('bm-hop-pacific-sunrise', 'Pacific Sunrise', 13.5, 6.0, 'pellet', 'Bittering', 'New Zealand', 'Pacific Sunrise features favorable bittering properties and a pleasant piney, woodsy aroma. Lemon and orange citrus drive this hop-forward variety, with tropical hits of melon and mango riding shotgun. Stone fruit and jammy sweetness support the initial front line aromatics alongside pleasant floral notes that help round out the overall profile. Subtle, yet notable hints of pine & berry refract through the aroma with lingering bits of hay and herbs that stay in their lane and are not distracting.', 'Pacific Gem', NULL, 22.0, 7.0, 28.5, 50.0),
  ('bm-hop-pacifica', 'Pacifica', 5.5, 5.5, 'pellet', 'Aroma', 'New Zealand', 'Pacifica has aroma descriptors that include a signature citrus orange zest marmalade; classic Hallertau characteristics with some floral notes. Moderate and highly pleasant. Orange marmalade and delicate citrus aromas come from this hop, blended with a very Old World Hallertau-esque warmth. It also has new-mown hay and honey with tangy herbal and sweet floral notes.', 'Hallertau', 0.231, 50.0, 16.0, 25.0, 12.5),
  ('bm-hop-pahto', 'Pahto', 18.5, 5.25, 'pellet', 'Bittering', 'United States of America', 'When used as a bittering addition hop, Pahto provides a very neutral flavor to beer, and a pleasant, smooth bitterness. The aroma profile of the hop cone is described as herbal, earthy, woody, and resinous with some fruit.', NULL, NULL, 9.5, 4.5, 29.0, 65.0),
  ('bm-hop-palisade', 'Palisade', 7.75, 6.75, 'pellet', 'Dual', 'United States of America', 'Palisade hops have aroma descriptors that include apricot, grass and clean floral characteristics.', 'Willamette, Glacier', NULL, 15.0, 12.0, 26.5, 50.0),
  ('bm-hop-paradigm', 'Paradigm', 9.85, 5.1, 'pellet', 'Aroma', 'United States of America', '​Paradigm is the proud beginning of an entire movement, an industry shift that may very well revitalize what it means to commercially grow hops for Midwest Hop growers. Aromas Identified by brewers include Herbal, Peach, Pear, Dank, Tropical, Cotton Candy, Mint, Papaya, Spice, Chamomile, Catty, Spicy Berry, Jolly Rancher, Bubble Gum, Lily and Rich Melon.', 'Saaz (US), Mosaic, Citra, Galaxy', NULL, 4.5, 3.5, 34.5, 39.5),
  ('bm-hop-pekko', 'Pekko', 14.5, 4.25, 'pellet', 'Dual', 'United States of America', 'The Pekko hop is an intriguing mix of flavors like mint, pear, citrus, cucumber and floral aspects. Pekko''s complex and clean characteristics of floral, citrus, and mint lend itself to many styles of beer.', 'Saaz (CZ), Azacca', NULL, 24.0, 17.5, 28.5, 25.0),
  ('bm-hop-perle-gr', 'Perle (GR)', 6.5, 3.75, 'pellet', 'Aroma', 'Germany', 'Specific aroma descriptors of the German Perle hop include herbal and spicy with delicate floral, fruit and mint tones.', 'Northern Brewer (US), Northern Brewer (GR), Perle (US)', NULL, 45.0, 15.0, 32.0, 27.5),
  ('bm-hop-perle-us', 'Perle (US)', 6.5, 3.5, 'pellet', 'Dual', 'United States of America', 'US Perle hops have aroma descriptors that include floral and spicy.  Perle is known for adding a traditional, German-like quality to beer.', 'Perle (GR), Northern Brewer (US), Northern Brewer (GR), Cluster, Galena', NULL, 31.0, 14.0, 31.5, 37.5),
  ('bm-hop-petit-blanc', 'Petit Blanc', 3.0, 5.5, 'pellet', 'Aroma', 'France', 'Petit Blanc hops have an intensive fruity flavor. Common descriptors include Papaya/Melon, Cherry, Lilac, Pina Colada, Lemon Blossom, Green Tea, Bees Wax.', NULL, NULL, NULL, NULL, 15.0, NULL),
  ('bm-hop-petoskey', 'Petoskey', 12.1, 6.16, 'pellet', 'Aroma', 'United States of America', 'Petoskey hops are "field grade" hops that come from Great Lake Hops (GLH). ', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-phoenix', 'Phoenix', 10.75, 4.4, 'pellet', 'Dual', 'United Kingdom', 'Phoenix hops have chocolate, pine, molasses and floral aromas.', 'Challenger,Northdown', NULL, 30.0, 11.0, 28.5, 24.0),
  ('bm-hop-pilgrim', 'Pilgrim', 11.0, 4.85, 'pellet', 'Dual', 'United Kingdom', 'Specific aroma descriptors of the Pilgrim hop include distinct fruit and spice characteristics with pleasant lemon, grapefruit, pear and berry flavors. Pilgrim is a bittering hop and it has a full-bodied, refreshing and rounded bitterness. However, Pilgrim is also not too overpowering, so it’s a great hop to use if you want a very versatile yet robust flavor.', 'Challenger, Pioneer, Challenger', NULL, 23.0, NULL, 37.0, 32.5),
  ('bm-hop-pilot', 'Pilot', 9.75, 4.15, 'pellet', 'Bittering', 'United Kingdom', 'Specific aroma descriptors of the Pilot hop include lemon, spice and marmalade. Pilot has a wonderfully refreshing, clean and crisp bittering quality.', 'Galena', NULL, 4.5, NULL, 32.5, 37.5),
  ('bm-hop-pioneer', 'Pioneer', 9.25, 4.0, 'pellet', 'Dual', 'United Kingdom', 'Specific aroma descriptors of the Pioneer hop include pleasant citrus (lemon and grapefruit) tones and hints of herbal, cedar flavors. Pioneer''s bittering characteristics are crisp, refreshing and clean.', 'Yeoman, Herald, Omega', NULL, 21.5, NULL, 38.0, 35.0),
  ('bm-hop-polaris', 'Polaris', 20.5, 5.5, 'pellet', 'Dual', 'Germany', 'Polaris hops have aroma descriptors that include mint, pineapple and menthol.', 'Herkules', NULL, 27.5, 10.5, 25.5, 50.0),
  ('bm-hop-premiant', 'Premiant', 8.0, 5.0, 'pellet', 'Bittering', 'Czech Replublic', 'Premiant hops have aroma descriptors that include pleasant, mild and fruity. The unusually low content of cohumulone in combination with other typical characteristics of this variety contributes to the neutral character of bitterness.', 'Styrian Golding, Saaz (CZ)', NULL, 30.0, 10.5, 20.5, 42.5),
  ('bm-hop-pride-of-ringwood', 'Pride of Ringwood', 9.0, 6.0, 'pellet', 'Bittering', 'Australia', 'Pride of Ringwood hops have aroma descriptors that include pronounced and pleasant with cedar, oak and herbal tones.', 'Centennial, Galena, Cluster', NULL, 3.0, 11.5, 32.5, 32.5),
  ('bm-hop-progress', 'Progress', 6.25, 2.25, 'pellet', 'Aroma', 'United Kingdom', 'Progress hops have aroma descriptors that include grass, mint, sweet, honey, and blackcurrant.', 'Golding, Fuggle', NULL, 43.5, 13.5, 26.0, 27.5),
  ('bm-hop-prussian', 'Prussian', 4.29, 2.73, 'pellet', 'Aroma', 'United States of America', 'GLH says the Prussian hop has lemony citrus aromas with piney notes.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-pulawski', 'Pulawski', 9.5, 3.5, 'pellet', 'Dual', 'Poland', 'Puławski has a pungent and complex aroma with white grapes, spices, clove and ripe papaya. Another promising new wave aroma hop.', NULL, NULL, 24.5, 12.0, 28.0, 38.5),
  ('bm-hop-rakau', 'Rakau', 10.5, 5.5, 'pellet', 'Dual', 'New Zealand', 'Specific aroma descriptors for the Rakau hop include stone fruit and fig characteristics; fresh orchard fruits, specifically apricot with some resinous pine needle characteristics are noted. Sometimes it is misspelled as Raku.', 'Amarillo, Summit', NULL, 16.5, 5.5, 24.0, 56.0),
  ('bm-hop-relax', 'Relax', 2.15, 12.5, 'pellet', 'Aroma', 'Germany', 'With cornflower and the aroma of alpine meadows to lemongrass and hibiscus, Relax hops have a refreshing profile. When a cold extraction with this variety is completed, notes of honeydew melon are present.', 'Monroe', NULL, NULL, NULL, NULL, 23.5),
  ('bm-hop-riwaka', 'Riwaka', 5.5, 4.5, 'pellet', 'Aroma', 'New Zealand', 'Specific aroma descriptors of the Riwaka hop includes powerfully fueled tropical passion fruit with grapefruit and citrus characters. This variety has a higher than average oil content, almost double that of its Saazer parent. ', 'Saaz (CZ),Citra,Calypso,Centennial,Motueka', NULL, 9.0, 4.0, 33.5, 68.5),
  ('bm-hop-saaz-cz', 'Saaz (CZ)', 3.5, 6.0, 'pellet', 'Aroma', 'Czech Replublic', 'Czech Republic Saaz has aroma descriptors that include mild with pleasant earthy, herbal and floral overtones.', 'Polish Lublin, Saaz (US), Sterling, Tettnang', 0.5, 22.5, 7.5, 24.5, 32.5),
  ('bm-hop-saaz-us', 'Saaz (US)', 3.75, 3.75, 'pellet', 'Aroma', 'United States of America', 'Saaz is a noble hop variety, and is considered one of the oldest known. Saaz hops have aromas that include earthiness with a mild spicy flavor to it. Saaz hops - regardless of the country they are grown in - are mostly only used for its aromas due to its low alpha acid content, which results in a delicate bitterness when added at the end of the boil.

Noble hops like Saaz, are aroma varieties that have an extensive history behind them. The term ‘noble’ has been used since the 1980’s and refers to hops that have been used in brewing beer for centuries. ', 'Saaz (CZ), Polish Lublin, Sterling, Tettnang, Sorachi Ace', 0.25, 37.5, 10.0, 26.0, 27.5),
  ('bm-hop-saaz-late', 'Saaz Late', 4.75, 5.25, 'pellet', 'Aroma', 'Czech Replublic', 'Beer hopped with Saaz Late is close to beers hopped with the traditional Saaz variety, but the lingering of the bitterness is slightly less. The character of the bitterness is somewhat less with greater astringency.', 'Saaz (CZ), Saaz (US)', NULL, 20.0, 7.5, 22.5, 30.0),
  ('bm-hop-sabro', 'Sabro', 14.5, 5.5, 'pellet', 'Aroma', 'United States of America', 'The Sabro hop has complex and distinct fruit and citrus aromas. It also has a unique blend of tangerine, coconut, tropical and stone fruit flavors underscored by hints of cedar and mint. Sabro proves to be a strongly expressive hop that translates its flavor incredibly well into beer.', NULL, 0.242, 10.5, 9.0, 22.0, 59.0),
  ('bm-hop-samba', 'Samba', 10.0, 5.0, 'pellet', 'Aroma', 'United States of America', 'Complex aroma characterized by juicy tropical fruits (pineapple, mango), stone fruits, candy, and orange tangerine.', NULL, NULL, NULL, NULL, 30.0, NULL),
  ('bm-hop-santiam', 'Santiam', 6.75, 6.9, 'pellet', 'Aroma', 'United States of America', 'Santiam hops have aroma descriptors that include black pepper, floral and spice.', 'Citra, Spalt, Spalter Select, Tettnang', 0.45, 25.0, 7.5, 21.0, 20.0),
  ('bm-hop-saphir', 'Saphir', 3.25, 5.5, 'pellet', 'Aroma', 'Germany', 'Saphir hops have aroma descriptors that include spicy, fruity and floral with hints of tangerine tones.', 'Hallertau Mittelfruh, Hallertau, Spalter Select', NULL, 25.0, 11.5, 14.5, 32.5),
  ('bm-hop-sasquatch', 'Sasquatch', 7.8, 8.2, 'pellet', 'Dual', 'Canada', 'Sasquatch is Canada’s first patented, proprietary hop, grown only in Canada. Sasquatch is a unique dual-purpose hop with orange, tea, lemon citrus notes with an alpha content between 6.6 to 9%. One of the main reasons it was called Sasquatch is due to the rugged mountain terrain that it was found in as well as the massive hop cones that Sasquatch produces.', NULL, NULL, 13.5, 5.5, 34.5, 60.5),
  ('bm-hop-satus', 'Satus', 13.25, 8.75, 'pellet', 'Bittering', 'United States of America', 'Satus is a high alpha dual-use hop considered great as a clean foundational hop when used at the beginning of a boil and when an extra punch of hops is desired. When it is used late in the boil, strong citrus notes come to the forefront.', 'Nugget, Galena', NULL, 17.5, 8.5, 33.5, 42.5),
  ('bm-hop-saugatuck', 'Saugatuck', 5.4, 3.27, 'pellet', 'Aroma', 'United States of America', 'Not much is written about the Saugatuck hop from GLH, but their description mentions that it is "fragrant", and hard to pin down but pleasant and interesting.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-sequoia', 'Sequoia Blend', 10.5, 4.5, 'pellet', 'Aroma', 'United States of America', 'Pronounced tropical fruit (mango, pineapple) with citrus and pine.', NULL, NULL, NULL, 7.0, 30.0, 60.0),
  ('bm-hop-shaddock', 'Shaddock', 4.96, 3.59, 'pellet', 'Aroma', 'United States of America', 'Shaddock hops are described by GLH has having a bright & interesting lime and grapefruit aroma that also oddly has notes of onion and garlic.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-simcoe', 'Simcoe', 13.0, 4.0, 'pellet', 'Dual', 'United States of America', 'Alongside its fruity and slightly earthy aromas, specific descriptors of the Simcoe hop includes grapefruit, passion fruit, pine and berry characteristics. In addition to its great bittering qualities, the Simcoe hop variety - often referred to as "Cascade on steroids" - is known for its tropical fruit flavors. It is commonly used in India pale ales and pale ales.

Simcoe is frequently used for bittering due to its high alpha acid percentages, but can be used as a late addition as well to bring out more fruity aromas. It has since become one of the most popular hops for both the craft beer and homebrewing industries. At 12%-14% Alpha Acid, Simcoe adds a smooth bitterness, but also packs a punch of stone fruit, pine, and citrus zest aromas. It truly is a dual purpose hop that is capable of standing on its own in single-hopped beers in a wide range of styles.', 'Summit, Magnum (US), Amarillo, Mosaic, Cascade, Centennial, Citra, Columbus', 0.268, 17.5, 11.0, 18.0, 45.0),
  ('bm-hop-sitiva', 'Sitiva Blend', 7.4, 4.35, 'pellet', 'Aroma', 'United States of America', 'Sitiva has ripe stone fruit, sweet floral, and soft peach flavors and aromas, as well as tropical fruit and lime character.', NULL, NULL, 10.5, NULL, 27.5, 54.0),
  ('bm-hop-sladek', 'Sládek', 6.75, 7.5, 'pellet', 'Aroma', 'Czech Replublic', 'Sládek hops have a fruity flavor profile with essences of peach, passion fruit, and grapefruit. Sládek is noted to be a good complement to Saaz in late-hopping applications.', 'Saaz (CZ), Saaz (US), Northern Brewer (GR), Northern Brewer (US)', NULL, 30.0, 11.5, 31.5, 42.5),
  ('bm-hop-smaragd', 'Smaragd', 5.0, 4.5, 'pellet', 'Bittering', 'Germany', 'Smaragd has aroma descriptors that include floral, spicy and mild fruity. Smaragd is a fine aroma variety with many noble characteristics.', 'Hallertau Mittelfruh, Opal', NULL, 40.0, 11.5, 15.5, 30.0),
  ('bm-hop-smooth-cone', 'Smooth Cone', 8.25, 4.3, 'pellet', 'Dual', 'New Zealand', 'Smooth Cone is a New Zealand hop variety that is no longer grown commercially but can still be found around.', 'Cluster', 0.35, 21.0, 6.0, 31.0, 55.0),
  ('bm-hop-solero', 'Solero', 10.1, 6.0, 'pellet', 'Aroma', 'Germany', 'The Solero hop is a dual-purpose hop known to have strong fruit aromas and flavors including tropical and passion fruits along with mango.', NULL, NULL, NULL, NULL, 37.5, NULL),
  ('bm-hop-sonnet', 'Sonnet', 5.0, 2.85, 'pellet', 'Aroma', 'United States of America', 'Sonnet has a beautiful honeysuckle floral note with a sweet lemon citrus undertone.  Use it in classic English styles, and of course cask conditioned ales.', 'East Kent Golding,Hersbrucker,Crystal,Saaz (CH), Saaz (US)', NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-sorachi-ace', 'Sorachi Ace', 13.5, 7.0, 'pellet', 'Dual', 'Japan', 'Sorachi Ace hops have aroma descriptors that include lemon, lime and dill. It remains a  popular variety among craft brewers for its unique citrus fruit and herbal aromas. ', 'Southern Cross', 0.275, 23.0, 9.0, 25.5, 50.0),
  ('bm-hop-southern-aroma', 'Southern Aroma', 5.45, 5.7, 'pellet', 'Aroma', 'South Africa', 'The aroma profile of the Southern Aroma hop includes floral, fields of flowers, woody/spicy, and fruity. It is a hop with classic noble hop character and a fruity South African terroir backdrop.', 'Motueka', NULL, 22.5, 14.0, 22.0, 22.5),
  ('bm-hop-southern-brewer', 'Southern Brewer', 10.0, 3.75, 'pellet', 'Bittering', 'South Africa', 'It is considered a bitter hop with no outstanding aroma qualities.', 'Southern Promise, Fuggle', NULL, NULL, NULL, 39.5, NULL),
  ('bm-hop-southern-cross', 'Southern Cross', 12.5, 6.0, 'pellet', 'Dual', 'New Zealand', 'Southern Cross hops have aroma descriptors that include citrus and tropical fruit with hints of lemon zest, lime, pine and spice. It has excellent essential oils and low co-humulone delivering a delicate balance of citrus and spice when added at the end of boil.', 'Sorachi Ace', NULL, 17.0, 6.5, 26.5, 43.0),
  ('bm-hop-southern-dawn', 'Southern Dawn', 12.35, 5.1, 'pellet', 'Dual', 'South Africa', 'Southern Dawn is a great neutral bittering addition for hoppy styles like IPAs or Pale Ales. ', NULL, NULL, 21.0, 9.5, 32.0, 33.5),
  ('bm-hop-southern-passion', 'Southern Passion', 12.6, 6.45, 'pellet', 'Aroma', 'South Africa', 'The aroma profile of the Southern Passion hop includes passion fruit, guava, red berries, floral, coconut, melon, calendula, and grapefruit.', NULL, NULL, 25.0, 10.5, 21.0, 37.5),
  ('bm-hop-southern-promise', 'Southern Promise', 12.0, 4.7, 'pellet', 'Dual', 'South Africa', 'Southern Promise is a dual-purpose hop with smooth, clean bitterness and a woody, earthy fragrance.', 'Southern Brewer', NULL, 25.0, 9.0, 21.0, 23.0),
  ('bm-hop-southern-star', 'Southern Star', 15.3, 5.75, 'pellet', 'Dual', 'South Africa', 'This hop offers clean, crisp and efficient bittering with slight berry, floral and citrus notes. Detailed aroma descriptors include pineapple, blueberries, tangerine, tropical fruit, passion fruit, quince, pear, cassis, rose petals, orange and coffee.', 'Mosaic, Ekuanot, El Dorado, Mandarina Bavaria, Southern Cross, Warrior', NULL, 25.0, 12.0, 28.0, 35.0),
  ('bm-hop-southern-sublime', 'Southern Sublime', 12.1, 4.9, 'pellet', 'Aroma', 'South Africa', 'The aroma profile of Southern Sublime (N1/69) is Kool-Aid, Juicy Fruit, citrus, mango, plums, dank, and pungent. Works well with intensely hop-forward beers like modern IPAs. It also has classic noble hop character with a fruity terroir backdrop.', NULL, NULL, 3.0, 6.0, 26.0, 50.0),
  ('bm-hop-southern-tropic', 'Southern Tropic', 15.35, 5.75, 'pellet', 'Bittering', 'South Africa', 'Southern Tropic is very fruit forward with sweet fruits of mango, plums, and grapefruit. Some brewers have described an aroma similar to Kool-Aid or Juicy Fruit. This hop works well with all hop-forward beers where tropical fruit characteristics are desired.', NULL, NULL, 27.0, 10.0, 28.0, 32.5),
  ('bm-hop-sovereign', 'Sovereign', 5.5, 2.6, 'pellet', 'Aroma', 'United Kingdom', 'Sovereign hops have aroma descriptors that include pleasant but intense fruity flavors with mild floral, grassy, herbal, pear and mint characteristics. It is often used in conjunction with Goldings in English-style beers.', 'Fuggle', NULL, 23.5, 8.0, 28.0, 25.5),
  ('bm-hop-spalt', 'Spalt', 4.1, 4.0, 'pellet', 'Aroma', 'Germany', 'Spalt - or Spalter - hops have aroma descriptors that include noble characteristics, earthy, spicy herbal and floral.', 'Saaz (CZ), Tettnang, Ultra, Tettnanger, Santiam, Liberty, Hallertau ', NULL, 25.0, 10.5, 25.5, 27.5),
  ('bm-hop-spalter-select', 'Spalter Select', 4.75, 3.75, 'pellet', 'Aroma', 'Germany', 'Sometimes referred to as just "Select", Spalter Select hops have aroma descriptors that include spicy and grass.', 'Tettnanger, Saaz (CZ), Spalt, Perle (GR), Hallertau Tradition', NULL, 16.0, 7.0, 24.0, 30.0),
  ('bm-hop-sterling', 'Sterling', 7.0, 5.0, 'pellet', 'Aroma', 'United States of America', 'Sterling hops have aroma descriptors that include noble and spicy.', 'Saaz (US), Mount Hood', 0.27, 17.0, 6.5, 25.0, 40.0),
  ('bm-hop-sticklebract', 'Sticklebract', 13.5, 7.25, 'pellet', 'Dual', 'New Zealand', 'Sticklebract was originally released as a high alpha bittering hop, but has become a dual-purpose variety characterized by citrus and pine flavors.', 'Northern Brewer (GR), Hersbrucker, Hallertau, Sorachi Ace, Simcoe', NULL, 16.5, 8.0, 40.0, 39.0),
  ('bm-hop-sticky-fingers', 'Sticky Fingers Blend', 11.92, 4.59, 'pellet', 'Dual', 'United States of America', 'A blend made up of 21 purely Michigan-grown hops with huge complex aroma notes of dankness, fruitiness and spice.', NULL, 0.339, NULL, NULL, 28.5, NULL),
  ('bm-hop-stirling', 'Stirling', 9.0, 5.0, 'pellet', 'Dual', 'United States of America', 'The spicy characteristics of the Saaz play well with the bright citrus from the Cascade. While it is primarily used as an aroma hop, it is versatile enough to work in a wide range of styles and uses.', 'Saaz (US)', 0.7, 21.0, 6.0, 24.5, 46.0),
  ('bm-hop-strata', 'Strata', 11.75, 6.0, 'pellet', 'Dual', 'United States of America', 'The Strata hop has many layers of different fruit flavor, dried and fresh, anchored with a dried chili-cannabis-funk. Late hot side additions using Strata bring out layers of rounded-tropical plus bright-fresh fruit flavors; dry hopping yields more grapefruit and cannabis. Other descriptors include passion fruit, strawberry and dank.', 'Galaxy, Mosaic', NULL, 26.0, 9.0, 21.0, 58.5),
  ('bm-hop-strisselspalt', 'Strisselspalt', 2.5, 4.5, 'pellet', 'Aroma', 'France', 'Strisselspalt has a delicate, pleasant and well-balanced aroma. Due to its delicate aromas, Strisselspalt is ideal for use in late hop additions or in dry hopping. Some commonly used aroma descriptors for the Strisselspalt hop include spicy, citrusy, floral, fruity and herbal.', 'Crystal, Hersbrucker, Mount Hood,Liberty,Hallertau', NULL, 17.0, 9.0, 23.5, 43.5),
  ('bm-hop-cardinal', 'Styrian Cardinal', 11.5, 3.9, 'pellet', 'Aroma', 'Slovenia', 'Cardinal hops are known to have a typical citrus and fruity notes as well as a harmonious flavor.', NULL, NULL, 18.5, 9.5, 34.0, 45.0),
  ('bm-hop-styrian-dragon', 'Styrian Dragon', 8.5, 8.0, 'pellet', 'Aroma', 'Slovenia', 'Profile descriptions for the Styrian Dragon include floral citrus, grapefruit, lemon, berries, rose, and tropical fruit.  Works well with all hop-forward beers including American, Belgian, and British styles, especially modern IPAs.', NULL, NULL, 27.5, 14.0, 23.5, 60.5),
  ('bm-hop-styrian-eagle', 'Styrian Eagle', 15.0, 4.5, 'pellet', 'Dual', 'Slovenia', 'Styrian Eagle is a Double Purpose hop. An all-around good hop with a high alpha, good disease resistances and fruity and floral aroma. Characteristics include Floral, Peach, Pine', NULL, NULL, 1.25, 5.5, 21.5, 56.0),
  ('bm-hop-styrian-fox', 'Styrian Fox', 8.85, 3.05, 'pellet', 'Dual', 'Slovenia', 'Styrian Fox is one of the latest Styrian hops on the market. When brewed, expect floral and fruity notes. Some brewers even say they get hints of pepper and mild tobacco flavours from this hop unique strain.', NULL, NULL, 13.0, 5.0, 28.0, 55.0),
  ('bm-hop-styrian-golding', 'Styrian Golding', 5.0, 3.0, 'pellet', 'Aroma', 'Slovenia', 'Styrian Golding hops have a spice with an earthy/sweet edge. It is a prized aroma hop and exhibits resinous, earthy flavors that are considered slightly more refined than Fuggle.', 'Fuggle, Willamette, Bobek', 0.275, 36.0, 10.0, 27.5, 30.0),
  ('bm-hop-styrian-kolibri', 'Styrian Kolibri', 5.0, 4.1, 'pellet', 'Aroma', 'Slovenia', 'When Styrian Kolibri was used by craft brewers, they have noticed very attractive floral notes in a range of beer varieties.', NULL, NULL, 18.5, 6.0, 23.0, 34.5),
  ('bm-hop-styrian-wolf', 'Styrian Wolf', 14.25, 4.05, 'pellet', 'Dual', 'Slovenia', 'Styrian Wolf hops have intense fruity and floral notes including flavors of sweet tropical fruits and complex aromas of mango, coconut, lemongrass, elderflower and even a touch of violet.', NULL, NULL, 7.0, 2.5, 22.5, 65.0),
  ('bm-hop-denali', 'Sultana (Denali)', 14.5, 5.25, 'pellet', 'Dual', 'United States of America', 'Sultana was formerly called Denali, however it is also called Nuggetzilla by some. This hop is rich in pineapple, citrus (often perceived as lemon), and pine flavors, though it can often come off as spicy as well.', 'Columbus, Tomahawk, Zeus, CTZ, Nugget', NULL, 16.0, 6.0, 24.0, 54.5),
  ('bm-hop-summer', 'Summer', 6.0, 5.45, 'pellet', 'Aroma', 'Australia', 'Summer hops have delicate notes of grass, stone fruit (peach), passion fruit, and citrus. It showcases distinct apricot and melon characteristics in dry hopping applications.  It is not as spicy as its Czech parent.', 'Palisade, Saaz (US)', NULL, 39.0, 9.5, 22.5, 33.5),
  ('bm-hop-summit', 'Summit', 16.25, 5.25, 'pellet', 'Bittering', 'United States of America', 'Summit hops'' aroma descriptors include pepper, incense, anise, orange, pink grapefruit and tangerine.  Summit is mainly used as a bittering hop, but does have earthy aromatic characteristics and subtle hints of citrus. Summit hops at times picks up notes of sulfur (like garlic/onion), so be careful when using this hop.

', 'Columbus, Tomahawk, Zeus, CTZ, Warrior, Millennium, Simcoe, Amarillo, Cascade', 0.15, 20.0, 14.0, 29.5, 35.0),
  ('bm-hop-sun', 'Sun', 14.0, 5.75, 'pellet', 'Bittering', 'United States of America', 'Sun hops have herbaceous aroma and flavor.', 'Magnum (GR), Magnum (US), Galena, Zeus', NULL, NULL, NULL, 35.0, NULL),
  ('bm-hop-sunbeam', 'Sunbeam', 4.5, 2.5, 'pellet', 'Aroma', 'United States of America', 'Sunbeam is an ornamental hop that was discovered to be inadvertently useful as an aroma hop. Selected in 1992 in Corvallis, Oregon.', NULL, NULL, 14.0, 4.0, 36.0, 56.0),
  ('bm-hop-super-galena', 'Super Galena', 14.5, 9.0, 'pellet', 'Bittering', 'United States of America', 'Super Galena hops have aroma descriptors that include sweet fruits, pear, pineapple, blackcurrant, grapefruit, lime, gooseberry and spicy wood. Super Galena is comparable to Galena in its aroma and bitterness profile, but offers a substantially higher yield and complete resistance to all current hop powdery mildew strains found in the U.S.', 'Galena, Nugget, Cluster, Chinook', NULL, NULL, NULL, 37.5, 52.5),
  ('bm-hop-super-pride', 'Super Pride', 14.4, 6.25, 'pellet', 'Dual', 'Australia', 'Super Pride hops have aroma descriptors that include mild and pleasant subtle resin and fruit tones.', 'Pride of Ringwood', NULL, 1.5, 7.0, 37.5, 38.0),
  ('bm-hop-sussex', 'Sussex', 5.05, 2.8, 'pellet', 'Aroma', 'United Kingdom', 'Sussex hops have aroma descriptors that include earthy, grass, mint, citrus and vanilla.', 'Progress, Whitbread Golding Variety, Fuggle', NULL, 23.0, NULL, 30.5, 42.0),
  ('bm-hop-sybilla', 'Sybilla', 7.0, 7.5, 'pellet', 'Aroma', 'Poland', 'Sybilla hops include floral, citrus, chocolate, orange, gingerbread and tobacco aromas.', 'Perle (US), Perle (GR), Northern Brewer (US), Northern Brewer (GR), Magnum (GR), Magnum (US), Nugget, Bobek, Lubelski', NULL, 42.5, NULL, 28.5, 39.0),
  ('bm-hop-sylva', 'Sylva', 5.65, 5.0, 'pellet', 'Aroma', 'Australia', 'Sylva hops have flavors of the forest and fresh-cut timber, subtle and hoppy bohemian-style aroma.', 'Hallertau Mittelfruh, Helga, Saaz (US), Northern Brewer (US)', NULL, 22.5, 6.5, 24.0, 31.0),
  ('bm-hop-tahoma', 'Tahoma', 7.6, 9.0, 'pellet', 'Aroma', 'United States of America', 'Tahoma hops have subtle flavors and aromas of the Tahoma hop include lemon citrus, orange, wood and spice.', 'Glacier', 0.307, 10.0, 3.0, 16.0, 69.5),
  ('bm-hop-taiheke', 'Taiheke', 7.0, 5.25, 'pellet', 'Dual', 'New Zealand', 'Remarkable levels of citrus notes that lean towards tropical fruit characteristics, such as grapefruit, lemon and lime. It is characterized by a floral, citrus profile, with a hint of spice.', NULL, NULL, 15.0, 7.5, 36.5, 55.0),
  ('bm-hop-talisman', 'Talisman', 6.85, 3.2, 'pellet', 'Dual', 'United States of America', 'Talisman has been discontinued. ', NULL, NULL, 4.0, 5.5, 53.0, 68.0),
  ('bm-hop-talus', 'Talus', 8.8, 9.25, 'pellet', 'Aroma', 'United States of America', 'Previously called HBC 692, the newly named Talus is an aroma hop for whirlpool and dry hopping additions. It delivers a high intensity hop aroma well suited for IPAs and other hop-forward beers. Talus hops exhibit grapefruit, floral, stone fruit, potpourri, woody, cream, pine, and resinous notes.', 'Sabro', NULL, 18.5, 11.0, 36.5, 45.0),
  ('bm-hop-tango', 'Tango', 9.25, 8.75, 'pellet', 'Dual', 'Germany', 'Depending on the beer type and dosage, this hop can impart a strong citrus flavor with pineapple, passion fruit and cassis notes.', NULL, NULL, NULL, NULL, 22.0, NULL),
  ('bm-hop-tardif-de-bourgogne', 'Tardif de Bourgogne', 3.75, 4.45, 'pellet', 'Aroma', 'France', 'Having top notes of pine, frankincense and rose petals. It is a great alternative for those whose palates are dank and bleary, from the current onslaught of the sweet and heavy.  Tardif de Bourgogne is an old school French noble varietal that was commercially successful in lager beers prior to the introduction of the popular French Strisselspalt.  It’s name loosely translates to “late harvest of burgundy.”', 'Strisselspalt', NULL, NULL, NULL, 20.0, NULL),
  ('bm-hop-target', 'Target', 11.0, 5.0, 'pellet', 'Bittering', 'United Kingdom', 'Specific aroma descriptors of the Target hop include fresh green sage, spicy and peppery, and hints of citrus marmalade. Whirlpool or dry hop additions play up the spice character. Target offers crisp bittering and moderate alpha acids.', 'Fuggle, Willamette', NULL, 20.0, 9.0, 37.5, 50.0),
  ('bm-hop-teamaker', 'Teamaker', 1.2, 9.3, 'pellet', 'Aroma', 'United States of America', 'Teamaker has the lowest alpha acid (it is not bitter at all) content of any commercially available variety, while its beta acids are higher than even Galena. This high beta-to-alpha ratio means, while Teamaker is not bitter, it is highly aromatic and still has all the antibacterial and health benefits of other hop varieties.', 'Crystal', NULL, 1.5, 12.0, NULL, 60.0),
  ('bm-hop-tettnang-us', 'Tettnang (US)', 4.0, 4.0, 'pellet', 'Aroma', 'United States of America', 'The American Tettnanger has noble characteristics.', 'Tettnanger, Fuggle, Santiam, Spalter Select, Spalt', NULL, 20.5, 6.5, 24.0, 37.5),
  ('bm-hop-tettnanger', 'Tettnanger', 4.15, 4.05, 'pellet', 'Dual', 'Germany', 'Tettnanger has notably more farnesene oil content giving it a soft spiciness and a subtle, balanced, floral and herbal aroma. It is great as a dual-use hop, and considered by many as being particularly well suited to European lagers and pilsners. Often used in Hefeweizen beers.', 'Tettnang (US), Spalter Select, Spalt, Saaz (CZ), Lubelski', NULL, 20.5, 6.5, 25.0, 40.5),
  ('bm-hop-tillicum', 'Tillicum', 14.5, 10.5, 'pellet', 'Bittering', 'United States of America', 'Tillicum is a high alpha variety with a very high content of beta acids. The variety was developed through the John I. Haas, Inc. breeding program and released in 1995. It is a daughter of Galena and a full sister to Chelan and therefore has analytical data similar to both varieties.', 'Galena,Chelan', NULL, 14.0, 7.5, 35.0, 40.0),
  ('bm-hop-tnt-blend', 'TNT Blend', 12.25, NULL, 'pellet', 'Aroma', 'United States of America', 'T''N''T blend is a fruity explosion of flavor on your tongue and unforgettably refreshing. It is a select blend of dynamite German hop varieties. This blend is designed specifically to major on the red fruits, sweet fruits and citrus to give a beer a solid tropical foundation.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-tomahawk', 'Tomahawk', 16.25, 5.25, 'pellet', 'Dual', 'United States of America', 'Tomahawk has aroma descriptors that include black pepper, licorice, curry and subtle citrus.', 'Columbus, CTZ, Zeus, Centennial, Chinook, Galena, Nugget, Millennium', NULL, 11.5, 8.0, 31.5, 50.0),
  ('bm-hop-topaz', 'Topaz', 16.9, 6.4, 'pellet', 'Dual', 'Australia', 'Topaz hops have light, tropical fruit flavors of lychee, clove-like spice and resinous grassy tones. This is a fantastic hop to use when dry hopping. When used with later additions and in higher gravity brews, specific flavor qualities come out as pleasant, and more pronounced light tropical fruit.', 'Galaxy, Citra, Cascade, Riwaka, Rakau, Amarillo', NULL, 12.0, 9.5, 50.0, 37.0),
  ('bm-hop-toyomidori', 'Toyomidori', 12.0, 5.5, 'pellet', 'Bittering', 'Japan', 'Toyomidori has mild fruity flavors and a relatively high alpha percentage, so it is perfect for bittering.', NULL, 0.37, 10.5, 4.5, 40.0, 59.0),
  ('bm-hop-trident', 'Trident', 12.5, 4.5, 'pellet', 'Dual', 'United States of America', 'Trident is a specialized blend with a much wider range of aroma and flavor characteristics than any single hop variety could generate on its own. Although, Trident is suitably balanced as is, it could also be added with others to build an even more unique and potent flavor profile.', NULL, NULL, NULL, NULL, 25.0, NULL),
  ('bm-hop-triplepearl', 'TriplePearl', 10.6, 3.75, 'pellet', 'Dual', 'United States of America', 'Triple Pearl present complex aromas of black pepper, cedar/sandalwood, and floral perfume. ', 'Perle (US)', 0.28, 9.0, 4.0, 38.0, 47.0),
  ('bm-hop-triskel', 'Triskel', 6.0, 4.75, 'pellet', 'Aroma', 'France', 'Triskel has inherited the aromatic notes of Strisselspalt in a particularly pronounced manner. Its notes are fruity, citrusy and flowery. Its oil content makes for interesting potential in late hopping, and especially in dry hopping. At the same time, its alpha acid content also creates an interesting alternative for first wort hopping.', 'Strisselspalt, Ahtanum, Centennial, Chinook, Simcoe', NULL, 13.0, 2.5, 21.5, 58.0),
  ('bm-hop-triumph', 'Triumph', 10.5, 4.0, 'pellet', 'Dual', 'United States of America', 'Triumph hops have intense and fruity aromas with prominent peach, lime, and orange, followed with suggestions of spice and pine. Triumph is more delicate than other fruit forward varieties, but still robust enough to be used in a wide range of styles.', 'Nugget, Hallertau', 0.26, 31.0, 9.0, 24.0, 32.5),
  ('bm-hop-tropica', 'Tropica', 8.8, 3.0, 'pellet', 'Dual', 'United States of America', 'Mighty Axe’s custom growing practices create Tropica’s distinct tropical character.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-tsingdao-flower', 'Tsingdao Flower', 7.0, 3.6, 'pellet', 'Dual', 'China', 'Tsingdao Flower is the dominant hop grown in Gansu, China.  Also referred to as "Qingdao" Flower hops. Has a birght and crisp lemon-peel quality to the bitterness.', 'Cluster', NULL, NULL, NULL, 35.0, NULL),
  ('bm-hop-ultra', 'Ultra', 6.35, 4.3, 'pellet', 'Aroma', 'United States of America', 'Ultra hops have aroma descriptors that include mild, spicy and floral bouquet. Ultra is related to traditional German varieties and can be utilized in similar applications.', 'Hallertau, Crystal, Liberty, Mount Hood, Saaz (US), Tettnanger', NULL, 12.5, 7.5, 30.0, 55.0),
  ('bm-hop-usda-008', 'USDA 008', 10.6, 3.0, 'pellet', 'Dual', 'United States of America', 'USDA 008 is very fruit-forward with tangerine, meyer lemon, and stonefruit. There is a nice backdrop of fresh pine that makes it complex in a classic west coast IPA kind of way. Notes of green apple, peach, and mango are rounded out with grassy and subdued earth characteristics. A great choice for adding a new dynamic to West Coast IPAs and hoppy/hazy pale ales.', NULL, 0.317, 48.5, 16.5, 25.5, 6.5),
  ('bm-hop-vanguard', 'Vanguard', 5.25, 6.25, 'pellet', 'Aroma', 'United States of America', 'Vanguard hops have aroma descriptors that include woody and cedar notes. It is an aroma variety with similar characteristics to Hallertau Mittelfrüh. Vanguard is typically utilized in traditional German style beers as a noble type  variety.', 'Hallertau, Hersbrucker, Mount Hood, Liberty', NULL, 52.0, 15.0, 17.0, 10.0),
  ('bm-hop-vic-secret', 'Vic Secret', 17.9, 7.2, 'pellet', 'Dual', 'Australia', 'Vic Secret is an Australian hop known for its bright tropical character of pineapple, pine, and passion fruit. Other aroma descriptors include tropical fruit, pine and herbs. It displays a more earthy character when added late in the boil, but is now commonly added as a whirlpool or dry hop in IPAs. Its flavors are similar to Galaxy hops, but are lighter in nature.', 'Galaxy', NULL, 15.0, 12.0, 54.0, 38.5),
  ('bm-hop-vienna-gold', 'Vienna Gold', 8.0, NULL, 'pellet', 'Dual', 'Australia', 'Vienna Gold is a hop variety that was grown widely in Australia several decades ago. However, due to the arrival of higher alpha varieties like Pride of Ringwood, it became less fashionable and was eventually discontinued. Vienna Gold is a highly vigorous growing variety that produces high yields of flowers and is easy to grow. This hop is not available commercially and is now only grown by homebrewers. It has a flavor similar to a German noble hop.', 'Cluster', NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-vista', 'Vista', 10.0, 4.5, 'pellet', 'Dual', 'United States of America', 'Brewers who participated in the blind smell tests described Vista as having Stone Fruit, Citrus, Tropical Fruit, and Floral characteristics. It can excel in fruit-forward IPAs and Pale Ales, but brewers also said it would work well in lighter, more delicate styles like lagers and pilsners.', NULL, NULL, 20.0, 12.0, 30.0, 35.0),
  ('bm-hop-vital', 'Vital', 12.5, 8.5, 'pellet', 'Dual', 'Czech Replublic', 'Vital hops have key flavors of plum, lavender, spice and licorice. It is very useful for bittering.', NULL, NULL, 3.5, 6.5, 23.5, 50.0),
  ('bm-hop-wai-iti', 'Wai-iti', 3.0, 5.0, 'pellet', 'Aroma', 'New Zealand', 'The New Zealand Wai-iti hop is lush and fragrant with dominant notes of stone fruit (notably peach and apricot) with pleasantly intense tropical citrus tones of lime and mandarin.', 'Riwaka', NULL, 28.0, 9.0, 23.0, 3.0),
  ('bm-hop-waimea', 'Waimea', 16.75, 8.0, 'pellet', 'Dual', 'New Zealand', 'Waimea hops have aroma descriptors that include lots of pine and citrus characters along with intense tangelo or mandarin.', 'Pacific Jade', NULL, 9.5, 2.5, 23.0, 60.0),
  ('bm-hop-wakatu', 'Wakatu', 7.5, 8.25, 'pellet', 'Dual', 'New Zealand', 'Wakatu has a pronounced earthy-sweet floral Hallertau character underscored by tropical fruit notes. Other specific aroma descriptors include restrained floral notes and freshly zested lime.', 'Hallertau Mittelfruh, Nelson Sauvin', NULL, 16.5, 8.5, 29.0, 35.5),
  ('bm-hop-walhalla', 'Walhalla', 7.985, 4.875, 'pellet', 'Aroma', 'United States of America', 'GLH says that Walhalla hops have a light citrus aroma with a hint of garlic (very faint), grassiness and herbal notes.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-warrior', 'Warrior', 16.25, 5.15, 'pellet', 'Dual', 'United States of America', 'Warrior has mild aromas with notes of resin and subtle pine. It was created for its high alpha content, low co-humulone, good storage stability and tolerance to powdery mildew. It is primarily used for its mild, clean bittering properties.', 'Columbus, Tomahawk, Zeus, CTZ, Nugget, Magnum (GR), Magnum (US), Summit', 0.24, 16.5, 12.5, 24.0, 45.0),
  ('bm-hop-whitbread-golding-variety-wgv', 'Whitbread Golding Variety (WGV)', 6.55, 2.75, 'pellet', 'Dual', 'United Kingdom', 'Whitbread Golding hops have fragrantly woodsy with overtones of fresh garden herbs and green fruit, thanks to good proportions of humulene and farnesene. It displays many similar characteristics but has more robust and slightly sweet, hoppy flavor.', 'Fuggle', NULL, 38.5, 13.0, 39.0, 23.0),
  ('bm-hop-wild-loyalist', 'Wild Loyalist', 4.65, 5.7, 'pellet', 'Aroma', 'Canada', 'With an alpha and beta profile similar to the noble hops, our Wild Loyalist contributes mild black pepper, herbal, earth, with a floral backend. ', 'Saaz (US), Styrian Golding', NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-wild-wolf', 'Wild Wolf', 8.25, 5.88, 'pellet', 'Dual', 'United States of America', 'Wild Wolf has soft fruit, herbal and natural earthy notes that make this a nice, approachable hop.', NULL, 0.303, NULL, NULL, NULL, NULL),
  ('bm-hop-willamette', 'Willamette', 5.6, 3.75, 'pellet', 'Dual', 'United States of America', 'Willamette hops have aroma descriptors that include floral, incense, and elderberry.', 'Glacier, Fuggle, Tettnang (US), Styrian Golding, East Kent Golding', 0.375, 23.5, 7.5, 31.5, 35.0),
  ('bm-hop-wurttemberg', 'Wurttemberg', 3.8, 3.1, 'pellet', 'Aroma', 'Germany', 'Wurttemberg is a legacy variety that carries a kaffir lime citrus and floral notes, as well as a pleasantly soft expression of pine and oregano spice.', 'Tettnanger', NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-x13459', 'X13459', 4.25, 4.5, 'pellet', 'Aroma', 'United States of America', 'This aroma cultivar is new in 2020 and known to have strong fruit flavors including citrus, peach and strawberry.', NULL, NULL, NULL, NULL, 22.5, NULL),
  ('bm-hop-xja2-436', 'XJA2/436', 13.95, 8.1, 'pellet', 'Bittering', 'South Africa', 'This hop has some potent bittering qualities. The aroma profile of XJA/436 is bergamot citrus, dried lemon zest, candied papaya, ripe cantaloupe, gooseberries, and resin.', 'Simcoe, Centennial, Bergamot', NULL, 28.0, 12.0, 29.5, 24.0),
  ('bm-hop-yakima-cluster', 'Yakima Cluster', 7.1, 4.55, 'pellet', 'Bittering', 'United States of America', 'Traits of the Yakima Cluster hop include a moderate bittering, some earthy flavors and a flowery aroma with elements of sweet fruit. All Cluster hops are interchangeable in brewing and quality.', 'Chinook, Cluster', NULL, 18.0, 6.5, 40.5, 50.0),
  ('bm-hop-yakima-gold', 'Yakima Gold', 7.5, 4.0, 'pellet', 'Dual', 'United States of America', 'Yakima Gold hops are an excellent general purpose variety with smooth bitterness and pleasant aroma characteristics.', 'Cluster', 0.316, 21.0, 7.0, 22.0, 40.0),
  ('bm-hop-yellow-sub', 'Yellow Sub', 6.7, NULL, 'pellet', 'Aroma', 'Germany', 'This composition turns a fine and excellent hop aroma into a sweet, fruity flamenco of apricot and orange, with a hint of blackberries. It''s been described as "Amarillo on steroids".', 'Amarillo', NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-yeoman', 'Yeoman', 14.0, 4.5, 'pellet', 'Dual', 'United Kingdom', 'Yeoman has a strong English hop aroma with citrus notes.

Discontinued.', 'Target', NULL, 20.0, 9.5, 25.0, 48.0),
  ('bm-hop-yqh-1320', 'YQH-1380', 10.15, 6.9, 'pellet', 'Dual', 'United States of America', 'This variety is described as "Clean and bright. With tropical, citrus, and stone fruit." Sensory analysis of the crop picks out aromas of pineapple, guava, lime, white peach, and orange zest.', NULL, NULL, 9.5, 4.5, 32.5, 67.5),
  ('bm-hop-zagrava', 'Zagrava', 5.5, 10.0, 'pellet', 'Dual', 'Ukraine', 'The Zagrava hop has spicy-floral aroma with herbal and fruit notes.', 'Saaz (US), Tettnanger, Lubelski, Spalter Select', NULL, 15.0, 7.5, 26.0, 40.0),
  ('bm-hop-zamba', 'Zamba Blend', 10.0, 5.0, 'pellet', 'Aroma', 'United States of America', 'Complex aroma characterized by juicy tropical fruits (pineapple, mango), stone fruits, candy, and orange tangerine. This hop blend
is named for the overwhelming tropical dance explosion its aroma evokes. ', NULL, NULL, 11.0, 6.5, 30.0, 65.0),
  ('bm-hop-zappa', 'Zappa', 7.5, 8.5, 'pellet', 'Aroma', 'United States of America', 'Zappa hops have spicy aromas with intense notes of tropical fruit (mango, passion fruit), citrus, and pine. Additional descriptors include savory, mint, and Fruity Pebbles. This hop is unlike any other on the market today.', NULL, NULL, 4.5, 8.5, 42.5, 64.5),
  ('bm-hop-zenia', 'Zenia', 12.5, 4.75, 'pellet', 'Dual', 'United States of America', 'Has intense dank and resin, jammy-orange aromas and distinctive lack of onion-garlic flavor. By manipulating the harvest timing and processing practices of CTZ hops, Zenia becomes the intersection between heavy-weight resin and orange marmalade.', NULL, NULL, NULL, NULL, NULL, NULL),
  ('bm-hop-zenith', 'Zenith', 10.0, 3.0, 'pellet', 'Bittering', 'United States of America', 'Zenith hops have pleasing bouquet aromas with hoppy citrus flavors.', 'Yeoman, Northern Brewer (US)', NULL, 19.0, 6.5, 25.0, 52.0),
  ('bm-hop-zeus', 'Zeus', 15.25, 5.25, 'pellet', 'Bittering', 'United States of America', 'Zeus hops have aroma descriptors that include pungent, black pepper, licorice, and curry.', 'Columbus, Tomahawk, Zeus, CTZ, Centennial, Chinook, Galena, Nugget, Millennium', 0.48, 13.5, 8.5, 34.0, 52.5),
  ('bm-hop-zula', 'Zula', 11.0, 5.4, 'pellet', 'Dual', 'Poland', 'Zula was designed as high-alpha variety, but due to “additional aroma compounds” it was sentenced to death by larger breweries. Years later it turned out that those strange aromas are tropical and citrus fruits. This hop is accompanied by short, clean bitterness when used in the early boil.', NULL, NULL, NULL, NULL, 30.0, NULL),
  ('bm-hop-zythos', 'Zythos', 11.25, 5.45, 'pellet', 'Dual', 'United States of America', 'Zythos hops impart distinct tangerine, citrus, floral, pine and grapefruit tones.', 'Amarillo, Cascade, Simcoe', NULL, 18.5, 8.5, 29.5, 40.0);

