-- ── Yeasts ─────────────────────────────────────────────────────────────────────

INSERT INTO yeasts (id, name, type, form, laboratory, product_id, min_temperature_c, max_temperature_c, flocculation, attenuation_pct, min_attenuation_pct, max_attenuation_pct, alcohol_tolerance, flavor_profile, styles, substitutes, species, pof_positive, sta1_positive) VALUES
  ('bm-yeast-gy003-a-touch-of-spice-belgian-ale-gigayeast', 'A TOUCH OF SPICE BELGIAN ALE', 'ale', 'liquid', 'GigaYeast', 'GY003', 20.0, 25.0, 'medium-low', 82.5, 81.0, 84.0, NULL, 'Abbey style yeast from the Belgian Ardennes. Spicy clove like notes and a hint of fruity esters. Medium flocculation means a clearer beer than most Belgian yeast. ', 'Belgian Ale, Dubbel, Belgian Strong, Tripel, Biere De Garde', NULL, NULL, 0, NULL),
  ('bm-yeast-oyl-018-abbey-ale-c-omega-yeast', 'ABBEY ALE C', 'ale', 'liquid', 'Omega Yeast', 'OYL-018', 20.0, 25.6, 'medium-low', 76.0, 74.0, 78.0, '12', 'The Abbey Ale C''s Trappist origin is best coupled with a little monastic patience: a notably low-flocculator, it is highly attenuating, with a fruity profile and lightly perceptible spiciness, as well as often significant banana character.', 'Ales', 'WY1214, WLP500', NULL, 0, NULL),
  ('bm-yeast-wlp530-abbey-ale-yeast-white-labs', 'Abbey Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP530', 18.9, 22.2, 'medium-high', 77.5, 75.0, 80.0, '14', 'This is a traditional Belgian abbey strain that produces cherry, plum and pear esters. Medium flocculationresults in a clear, drinkable beer.', NULL, 'WY3787, B56', NULL, 0, NULL),
  ('bm-yeast-wlp540-abbey-iv-ale-yeast-white-labs', 'Abbey IV Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP540', 18.9, 22.2, 'medium', 78.0, 74.0, 82.0, '14', 'This strain produces balanced fruit aroma and flavor characters.From the Ardennes region of Belgium, this strain produces moderate levels of ester and phenolic characters,', NULL, 'WY1762', NULL, 0, NULL),
  ('bm-yeast-oyl-218-all-the-bretts-omega-yeast', 'ALL THE BRETTS', 'ale', 'liquid', 'Omega Yeast', 'OYL-218', 20.0, 29.4, 'low', 85.0, 85.0, 85.0, '11', 'An evolving blend of many of the Brett strains in the Omega collection. Use this yeast in the secondary and expect high attenuation and a fruity and funky complexity that continues to develop over time.', 'Farmhouse', NULL, 'Brettanomyces', 0, NULL),
  ('bm-yeast-oyl-001-alt-omega-yeast', 'ALT', 'ale', 'liquid', 'Omega Yeast', 'OYL-001', 12.8, 20.0, 'low', 75.0, 73.0, 77.0, '11', 'An enthusiastic top cropper from Düsseldorf. This strain ferments at low
temperatures with a clean, low ester profile. Light fruit emerges at higher
temperatures. Features quick maturation. Yeast stays in suspension. Little to
no diacetyl. Try also Kolsch II (OYL-044) or even West Coast Ale I (OYL-004)', 'Ales', 'WY1007, WLP036', NULL, 0, NULL),
  ('bm-yeast-gy016-altstadt-ale-gigayeast', 'ALTSTADT ALE', 'ale', 'liquid', 'GigaYeast', 'GY016', 12.8, 20.0, 'low', 79.0, 77.0, 81.0, NULL, 'An ale yeast that ferments at cold temperatures and produces a lager like ale style. Used in traditional Alt and Kolsch styles. Leaves a nice, residual maltiness. ', 'Kolsch, California Common, Altbier, Biere De Garde, Cream Ale', NULL, NULL, 0, NULL),
  ('bm-yeast-wlp4637-amalgamation-brett-super-blend-the-yeast-bay', 'Amalgamation - Brett Super Blend', 'ale', 'liquid', 'The Yeast Bay', 'WLP4637', 21.1, 26.7, 'low', 90.0, 85.0, 95.0, '14', 'Amalgamation is the union of our six favorite Brettanomyces isolates from our microbe library. Each isolate produces a unique bouquet of bright and fruity flavors and aromas. The resulting beer will be dry with complex fruit-forward flavor and aroma of berries and citrus, accompanied by some funk on the palate.  ', NULL, NULL, 'Brettanomyces', 0, NULL),
  ('bm-yeast-wlp4641-amalgamation-ii-brett-super-blend-the-yeast-bay', 'Amalgamation II - Brett Super Blend', 'ale', 'liquid', 'The Yeast Bay', 'WLP4641', 21.1, 26.7, 'low', 84.0, 82.0, 86.0, '14', 'Amalgamation II is a blend of 5 Brettanomyces bruxellensis isolates that showcases qualities of each isolate: The balanced funk of the Beersel isolates and TYB184, the SweeTarts™ character of TYB207, and the tropical bouquet of lemon, pineapple, guava, mango and papaya esters contributed by TYB261. ', NULL, NULL, 'Brettanomyces bruxellensis', 0, NULL),
  ('bm-yeast-wy1056-american-ale-wyeast', 'American Ale', 'ale', 'liquid', 'Wyeast', 'WY1056', 15.6, 22.2, 'medium-low', 75.0, 73.0, 77.0, '11', 'Very clean, crisp flavor characteristics with low fruitness and mild ester production. A very versatile yeast for styles that desire dominant malt and hop character. This strain makes a wonderful "House" strain. Mild citrus notes develop with cooler 60-66F (15-19C) fermentations. Normally requires filtration for bright beers.', 'Pale Ales, Amber Ales, IPAs, Brown Ales, Double IPA', 'WLP001,US-05,RVA-101,A07,OYL-004,BRY-97,M44,BBUSA1,GY001', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-american-ale-escarpment-labs', 'American Ale', 'ale', 'liquid', 'Escarpment Labs', NULL, 16.1, 22.2, 'medium', 77.5, 75.0, 80.0, '11', 'Excellent performance, and somewhat lower attenuation than Cali Ale. Suitable for nearly any clean style. Much like Cali Ale, exhibits clean fermentation at a wide temperature range, and accentuates hop character. ', 'Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy1272-american-ale-ii-wyeast', 'American Ale II', 'ale', 'liquid', 'Wyeast', 'WY1272', 15.6, 22.2, 'medium', 74.0, 72.0, 76.0, '10', 'With many of the best qualities that brewers look for when brewing American styles of beer, this strain''s performance is consistent and it makes great beer. This versatile strain is a very good choice for a House strain. Expect a soft, clean profile with hints of nut, and a slightly tart finish. Ferment at warmer temperatures to accentuate hop character with an increased fruitiness. Or, ferment cool for a clean, light citrus character. It attenuates well and is reliably flocculent, producing bright beer without filtration.', 'Blonde Ale, Pale Ale, IPA, Strong Ale, Brown Ale, Porter', 'WLP051, A15', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp060-american-ale-yeast-blend-white-labs', 'American Ale Yeast Blend', 'ale', 'liquid', 'White Labs', 'WLP060', 20.0, 22.2, 'medium', 76.0, 72.0, 80.0, '11', 'This blend of three strains creates a clean and neutral fermentation character. It lends complexity to finishedbeer by exhibiting a crisp, clean lager-like character with accentuated hop flavors and bitterness.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-wlp670-white-labs-american-farmhouse-blend', 'American Farmhouse Blend', 'ale', 'liquid', 'White Labs', 'WLP670', 20.0, 22.2, 'medium', 78.5, 75.0, 82.0, '9', 'Inspired by American brewers crafting semi-traditional Belgian-style ales. Creates a complex flavor profile with a moderate level of sourness. Consists of a traditional farmhouse yeast strain and Brettanomyces.', 'Farmhouse Ale, Sours', NULL, 'Saccharomyces cerevisiae, Brettanomyces', 0, 1),
  ('bm-yeast-wlp320-american-hefeweizen-ale-yeast-white-labs', 'American Hefeweizen Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP320', 18.3, 20.6, 'low', 72.5, 70.0, 75.0, '9', 'This strain ferments much cleaner than it''s hefeweizen strain counterparts. It produces very slight banana and clove notes and has low flocculation, leaving resulting beers with characteristic cloudiness.', 'American Hefeweizen', 'GY020,WY1010,B44', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy2035-american-lager-wyeast', 'American Lager', 'lager', 'liquid', 'Wyeast', 'WY2035', 8.9, 14.4, 'medium', 75.0, 73.0, 77.0, '9', 'A complex and aromatic strain that can be used for a variety of lager beers. This strain is an excellent choice for Pre-Prohibition Lagers, formerly known as Classic American Pilsners.', 'American Lager', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-gy030-american-lager-gigayeast', 'AMERICAN LAGER', 'lager', 'liquid', 'GigaYeast', 'GY030', 8.9, 15.6, 'medium', 81.0, 79.0, 83.0, NULL, 'Think you don''t like American Lager? Think again. This lager yeast is a powerful attenuator that leaves a dry beer with a slightly fruity finish. Awesome. ', 'Lager, Black Lager, Pilsner, Schwarzbier, Imperial Pilsner', NULL, NULL, 0, NULL),
  ('bm-yeast-oyl-103-american-lager-omega-yeast', 'AMERICAN LAGER', 'lager', 'liquid', 'Omega Yeast', 'OYL-103', 8.9, 14.4, 'medium', 75.0, 73.0, 77.0, '9', 'This strain is thought to be from one of the US''s oldest family-owned breweries in Minnesota. More flocculent and complex in flavor than many of its lager peers, including American Pilsner (OYL-102).', 'Lagers', 'WY2035', NULL, 0, NULL),
  ('bm-yeast-wlp840-american-lager-yeast-white-labs', 'American Lager Yeast', 'lager', 'liquid', 'White Labs', 'WLP840', 10.0, 12.8, 'medium', 77.5, 75.0, 80.0, '9', 'This strain makes dry and clean lagers with a light note of apple fruitiness. Sulfur and diacetyl production is minimalmaking this strain easy to work with and fitting for American-style lagers.', NULL, 'WY2007', NULL, 0, NULL),
  ('bm-yeast-oyl-102-american-pilsner-omega-yeast', 'AMERICAN PILSNER', 'lager', 'liquid', 'Omega Yeast', 'OYL-102', 8.9, 13.3, 'medium', 73.0, 71.0, 75.0, '9', 'Thought to be from the most popular beer in America. A mild, neutral, smooth lager strain, dry and clean with good malt and very slight apple characteristics.', 'Lagers', 'WY2007, WLP840', NULL, 0, NULL),
  ('bm-yeast-oyl-002-american-wheat-omega-yeast', 'AMERICAN WHEAT', 'ale', 'liquid', 'Omega Yeast', 'OYL-002', 14.4, 23.3, 'low', 76.0, 74.0, 78.0, '10', 'Energetically top cropping, this powerful fermenter leaves behind a light, tart
and refreshing, crisp character. Fairly clean and lightly dry, it excels particularly
at American styles. The small amount of sulfur produced during fermentation
conditions out.', 'Ales', 'WY1010', NULL, 0, NULL),
  ('bm-yeast-wy1010-american-wheat-wyeast', 'American Wheat', 'ale', 'liquid', 'Wyeast', 'WY1010', 14.4, 23.3, 'low', 76.0, 74.0, 78.0, '10', 'A strong fermenting, true top cropping yeast that produces a dry, slightly tart, crisp beer. Ideal for beers where low ester profile is desirable.', 'American Hefeweizen, Wheat, Cream Ale, Kolsch, Altbier, Lager', 'GY020,WLP320,B44', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-anchorman-ale-escarpment-labs', 'Anchorman Ale', 'ale', 'liquid', 'Escarpment Labs', NULL, 18.3, 20.0, 'high', 77.5, 75.0, 80.0, '14', 'Clean fermentation profile, with slightly faster attenuation and flocculation than Cali Ale Yeast. Suitable for production of clean West Coast style ales.', 'IPA, Pale Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-ardennes-belgian-ale-escarpment-labs', 'Ardennes Belgian Ale', 'ale', 'liquid', 'Escarpment Labs', NULL, 18.3, 24.4, 'medium-high', 76.0, 76.0, 76.0, '14', NULL, NULL, NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-arset-kveik-blend-escarpment-labs', 'Arset Kveik Blend', 'ale', 'liquid', 'Escarpment Labs', NULL, 20.0, 36.7, 'high', 75.0, 75.0, 75.0, '14', 'This kveik yeast was sourced from Jakob Årset, on the farm Årset in Eidsdal, Norway. The overall flavour profile is similar to the Hornindal Kveik Blend, but this blend shows a higher degree of hop biotransformation. This blend also exhibits a broad temperature range (we have heard of sub-15ºC) and tolerates acidic wort quite well.', NULL, NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-bbaur-aurora-bootleg-biology', 'AURORA', 'ale', 'liquid', 'Bootleg Biology', 'BBAUR', 23.9, 36.7, 'medium', 81.0, 76.0, 86.0, '9', 'The perfect yeast for homebrewers with no temperature control! Use AURORA for worry-free fermentations. Just pitch it and ditch it!

AURORA creates pleasant orange and citrus esters that perfectly complement beers like IPAs made with fruit-forward hops.

Easily produce rounded, complex beers at temperatures as high as 98F (37C) without being phenolic or having noticeable off flavors. At the high end of fermentation temperature, beers can finish attenuating in as little as three days!', 'IPA, Pale Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-a04-barbarian-imperial-yeast', 'Barbarian', 'ale', 'liquid', 'Imperial Yeast', 'A04', 16.7, 21.1, 'medium', 73.5, 73.0, 74.0, '10', 'Excellent yeast strain for any hop forward beers. Wonderfully suited for juicy, hazy New England IPAs. Commonly referred to as the conan yeast strain, it''s ready to attack your IPA. Barbarian produces stone fruit esters that work great when paired with citrus hops. Barbarian will give you what you need for an exceptionally balanced IPA, leaving a nice round and full bodied mouthfeel.', 'American Pale Ale, Black IPA, White IPA, Imperial IPA, American Pale Ale, English IPA, Red IPA, Robust Porter, American Stout, Winter Seasonal Beer, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, Cream Ale, American Wheat Beer, Blonde Ale, American Amber Ale, American Brown Ale', 'OYL-052,GY054,WLP4000,WLP095,ECY29,RVA-104,ES-VT,LB-NE', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-a46-bartleby-hornindal-kveik-imperial', 'Bartleby', 'ale', 'liquid', 'Imperial Yeast', 'A46', 20.0, 36.7, 'high', 80.0, 75.0, 85.0, '10', 'Bartleby is a hornindal Kveik strain that is a great choice for anything from a traditional Norwegian farmhouse ale to a hazy IPA. When used on the high end of the temperature range, Bartleby will produce a lot of pineapple, apricot and peach aromas. The ability to run this yeast at higher fermentation temperatures along with its high flocculation properties make it a great strain for fast turnaround times. This strain is not a part of our core availability line up, please call or email for lead time and specifics. ', 'IPA, Pale Ale, Stout, Porter, English Ale', 'OYL-091,GY135,WLP4050,WLP521,ES-HORN', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp510-bastogne-belgian-ale-yeast-white-labs', 'Bastogne Belgian Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP510', 18.9, 22.2, 'medium', 77.0, 74.0, 80.0, '14', 'A high-gravity ale yeast that produces a dry beer with a slightly acidic finish. While fruit forward, this strainis mild on spice-like phenols.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-gy017-bavarian-hefe-gigayeast', 'Bavarian Hefe', 'ale', 'liquid', 'GigaYeast', 'GY017', 17.8, 26.7, 'very-low', 79.0, 77.0, 81.0, '9', 'A Hefeweizen yeast from one of Bavaria''s oldest breweries. Produces the traditional clove and banana flavors associated with the style— especially when fermented warm. ', 'Dunkelweizen, Gose, Hefeweizen, Weizenbock', 'OYL-021,OYL-022,WLP300,WLP380,WY3068,WY3333,G01,WB-06,T-58,M20', 'Saccharomyces cerevisiae ', 0, NULL),
  ('bm-yeast-wy2206-bavarian-lager-wyeast', 'Bavarian Lager', 'lager', 'liquid', 'Wyeast', 'WY2206', 7.8, 14.4, 'medium-high', 75.0, 73.0, 77.0, '9', 'Used by many German breweries to produce rich, full-bodied, malty beers, this strain is a good choice for bocks and doppelbocks. A thorough diacetyl rest is recommended after fermentation is complete.', 'German Pilsner, Munich Dunkel, Lager, Märzen', 'OYL-107,WLP820,WLP830,RVA-303,WY2633,W-34/70,S-23', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-wlp351-bavarian-weizen-ale-yeast-white-labs', 'Bavarian Weizen Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP351', 18.9, 21.1, 'low', 75.0, 73.0, 77.0, '9', 'This is former Yeast Lab W51. It produces a classic German-style wheat beer, with medium to high spicyphenolic overtones reminiscent of cloves.', 'Hefeweizen, Weissbier, Wheat', 'WY3638,OYL-025,WLP351', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy3638-bavarian-wheat-wyeast', 'Bavarian Wheat', 'ale', 'liquid', 'Wyeast', 'WY3638', 17.8, 23.9, 'low', 73.0, 70.0, 76.0, '10', 'A complex alternative to the standard German wheat strain profile. This strain produces apple, pear, and plum esters in addition to the dominant banana character. The esters are complemented nicely by clove and subtle vanilla phenolics. The balance can be manipulated towards ester production through increasing fermentation temperature, increasing the wort density, and decreasing the pitch rate. Over pitching can result in a near complete loss of banana character. Decreasing the ester level will allow a higher clove character to be perceived. Sulfur is commonly produced, but will dissipate with conditioning. This strain is very powdery and will remain in suspension for an extended amount of time following attenuation. This is true top cropping yeast and requires fermentor headspace of 33%.', 'Wheats, Weissbier', 'WLP351,OYL-025', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-m20-bavarian-wheat-mangrove-jack', 'Bavarian Wheat', 'ale', 'dry', 'Mangrove Jack', 'M20', 15.0, 30.0, 'low', 72.5, 70.0, 75.0, '9', 'Deliciously smooth, light golden in colour, full bodied aromas of vanilla and banana and a lingering aftertaste. This yeast produces a silky mouth feel and rich body.', 'Hefeweizen, Kristal Weizen, Dunkel Weizen and more', 'GY107,OYL-021,OYL-022,WLP300,WLP380,WY3068,WY3333,G01,WB-06,T-58', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy3056-bavarian-wheat-blend-wyeast', 'Bavarian Wheat Blend', 'ale', 'liquid', 'Wyeast', 'WY3056', 17.8, 23.3, 'medium', 75.0, 73.0, 77.0, '10', 'This proprietary blend of a top-fermenting neutral ale strain and a Bavarian wheat strain is a great choice when a subtle German style wheat beer is desired. The complex esters and phenolics from the wheat strain are nicely softened and balanced by the neutral ale strain.', 'Weissbier, Wheats', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-025-bavarian-wheat-i-omega-yeast', 'Bavarian Wheat I', 'ale', 'liquid', 'Omega Yeast', 'OYL-025', 18.9, 22.2, 'low', 75.0, 72.0, 78.0, '10', 'A spicier alternative to Hefeweizen Ale I (OYL-021) for the production of
German wheat beers, Bavarian Wheat I imparts a more phenolic profile with
predominant notes of clove and pepper.', 'Hefeweizen, Ales', 'WLP351', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-034-bavarian-wheat-ii-omega-yeast', 'Bavarian Wheat II', 'ale', 'liquid', 'Omega Yeast', 'OYL-034', 17.8, 23.9, 'low', 73.0, 70.0, 76.0, '10', 'A big top cropper and a low flocculator, with banana, light pear, apple/plum,
clove and vanilla. Another great wheat beer option with a more complex aroma
relative to Hefeweizen Ale I (OYL-021). Up the esters with higher temperatures,
wort density and lower pitch rate, or keep muted at lower temperatures to show
clove. Sulfur conditions out.', 'Hefeweizen, Ales', 'WY3638,OYL-025,WLP351', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-114-bayern-lager-omega-yeast', 'BAYERN LAGER', 'lager', 'liquid', 'Omega Yeast', 'OYL-114', 10.6, 16.7, 'medium', 74.0, 72.0, 76.0, '9', 'Thought to come from Munich''s oldest, traditional and vintage-vibed brewery. This clean, crisp, lager strain ferments well at a wide range, has good flocculation, and has both low sulfur and low diacetyl production.', 'Lagers', NULL, NULL, 0, NULL),
  ('bm-yeast-wlp006-bedford-british-ale-yeast', 'Bedford British Ale', 'ale', 'liquid', 'White Labs', 'WLP006', 18.3, 21.1, 'high', 76.0, 72.0, 80.0, '10', 'WLP006 ferments dry and flocculates very well; produces a distinct ester profile. This yeast yields a full mouthfeel, perfect for creating English-style ales, including bitters, pale ales, porters, stouts and browns.

Bedford British yeast from White Labs is a great all-around British strain of ale yeast! Bedford is known to ferment dry, producing beers with less residual sugars than other British and English ale strains. It is also known to be a very highly flocculant strain, leaving beers crystal clear in a short amount of time! Good for about any time of British-style ale, including bitters, browns, pale ales and porters, it can also be used on some American-style ales. This strain produces a unique set of esters that makes for a distinct flavor profile.', 'ESB, Pale Ale, Porter, Stout, Brown Ale', 'S-33', NULL, 0, 0),
  ('bm-yeast-wlp4603-beersel-brettanomyces-blend-the-yeast-bay', 'Beersel Brettanomyces Blend', 'ale', 'liquid', 'The Yeast Bay', 'WLP4603', 21.1, 26.7, 'low', 83.5, 82.0, 85.0, '14', 'This blend combines Brettanomyces bruxellensis strains isolated from a lambic produced in the Beersel area in the Belgian province of Flemish Brabant, and will produce a balanced profile of fruitiness, funkiness and a crisp tartness.', NULL, NULL, 'Brettanomyces bruxellensis', 0, NULL),
  ('bm-yeast-gy014-belgian-abbey-ale-gigayeast', 'BELGIAN ABBEY ALE', 'ale', 'liquid', 'GigaYeast', 'GY014', 17.8, 26.7, 'low', 80.0, 79.0, 81.0, NULL, 'Classic Belgian Ale yeast. Strong attenuation with a fruity nose and virtually no phenolics. The warmer it gets the fruitier it grows. ', 'Belgian Ale, Dubbel, Belgian Strong, Tripel, Biere De Garde, Saison', 'B63, WLP500, WY1214', NULL, 0, NULL),
  ('bm-yeast-wy1214-belgian-abbey-style-ale-wyeast', 'Belgian Abbey Style Ale', 'ale', 'liquid', 'Wyeast', 'WY1214', 20.0, 25.6, 'medium-low', 76.0, 74.0, 78.0, '12', 'A widely used and alcohol tolerant Abbey style yeast that is suitable for a variety of Belgian style ales. This strain produces a nice ester profile as well as slightly spicy alcohol notes. It can be slow to start; however, it attenuates well.', 'Strong Ale, Belgian Tripel, Belgian Ale, Witbier, Oktoberfest, Winter Beers', 'WLP500, B63, GY014, T-58', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy1762-belgian-abbey-style-ale-ii-wyeast', 'Belgian Abbey Style Ale II', 'ale', 'liquid', 'Wyeast', 'WY1762', 22.8, 25.0, 'medium', 75.0, 73.0, 77.0, '12', 'An excellent yeast strain for use in Belgian dark strong ales. This strain has a relatively clean profile which allows a rich malt and distinctive ethanol character to shine. Delicate dried fruit esters can be produced when used at higher fermentation temperatures or in a high gravity wort.', 'Belgian Ales, Barleywine, Wee Heavy, Biere de Garde', 'WLP540', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-m41-belgian-ale-mangrove-jack', 'Belgian Ale', 'ale', 'dry', 'Mangrove Jack', 'M41', 17.8, 27.8, 'medium', 85.0, 82.0, 88.0, NULL, 'Spicy and phenolic, this yeast emulates the intensity and complexity of some of
the best monastic breweries in Belgium, high attenuation and alcohol tolerance
allows you to brew a huge range of Belgian beers. Beers fermented with this yeast exhibit excellent classic Belgian ale flavour, clove hints
with a multitude of fruit esters, alcohol and banana character. ', 'Belgian Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-024-belgian-ale-a-omega-yeast', 'BELGIAN ALE A', 'ale', 'liquid', 'Omega Yeast', 'OYL-024', 18.3, 25.6, 'high', 78.5, 72.0, 85.0, '12', 'As one of the few highly flocculent Belgian ale strains, this strain makes a great Belgian house strain. It is brewery friendly, crops easily and has a well-rounded flavor profile with balanced fruitiness and phenolics. Esters increase with upward temperatures.', 'Ales', 'WY3522, WLP550', NULL, 0, NULL),
  ('bm-yeast-oyl-019-belgian-ale-d-omega-yeast', 'BELGIAN ALE D', 'ale', 'liquid', 'Omega Yeast', 'OYL-019', 17.8, 26.7, 'low', 76.0, 74.0, 78.0, '12', 'This devil of a strain is thought to be from the famous strong golden ale brewer. The bargain is classic sacrifice for pay off: tricky fermentation kinetics for rich flavor profile and aroma complexity. If tempted by this flavorful but low flocculating stop-and-starter, let us know and we can help with a tip or two. Belgian Golden Strong (OYL-056) is a great alternative with a similar flavor profile, but more reliable fermentation performance.', 'Ales', 'WY1388, WLP570', 'Saccharomyces cerevsiae var. diastaticus', 0, 1),
  ('bm-yeast-oyl-049-belgian-ale-dk-omega-yeast', 'BELGIAN ALE DK', 'ale', 'liquid', 'Omega Yeast', 'OYL-049', 19.4, 21.1, 'medium', 76.5, 73.0, 80.0, '10', 'A mild Belgian-charactered ale yeast with light toasty or biscuit-like aromatic maltiness. Can produce a touch of lagery sulfur', 'Ales', 'WLP515', NULL, 0, NULL),
  ('bm-yeast-oyl-046-belgian-ale-o-omega-yeast', 'BELGIAN ALE O', 'ale', 'liquid', 'Omega Yeast', 'OYL-046', 18.9, 22.2, 'medium', 77.0, 74.0, 80.0, '12', 'With balanced fruit and phenolics, this Trappist ale yeast''s clean and dry profile
carries a signature sharp tasting, slightly acidic finish that the thought-to-be
brewery of origin describes as acidulous. Welcomes high gravity. Belgian
profile is toned down compared to Abbey Ale C (OYL-018) and Belgian Ale W
(OYL-028).', 'Ales', 'WLP510', NULL, 0, NULL),
  ('bm-yeast-oyl-020-belgian-ale-r-omega-yeast', 'BELGIAN ALE R', 'ale', 'liquid', 'Omega Yeast', 'OYL-020', 18.3, 23.9, 'medium', 77.5, 73.0, 82.0, '12', 'This has low phenolics for a Belgian strain, with stone fruit and light, floral or rose-like aromas. Sulfur produced dissipates with conditioning. Accentuated flavors and aromas occur at higher temps, and in a high gravity environment.', 'Ales', 'WY1762, WLP540', NULL, 0, NULL),
  ('bm-yeast-oyl-028-belgian-ale-w-omega-yeast', 'BELGIAN ALE W', 'ale', 'liquid', 'Omega Yeast', 'OYL-028', 17.8, 25.6, 'medium', 76.0, 74.0, 78.0, '12', 'An eruptive top cropper displaying nice fruit and rustic phenolics. This reliable Belgian strain is a good flocculator with a wide temperature range. Three famous brewers ferment this on vastly different schedules, showing the varied outcomes available.', 'Ales', 'WY3787, WLP530', NULL, 0, NULL),
  ('bm-yeast-wlp550-belgian-ale-yeast-white-labs', 'Belgian Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP550', 20.0, 25.6, 'medium', 81.5, 78.0, 85.0, '11', 'This very expressive strain produces phenol-forward flavors and aromas reminiscent of clove, allspiceand peppercorns.', NULL, 'WY3522, B45', NULL, 0, NULL),
  ('bm-yeast-wy3522-belgian-ardennes-wyeast', 'Belgian Ardennes', 'ale', 'liquid', 'Wyeast', 'WY3522', 17.2, 24.4, 'high', 74.0, 72.0, 76.0, '12', 'One of the great and versatile strains for the production of classic Belgian style ales. This strain produces a beautiful balance of delicate fruit esters and subtle spicy notes, with neither one dominating. Unlike many other Belgian style strains, this strain is highly flocculent and results in bright beers.', 'Belgian Ales, Belgian Tripel, Belgian IPA', 'WLP550, B45', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy3822-belgian-dark-ale-wyeast', 'Belgian Dark Ale', 'ale', 'liquid', 'Wyeast', 'WY3822', 18.3, 26.7, 'medium', 76.5, 74.0, 79.0, '12', 'This unique Belgian ale yeast is a high acid producer with balanced ester and phenol production allowing a good expression of malt profile, especially the strong flavors of darker malts and sugars. High alcohol tolerance. Spicy, tart, and dry on the palate with a very complex finish.', 'Belgian Ales', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-wlp570-belgian-golden-ale-yeast-white-labs', 'Belgian Golden Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP570', 20.0, 23.9, 'low', 75.5, 73.0, 78.0, '14', 'From East Flanders, this yeast is versatile in that it can produce low to high gravity Belgian beers up to12% ABV. A combination of fruitiness and phenolic characteristics dominate the flavor profile.', 'Belgian Ales', 'WY1388', 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-oyl-056-belgian-golden-strong-omega-yeast', 'BELGIAN GOLDEN STRONG', 'ale', 'liquid', 'Omega Yeast', 'OYL-056', 20.0, 24.4, 'low', 92.5, 90.0, 95.0, '14', 'Perfectly suited for the production of high-gravity Belgian ales where a dry finish is desired. A mellow phenolic character is balanced by an ester profile of pear and light banana, while high levels of glycerol production ensure a round mouthfeel even at very low finishing gravity. Consistently reaches greater than 90 apparent attenuation without sluggishness or stalling.', 'Ales', NULL, 'Saccharomyces cerevsiae var. diastaticus', 0, 1),
  ('bm-yeast-wy3787-belgian-high-gravity-wyeast', 'Belgian High Gravity', 'ale', 'liquid', 'Wyeast', 'WY3787', 17.8, 25.6, 'medium', 76.0, 74.0, 78.0, '11', 'A classic strain for brewing Belgian dubbel or Belgian tripel. This Abbey strain produces a nice balance of complex fruity esters and phenolics, making it desirable for use in other Belgian style ales as well. A flocculent, true top cropping yeast (additional headspace is recommended), that will work over a broad temperature range. This strain makes a great Belgian style house strain.', 'Belgian Ales', 'WLP530, b48', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy3278-belgian-lambic-blend-wyeast', 'Belgian Lambic Blend', 'ale', 'liquid', 'Wyeast', 'WY3278', 17.2, 23.9, 'varies', 75.0, 70.0, 80.0, '11', 'This blend contains yeast and bacteria cultures important to the production of spontaneously fermented beers of the Lambic region. Specific proportions of a Belgian style ale strain, a sherry strain, two Brettanomyces strains, a Lactobacillus culture, and a Pediococcus culture produce the desirable flavor components of these beers as they are brewed in Brussels. Propagation of this culture is not recommended and will result in a change of the proportions of the individual components. This blend will produce a very dry beer due to the super-attenuative nature of the mixed cultures.', 'Lambic, Flanders Red Ale', NULL, 'Saccharomyces cerevisiae, Brettanomyces, Lactobacillus, & Pediococcus', 0, NULL),
  ('bm-yeast-gy007-belgian-mix-gigayeast', 'BELGIAN MIX', 'ale', 'liquid', 'GigaYeast', 'GY007', 18.9, 25.0, 'low', 80.0, 79.0, 81.0, NULL, 'A blend of Belgian Ale yeast combine to create robust attenuation and a complex flavor profile. ', 'Belgian Ale, Dubbel, Belgian Strong, Tripel, Biere De Garde, Saison', NULL, NULL, 0, NULL),
  ('bm-yeast-wy3724-belgian-saison-wyeast', 'Belgian Saison', 'ale', 'liquid', 'Wyeast', 'WY3724', 21.1, 35.0, 'low', 78.0, 76.0, 80.0, '12', 'This strain is the classic farmhouse ale yeast. A traditional yeast that is spicy with complex aromatics, including bubble gum. It is very tart and dry on the palate with a mild fruitiness. Expect a crisp, mildly acidic finish that will benefit from elevated fermentation temperatures. This strain is notorious for a rapid and vigorous start to fermentation, only to stick around 1.035 S.G. Fermentation will finish, given time and warm temperatures. Warm fermentation temperatures, at least 90 °F (32 °C), or the use of a secondary strain can accelerate attenuation.', 'Saison', 'GY027, Lallemand Belle Saison, WLP565', 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-oyl-027-belgian-saison-i-omega-yeast', 'BELGIAN SAISON I', 'ale', 'liquid', 'Omega Yeast', 'OYL-027', 21.1, 35.0, 'low', 78.0, 76.0, 80.0, '12', 'Well regarded as a farmhouse ale strain despite fickle fermentation behavior. It has fruity complexity, good phenolics and a tart and dry finish. It''s better at warm fermentation temperatures, but is still well known to stall around 1.030. Try using an additional strain to aid attenuation, or the more reliable Saisonstein''s Monster (OYL-500), Belgian Saison II (OYL-042) or French Saison (OYL-026).', 'Ales', 'WY3724, WLP565', NULL, 0, NULL),
  ('bm-yeast-wlp565-belgian-saison-i-ale-yeast-white-labs', 'Belgian Saison I Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP565', 20.0, 23.9, 'medium', 70.0, 65.0, 75.0, '9', 'A classic saison strain sourced from the Wallonia region of Belgium. This strain makes a classic saison byproducing flavors and aromas noted as earthy, peppery and spicy.', 'Saison,Dubbel,Trippel', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-oyl-042-belgian-saison-ii-omega-yeast', 'BELGIAN SAISON II', 'ale', 'liquid', 'Omega Yeast', 'OYL-042', 21.1, 28.9, 'medium', 76.5, 74.0, 79.0, '12', 'Thought to originate from a small, sophisticated, Belgian brewer''s spelt saison. It is earthy, spicy, peppery, tart and dry, with tropical fruit and citrus at warm fermentation temperatures. A perfect strain for farmhouse ales and saisons. It favors pitching in the upper 60s or low 70s, and free-rising from there.', 'Ales', 'WY3726', NULL, 0, NULL),
  ('bm-yeast-wlp566-belgian-saison-ii-ale-yeast-white-labs', 'Belgian Saison II Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP566', 20.0, 25.6, 'medium', 81.5, 78.0, 85.0, '9', 'This strain is a moderate phenol producer with clove-like flavor and aromatic notes present in finished beer.Some fruit-forward ester production provides a balance between fruit and spice aroma and flavors.', 'Saison', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-wy3655-belgian-schelde-ale-wyeast', 'Belgian Schelde Ale', 'ale', 'liquid', 'Wyeast', 'WY3655', 16.7, 17.8, 'medium', 75.0, 73.0, 77.0, '11', 'From the East Flanders - Antwerpen region of Belgium, this unique top-fermenting yeast produces complex, classic Belgian aromas and flavors that meld well with premium quality pale and crystal malts. Well-rounded and smooth textures are exhibited with a full bodied malty profile and mouthfeel.', 'Belgian Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-belgian-sour-blend-escarpment-labs', 'Belgian Sour Blend', 'ale', 'liquid', 'Escarpment Labs', NULL, 21.1, 32.2, 'low', 0.0, 0.0, 0.0, '7', 'A blend of 5 Brettanomyces strains isolated from Belgian Lambic beers, alongside 4 strains of Lactobacillus and 2 strains of Pediococcus, for the production of mixed fermentation sour ales. For best results, we recommend using this blend in beer with less than 7 IBUs initially. Subsequent generations can use increasing IBUs. This is supplied at secondary fermentation pitch rates, and is intended to be used in secondary or as a copitch, alongside a primary fermentation strain of your choice.', 'Sours', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy1581-belgian-stout-wyeast', 'Belgian Stout', 'ale', 'liquid', 'Wyeast', 'WY1581', 18.3, 23.9, 'medium', 77.5, 70.0, 85.0, '12', 'A very versatile ale strain from Belgium. Excellent for Belgian stouts and Belgian specialty ales. Ferments to dryness and produces moderate levels of esters without significant phenolic or spicy characteristics.', 'Belgian Ales, Belgian Tripel, Saison', 'B51', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy1388-belgian-strong-ale-wyeast', 'Belgian Strong Ale', 'ale', 'liquid', 'Wyeast', 'WY1388', 17.8, 26.7, 'low', 76.0, 74.0, 78.0, '12', 'The classic choice for brewing golden strong ales. This alcohol tolerant strain will produce a complex ester profile balanced nicely with subtle phenolics. Malt flavors and aromas will remain even with a well attenuated dry, tart finish. This strain is prone to stalling at approximately 1.035; racking or slight aeration will encourage it to finish fermentation.', 'Belgian Tripel, Belgian Style ales', 'WLP570, GY048, M31', 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-wlp545-belgian-strong-ale-yeast-white-labs', 'Belgian Strong Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP545', 18.9, 22.2, 'medium', 81.5, 78.0, 85.0, '14', 'From the Ardennes region of Belgium, this strain produces moderate levels of ester and phenolic characters, described as dried sage and black cracked pepper. High attenuation results in a dry finish ideal for high gravity beer.', 'Christmas Beers,Belgian Ales', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-wy3789-belgian-style-blend-wyeast', 'Belgian Style Blend', 'ale', 'liquid', 'Wyeast', 'WY3789', 20.0, 29.4, 'medium', 77.5, 75.0, 80.0, '12', 'A unique blend of Belgian Saccharomyces and Brettanomyces for emulating Trappist-style beer from the Florenville region in Belgium. Phenolics, mild fruitiness and complex spicy notes develop with increased fermentation temperatures. Subdued but classic "Brett" character.', 'Belgian Ales, Bretts', NULL, 'Saccharomyces cerevisiae, Brettanomyces', 0, NULL),
  ('bm-yeast-gy015-belgian-tripel-gigayeast', 'BELGIAN TRIPEL', 'ale', 'liquid', 'GigaYeast', 'GY015', 18.9, 23.3, 'low', 75.0, 74.0, 76.0, NULL, 'Belgian Ale yeast from the mother of all Tripels. Warm notes with just a hint of spice. Excellent for emphasizing the malty sweet quality prized in certain Belgians. ', 'Belgian Ale, Dubbel, Belgian Strong, Tripel, Biere De Garde, Saison', NULL, NULL, 0, NULL),
  ('bm-yeast-oyl-029-belgian-wheat-omega-yeast', 'Belgian Wheat', 'ale', 'liquid', 'Omega Yeast', 'OYL-029', 17.8, 23.3, 'medium', 74.0, 72.0, 76.0, '12', 'This strain is great for a wheat beer with more ester complexity than Hefeweizen Ale I (OYL-021) and Hefeweizen Ale II (OYL-022). The strain features apple, bubblegum, plum, and a lightly tart and dry finish. It supports malt and hop flavors well.', 'Hefeweizen, Ales', 'WY3942,WLP351,OYL-025', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy3942-belgian-wheat-wyeast', 'Belgian Wheat', 'ale', 'liquid', 'Wyeast', 'WY3942', 17.8, 23.3, 'medium', 74.0, 72.0, 76.0, '12', 'Isolated from a small Belgian brewery, this strain produces beers with moderate esters and minimal phenolics. Apple, bubblegum and plum-like aromas blend nicely with malt and hops. This strain will finish dry with a hint of tartness.', 'Belgian Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-gy028-belgian-wit-gigayeast', 'BELGIAN WIT', 'ale', 'liquid', 'GigaYeast', 'GY028', 17.8, 26.7, 'very-low', 77.5, 76.0, 79.0, NULL, 'Classic Belgian Wit yeast. Produces the tart and spicy flavors of a traditional Wit. This yeast is a strong attenuator that leaves a dry, slightly cloudy beer. ', 'Belgian Witbier, Saison, Belgian Ale', NULL, NULL, 0, NULL),
  ('bm-yeast-m21-belgian-wit-mangrove-jack', 'Belgian Wit', 'ale', 'dry', 'Mangrove Jack', 'M21', 17.8, 25.0, 'medium-low', 72.5, 70.0, 75.0, NULL, 'A traditional, top-fermenting yeast that has a good balance between fruity esters, and warming spice phenolics. The yeast will leave some sweetness, and will drop bright if left long enough. This yeast has a slightly suppressed Belgian character presenting as phenolic and dry,
fruity and very complex character. The mouthfeel is smooth, light, dry and crisp', 'Witbier, Spiced Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp400-belgian-wit-ale-yeast-white-labs', 'Belgian Wit Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP400', 19.4, 23.3, 'medium-low', 76.0, 74.0, 78.0, '9', 'High phenol production contributes an herbal aroma and flavor notes which blends well with herb and fruitadjuncts. Expect a slightly lower resulting pH than English or American ale strains creating a dry beer.', NULL, 'WY3944, M21, B44', NULL, 0, NULL),
  ('bm-yeast-wlp410-belgian-wit-ii-ale-yeast-white-labs', 'Belgian Wit II Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP410', 19.4, 23.3, 'medium-low', 72.5, 70.0, 75.0, '9', 'A fairly clean strain with medium intensity and spice-like phenol production. With up to 75% attenuation, thisstrain produces a residual malt character.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-wy3944-belgian-witbier-wyeast', 'Belgian Witbier', 'ale', 'liquid', 'Wyeast', 'WY3944', 16.7, 23.9, 'medium', 74.0, 72.0, 76.0, '11', 'This versatile witbier yeast strain can be used in a variety of Belgian style ales. This strain produces a complex flavor profile dominated by spicy phenolics with low to moderate ester production. It is a great strain choice when you want a delicate clove profile not to be overshadowed by esters. It will ferment fairly dry with a slightly tart finish that compliments the use of oats, malted and unmalted wheat. This strain is a true top cropping yeast requiring full fermentor headspace of 33%.', 'Belgian Ales', 'WLP400, B44, M21', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp575-belgian-style-ale-yeast-blend-white-labs', 'Belgian-Style Ale Yeast Blend', 'ale', 'liquid', 'White Labs', 'WLP575', 20.0, 23.9, 'medium', 77.0, 74.0, 80.0, '11', 'A blend of two monastery-type yeast strains and one Belgian ale-type yeast. This blend creates a versatileculture which can be used for monastery-style beers or a myriad of American-Belgian style beers.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-wlp568-belgian-style-saison-ale-yeast-blend-white-labs', 'Belgian-Style Saison Ale Yeast Blend', 'ale', 'liquid', 'White Labs', 'WLP568', 21.1, 26.7, 'medium', 75.0, 70.0, 80.0, '9', 'Incorporates Belgian and saison strains to produce pear-like esters backed by spicy, earthy and clove-likeflavors and aromas. Creates harmony and complexity throughout its ester and phenol production.', 'Saison', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-ecy06-berliner-blend-east-coast-yeast', 'Berliner blend', 'ale', 'liquid', 'East Coast Yeast', 'ECY06', NULL, NULL, NULL, 0.0, 0.0, 0.0, NULL, 'Kolsch yeast and Lactobacillus blend.', 'Berliner Weiss', NULL, 'Saccharomyces cerevisiae, Lactobacillus', 0, NULL),
  ('bm-yeast-gb122-berliner-blend-gigayeast', 'BERLINER BLEND', 'ale', 'liquid', 'GigaYeast', 'GB122', 21.1, 26.7, NULL, 89.0, 89.0, 89.0, NULL, 'A blend of neutral ale yeast and lactic acid bacteria. Use directly in a primary to make a crisp, sour beer!', 'Sour Beer, Gose, Berliner Weisse', NULL, NULL, 0, NULL),
  ('bm-yeast-berliner-brett-i-escarpment-labs', 'Berliner Brett I', 'ale', 'liquid', 'Escarpment Labs', NULL, 17.8, 23.9, 'medium', 0.0, 0.0, 0.0, '14', 'We pulled this Brett strain out of a ~40 year old bottle of Hochschule Berliner Weisse. It''s a survivor! This strain of Brettanomyces anomalus works well in traditional style Berliners, and anywhere subtle, refined Brett character is desired. It shows restrained funk, and the fruit profile tends toward citrus and white wine. This strain is sold in secondary pitch rates only. ', 'Sours', NULL, 'Wilds & Sours', 0, NULL),
  ('bm-yeast-wy3191-berliner-weisse-blend-wyeast', 'Berliner Weisse Blend', 'ale', 'liquid', 'Wyeast', 'WY3191', 20.0, 22.2, 'low', 75.0, 73.0, 77.0, '6', 'This blend includes a German ale strain with low ester formation and a dry, crisp finish. The Lactobacillus included produces moderate levels of acidity, and the unique Brettanomyces strain imparts a critical earthy characteristic that is indicative of a true Berliner Weisse. When this blend is used, expect a slow start to fermentation as the yeast and bacteria in the blend is balanced to allow proper acid production. It generally requires 3-6 months of aging to fully develop flavor characteristics. Use this blend with worts containing extremely low hopping rates.', 'Berliner Weiss, Lambic, Flanders Red Ale, Gose', NULL, 'Saccharomyces cerevisiae, Brettanomyces, & Lactobacillus', 0, NULL),
  ('bm-yeast-wy3725-biere-de-garde-wyeast', 'Bière de Garde', 'ale', 'liquid', 'Wyeast', 'WY3725', 21.1, 28.9, 'low', 76.5, 74.0, 79.0, '12', 'Low to moderate ester production with subtle spiciness. Malty and full on the palate with initial sweetness. Finishes dry and slightly tart. Ferments well with no sluggishness.', 'Biere de Garde, Saison, Belgian Ales', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-oyl-039-biere-de-garde-omega-yeast', 'BIERE DE GARDE', 'ale', 'liquid', 'Omega Yeast', 'OYL-039', 21.1, 28.9, 'low', 76.5, 74.0, 79.0, '9', 'Lightly phenolic, fruity, dry, delicately tart and a very low flocculator, this presents much like a saison strain. Try this for Bière de Garde, or a Belgian or French farmhouse ale. In fact, a clean-bodied Bière de Garde can be achieved with any lager strain here at the warm end of its temperature range. For farmhouse, try also French Saison (OYL-026) or Belgian Saison II (OYL-042)', 'Ales, Farmhouse, Bière de Garde, Saison', 'WY3725', 'Saccharomyces cerevsiae var. diastaticus', 0, 1),
  ('bm-yeast-biergarten-lager-escarpment-labs', 'Biergarten Lager', 'lager', 'liquid', 'Escarpment Labs', NULL, 8.9, 12.8, 'medium', 73.0, 73.0, 73.0, '9', 'A lager strain sourced from a venerable Munich brewery, this strain offers low diacetyl production and a crisp flavour profile highly suited for German Pils, Helles, Festbier or other Munich-style lagers. ', 'Lagers', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-m84-bohemian-lager-mangrove-jack', 'Bohemian Lager', 'lager', 'dry', 'Mangrove Jack', 'M84', 10.0, 15.0, 'high', 74.0, 72.0, 76.0, NULL, 'A bottom-fermenting lager yeast characterised by its dry and clean palate typical
of traditional Czech brewing. Produces soft, delicate and well balanced beers.  Hop and malt character will be enhanced and supported by moderate to full body. In wort
with simple malt bills, delicate malt flavours will survive. Beer fermented with this strain
is generally rich and chewy without being heavy at all. Light and delicately balanced
beers call for this strain. Lagering periods as short as 4 weeks may produce acceptable
beer but allowing it to lager for 6-8 weeks, will result in beer that is richer and smoother
with a more refined aroma and flavour.', 'German Pilsners, Porters, American Lagers', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy2124-bohemian-lager-wyeast', 'Bohemian Lager', 'lager', 'liquid', 'Wyeast', 'WY2124', 7.2, 20.0, 'medium-low', 75.0, 73.0, 77.0, '9', 'This Carlsberg type yeast is the most widely used lager strain in the world. This strain produces a distinct malty profile with some ester character and a crisp finish. A versatile strain, that is great to use with lagers or Pilsners for fermentations in the 45-55°F (8-12°C) range. It may also be used for Common beer production with fermentations at 65-68°F (18-20°C). A thorough diacetyl rest is recommended after fermentation is complete.', 'German Pils, Helles, Lager, Munich Dunkel, Marzen, Bock', 'WLP830, L13, W-34/70', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-brett-b-escarpment-labs', 'Brett B', 'ale', 'liquid', 'Escarpment Labs', NULL, 26.7, 26.7, 'low', 76.5, 75.0, 78.0, '11', 'A classic Brettanomyces bruxellensis strain, isolated from a classic abbey beer, which is typically used in secondary fermentations where balanced Brett character (fruit, funk) is desired. ', 'Sours', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-210-brett-blend-1-where-da-funk-omega-yeast', 'BRETT BLEND #1 WHERE DA FUNK?', 'ale', 'liquid', 'Omega Yeast', 'OYL-210', 20.0, 26.7, 'very-low', 83.0, 78.0, 88.0, '11', 'One Brett-famous Colorado brewery strain plus two uniquely funky Sacch strains result in huge tropical fruit aroma (fades a bit during conditioning) with a wide temperature range. Very dry (consider flaked oats for body). Develops mild funk and low acid even with extended aging. Pairs well with fruity aroma hops for a unique pale ale.', 'Farmhouse', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-oyl-211-brett-blend-2-bit-ofunk-omega-yeast', 'BRETT BLEND #2 BIT O''FUNK', 'ale', 'liquid', 'Omega Yeast', 'OYL-211', 20.0, 26.7, 'very-low', 85.0, 85.0, 85.0, '11', 'This blend contains the two Saccharomyces strains from Brett Blend #1 for primary fermentation and is spiked with Brettanomyces Bruxellensis (OYL-202) for development of moderate funk during a secondary fermentation. The bit ‘o funkiness will take extended time (3+ months) to develop.', 'Farmhouse', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-oyl-212-brett-blend-3-bring-on-da-funk-omega-yeast', 'BRETT BLEND #3 BRING ON DA FUNK', 'ale', 'liquid', 'Omega Yeast', 'OYL-212', 20.0, 26.7, 'very-low', 85.0, 85.0, 85.0, '11', 'Two Sacch strains from Brett Blend #1 (OYL-210) spiked with both brux and lambicus, plus two additional Brett isolates from a Brett-famous Colorado brewery, plus two Brett isolates from an intense Belgian source equals a funky, fruity, complex, 8-strain composition. Brett character develops over time (as will acid production if exposed to oxygen)', 'Farmhouse', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-brett-d-escarpment-labs', 'Brett D', 'ale', 'liquid', 'Escarpment Labs', NULL, 22.2, 25.0, 'medium-low', 80.0, 80.0, 80.0, '12', 'This strain of Brettanomyces bruxellensis is noted for very prominent pineapple esters alongside a good dose of funk. It is suitable for primary fermentation of 100% Brett beers or secondary fermentation where some extra fruit and funk is desired. Works great with hops when co-pitched with clean ale strains as well, for faster turnaround of Brett IPAs. ', 'Sour IPA', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-brett-q-escarpment-labs', 'Brett Q', 'ale', 'liquid', 'Escarpment Labs', NULL, 20.0, 25.0, 'medium-low', 80.0, 80.0, 80.0, '14', 'This unique Brettanomyces bruxellensis strain was originally isolated from a barrel-aged sour beer from Quebec. This strain typically completes primary fermentation within one month, and is also suitable for secondary aging of a wide range of beer styles where subtle Brett character is desired. Tasting notes include ripe strawberry, pear, apple, with underlying funk. ', 'Sours', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-tyb261-brettanomyces-bruxellenis-tyb261-the-yeast-bay', 'Brettanomyces Bruxellenis TYB261', 'ale', 'liquid', 'The Yeast Bay', 'TYB261', 22.2, 27.8, 'low', 83.5, 82.0, 85.0, '14', 'This blend combines Brettanomyces bruxellensis strains isolated from a lambic produced in the Beersel area in the Belgian province of Flemish Brabant, and will produce a balanced profile of fruitiness, funkiness and a crisp tartness.', NULL, NULL, 'Brettanomyces bruxellensis', 0, NULL),
  ('bm-yeast-wy5112-wyeast-brettanomyces-bruxellensis', 'Brettanomyces Bruxellensis', 'ale', 'liquid', 'Wyeast', 'WY5112', 15.6, 23.9, 'medium', 96.0, 90.0, 102.0, '12', 'This strain of wild yeast was isolated from brewery cultures in the Brussels region of Belgium. It produces the classic “sweaty horse blanket” character of indigenous beers such as gueuze, lambics and sour browns and may form a pellicle in bottles or casks. The strain is generally used in conjunction with S. cerevisiae, as well as other wild yeast and lactic bacteria. At least 3-6 months aging is generally required for flavor to fully develop.', 'Flanders Red Ale, Gueuze, Lambic', 'WLP650,OYL-202', 'Brettanomyces bruxellensis', 0, NULL),
  ('bm-yeast-oyl-202-brettanomyces-bruxellensis-omega-yeast', 'BRETTANOMYCES BRUXELLENSIS', 'ale', 'liquid', 'Omega Yeast', 'OYL-202', 29.4, 29.4, 'low', 77.5, 70.0, 85.0, '10', 'First classified in 1904, Bretts are crucial in secondary fermentation for Belgian styles, consuming sugars that Sacchs leave behind. Brett Bruxellensis contributes medium Brett intensity with classic barnyard earthiness and a light medicinal quality. See also: Brett Claussenii (OYL-201), Brett Lambicus (OYL-203), and three Funk blends (OYL-210, 211, 212).', 'Farmhouse, Lambic, Flanders Red Ale', 'WY5112,WLP650', 'Brettanomyces Bruxellensis', 0, NULL),
  ('bm-yeast-tyb184-brettanomyces-bruxellensis-strain-tyb184-the-yeast-bay', 'BRETTANOMYCES BRUXELLENSIS - STRAIN TYB184', 'ale', 'liquid', 'The Yeast Bay', 'TYB184', 22.2, 27.8, 'medium-low', 85.0, 82.0, 88.0, '14', 'Isolated from a rustic farmhouse style beer produced in the Northeastern United States, this single strain of Brettanomyces bruxellensis is attenuative, produces a moderate citric acidic-like character and an ester profile of lemon/pineapple, with a restrained funkiness.', 'Farmhouse Ales', NULL, 'Wilds & Sours', 0, NULL),
  ('bm-yeast-tyb207-brettanomyces-bruxellensis-strain-tyb207-the-yeast-bay', 'Brettanomyces Bruxellensis - Strain TYB207', 'ale', 'liquid', 'The Yeast Bay', 'TYB207', 22.2, 27.8, 'medium-low', 81.0, 80.0, 82.0, '14', 'Isolated from a Belgian-inspired brewery in the Northeastern United States, this single strain of Brettanomyces bruxellensis exhibits good attenuation and produces a tart tropical fruit ester profile reminiscent of SweeTarts™. ', NULL, NULL, 'Wilds & Sours', 0, NULL),
  ('bm-yeast-tyb307-brettanomyces-bruxellensis-strain-tyb307-the-yeast-bay', 'Brettanomyces Bruxellensis - Strain TYB307', 'ale', 'liquid', 'The Yeast Bay', 'TYB307', 21.1, 26.7, 'low', 82.0, 80.0, 84.0, '14', 'This isolate is a single strain of Brettanomyces bruxellensis isolated from a California brewery that utilizes an extensive and diverse array of organisms in the production of their wild/sour/funky beers. This strain exhibits a lemony-tartness with hints of hay and mild barnyard funk, and has a crisp and dry finish.  ', NULL, NULL, 'Wilds & Sours', 0, NULL),
  ('bm-yeast-tyb415-brettanomyces-bruxellensis-strain-tyb415-the-yeast-bay', 'Brettanomyces bruxellensis - Strain TYB415', 'ale', 'liquid', 'The Yeast Bay', 'TYB415', 21.1, 26.7, 'low', 84.0, 82.0, 86.0, '14', 'This isolate is a single strain of Brettanomyces bruxellensis hailing from a brewer of all things sour and wild in the Mountain West. This strain exhibits a strong profile of complex tropical fruit that is dominated by pineapple with a noticeable earthiness that adds a unique complexity and depth of character to the beer. This strain will produce a massive, thick krausen. ', NULL, NULL, 'Wilds & Sours', 0, NULL),
  ('bm-yeast-wlp645-brettanomyces-claussenii', 'Brettanomyces Claussenii', 'ale', 'liquid', 'White Labs', 'WLP645', 29.4, 29.4, 'low', 77.5, 70.0, 85.0, '12', 'Originally isolated from strong English stock beer in the early 20th century, this yeast has low-intensity Brettanomyces character and is closely related to Brettanomyces anomalus. This strain produces fruity, pineapple-like aroma with an earthy hay-like background aroma and aroma note. WLP645 Brettanomyces claussenii is POF+, this strain will contribute phenolic characteristics to finished products. ', 'Cider,Lambic,Sour', 'OYL-201', 'Brettanomyces claussenii', 1, NULL),
  ('bm-yeast-oyl-201-brettanomyces-claussenii-omega-yeast', 'BRETTANOMYCES CLAUSSENII', 'ale', 'liquid', 'Omega Yeast', 'OYL-201', 29.4, 29.4, 'low', 77.5, 70.0, 85.0, '10', 'The mildest on the Brett funkiness spectrum, Brett Claussenii presents more of a leathery earthiness and some pineapple—both characteristics that are contributed in large part by the aroma alone. It does its best work as a secondary yeast. See also: Brett Bruxellensis (OYL-202), Brett Lambicus (OYL-203) and three Funk blends (OYL-210, 211, 212)', 'Farmhouse', 'WLP645', 'Brettanomyces claussenii', 0, NULL),
  ('bm-yeast-oyl-203-brettanomyces-lambicus-omega-yeast', 'BRETTANOMYCES LAMBICUS', 'ale', 'liquid', 'Omega Yeast', 'OYL-203', 29.4, 29.4, 'low', 77.5, 70.0, 85.0, '10', 'Dive in deep with horsey, spicy, cherry pie funk in this significant Brett strain— best in secondary pitches. See also: Brett Bruxellensis (OYL-202), Brett Claussenii (OYL-201), three Funk blends (OYL-210, 211, 212), All The Bretts (OYL-218) or our farmhouse blend: C2C Farmhouse (OYL-217).', 'Farmhouse, Lambic, Flanders Red Ales', 'WY5526,WLP653', 'Brettanomyces lambicus', 0, NULL),
  ('bm-yeast-wlp653-brettanomyces-lambicus-white-labs', 'Brettanomyces Lambicus', 'ale', 'liquid', 'White Labs', 'WLP653', 29.4, 29.4, 'low', 77.5, 70.0, 85.0, '12', 'This yeast produces a high intensity of the traditional Brettanomyces characters — horsey, smoky and spicy flavors — in beer. As the name suggests, this strain is found most often in lambic style beers but is also commonly found in Flanders and sour brown ales. WLP653 Brettanomyces lambicus is POF+, this strain will contribute phenolic characteristics to finished products. ', 'Lambic, Flanders Red Ale, Sours', 'OYL-203,WY5526', 'Brettanomyces lambicus', 1, 0),
  ('bm-yeast-wy5526-wyeast-brettanomyces-lambicus', 'Brettanomyces Lambicus', 'ale', 'liquid', 'Wyeast', 'WY5526', 15.6, 23.9, 'medium', 96.0, 90.0, 102.0, '12', 'This is a wild yeast strain isolated from Belgian lambic beers. It produces a pie cherry-like flavor and sourness along with distinct “Brett” character. A pellicle may form in bottles or casks. To produce the classic Belgian character, this strain works best in conjunction with other yeast and lactic bacteria. It generally requires 3-6 months of aging to fully develop flavor characteristics. This Wyeast strain is known by it''s old nomenclature, Brettanomyces lambicus, while rapid PCR analysis confirms that genetically it is Brettanomyces bruxellensis. This strain remains known as B. lambicus because of the name''s historical relevance and unique profile.', 'Lambic,Berliner Weisse, Flanders Red Ale, Gueuze', 'WLP645,OYL-203', 'Brettanomyces bruxellensis', 0, NULL),
  ('bm-yeast-wy1098-british-ale-wyeast', 'British Ale', 'ale', 'liquid', 'Wyeast', 'WY1098', 17.8, 22.2, 'medium', 74.0, 73.0, 75.0, '10', 'This yeast allows malt and hop character to dominate the profile. It ferments dry and crisp, producing well-balanced beers with a clean and neutral finish. Ferments well down to 64°F (18°C).', 'Porters, Brown Ales, English IPAs, Blonde Ales, Scottish Heavy, Barleywines', 'WLP007, S-04, A01, GY031', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-gy011-british-ale-1-gigayeast', 'BRITISH ALE #1', 'ale', 'liquid', 'GigaYeast', 'GY011', 17.8, 25.0, 'high', 77.0, 75.0, 79.0, NULL, 'Versatile house strain from a traditional UK Brewery. Strong attenuation, low esters and excellent flocculation for clear beer. ', 'British Ales, Pale/Amber Ale, Barley Wine, Scotch Ale, Bitter, Stout, India Pale Ale', NULL, NULL, 0, NULL),
  ('bm-yeast-gy031-british-ale-2-gigayeast', 'BRITISH ALE #2', 'ale', 'liquid', 'GigaYeast', 'GY031', 17.8, 23.9, 'high', 81.0, 80.0, 82.0, NULL, 'From one of the oldest and best-known English cask ales. Strong Attenuation and excellent flocculation with slightly more fruity ester production than GY011. ', 'British Ales, Pale/Amber Ale, Barley Wine, Scotch Ale, Bitter, Stout, India Pale Ale', 'S-04, A01, WLP007, WY1098', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-006-british-ale-i-omega-yeast', 'BRITISH ALE I', 'ale', 'liquid', 'Omega Yeast', 'OYL-006', 17.8, 22.2, 'medium-high', 75.0, 70.0, 80.0, '10', 'A productive, brewery friendly, top cropper attributed to a historic London brewery whose lab once hosted Louis Pasteur. It drops fast and clear, and is clean and crisp at low temperatures with heightened esters and a lightly tart, dry finish at upper ranges. Try also British Ale II (OYL-007) for less attenuation and enhanced malts, or British VIII (OYL-016)', 'Ales, British Ales', 'WY1098, WLP007', NULL, 0, NULL),
  ('bm-yeast-oyl-007-british-ale-ii-omega-yeast', 'BRITISH ALE II', 'ale', 'liquid', 'Omega Yeast', 'OYL-007', 17.8, 23.9, 'medium-high', 70.0, 68.0, 72.0, '10', 'Like British Ale I (OYL-006), this English brewery strain is thought to be from the historical London brewery that Louis Pasteur visited. It is a strong fermenter, brewery friendly, flexible, leaves near spotless clarity, and has more fruit-like esters and malt than British Ale I. Select for malt and fruit at higher fermentation temperatures or a clean profile at lower temperatures.', 'Ales, British Ales', 'WY1099', NULL, 0, NULL),
  ('bm-yeast-wy1335-british-ale-ii-wyeast', 'British Ale II', 'ale', 'liquid', 'Wyeast', 'WY1335', 17.2, 23.9, 'high', 74.5, 73.0, 76.0, '10', 'A classic British ale profile with good flocculation and malty flavor characteristics. It will finish crisp, clean and fairly dry.', 'Bitters, Strong Ale, Brown Ale, Porter, Stout, English IPA', 'WLP025', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-008-british-ale-iii-omega-yeast', 'BRITISH ALE III', 'ale', 'liquid', 'Omega Yeast', 'OYL-008', 17.8, 23.3, 'high', 70.5, 67.0, 74.0, '10', 'This is a top cropping, complex and malty strain. A shy starter, it''s slow but steady to ferment and a notorious diacetyl maker. Despite its finicky nature, its noteworthy esters match well with English style ales. It is highly flocculent and clears extremely well without filtration.', 'Ales, British Ales', 'WY1187, WLP005', NULL, 0, NULL),
  ('bm-yeast-oyl-010-british-ale-iv-omega-yeast', 'BRITISH ALE IV', 'ale', 'liquid', 'Omega Yeast', 'OYL-010', 20.6, 24.4, 'medium-low', 72.5, 69.0, 76.0, '10', 'Nuances of apple, clover honey and pear and a light mineral quality for great character presentation in English styles, particularly bitters. Not very flocculent compared to a lot of English strains. Filtration recommended.', 'Ales, British Ales', 'WY1275, WLP023', NULL, 0, NULL),
  ('bm-yeast-oyl-011-british-ale-v-omega-yeast', 'BRITISH ALE V', 'ale', 'liquid', 'Omega Yeast', 'OYL-011', 17.8, 23.3, 'high', 73.0, 71.0, 75.0, '10', 'A good top cropper thought to be from a famous Manchester bitters maker. Its residual sweetness pairs popularly with the signature huge, fruity hop flavor and aroma of the NEIPA. Alternately, try DIPA (OYL-052) for slightly less residual sweetness', 'Ale, British Ales, IPA, Hazy IPA', 'A38,WY1318,RVA-132,ES-FOG,WLP066,GY128,LAL-VERDANT', 'Saccharomyces cerevisiae', 0, 0),
  ('bm-yeast-oyl-013-british-ale-vi-omega-yeast', 'BRITISH ALE VI', 'ale', 'liquid', 'Omega Yeast', 'OYL-013', 17.2, 23.9, 'high', 74.5, 73.0, 76.0, '10', 'British Ale VI sports a classic British character—reserved but witty, with a rather high tolerance for alcohol. Crisp, clean, malty and with a mostly dry finish. A good flocculator.', 'Ales, British Ales', 'WY1335, WLP025', NULL, 0, NULL),
  ('bm-yeast-oyl-014-british-ale-vii-omega-yeast', 'BRITISH ALE VII', 'ale', 'liquid', 'Omega Yeast', 'OYL-014', 17.8, 22.2, 'high', 69.0, 67.0, 71.0, '9', 'A well behaved, reasonably productive flocculator that leaves a clear bodied beer. This strain produces very clean, well balanced ales that are both significantly malty and have esters reminiscent of stone fruit with dry, nutty tones at the back end. Think compatibility with cask ales, for example.', 'Ales, British Ales', 'WY1469', NULL, 0, NULL),
  ('bm-yeast-oyl-016-british-ale-viii-omega-yeast', 'BRITISH ALE VIII', 'ale', 'liquid', 'Omega Yeast', 'OYL-016', 17.8, 22.2, 'very-high', 69.0, 67.0, 71.0, '9', 'A ridiculously thorough flocculator thought to be from a highly regarded English ESB. This strain has unique fruitiness and noticeable finishing sweetness. Drops out quickly and completely. Easy to crop, but needs a diacetyl rest. To enhance the fruit, ferment up at the recommended temperature ceiling.', 'Ales, British Ales', 'WY1968, WLP002', NULL, 0, NULL),
  ('bm-yeast-wlp005-british-ale-yeast-white-labs', 'British Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP005', 18.3, 21.1, 'high', 70.5, 67.0, 74.0, '9', 'Known for its use in malty English beers, this strain will push bready, grainy malt flavors while beinga mild ester producer.', NULL, 'WY1187', NULL, 0, NULL),
  ('bm-yeast-wy1026-british-cask-ale-wyeast', 'British Cask Ale', 'ale', 'liquid', 'Wyeast', 'WY1026', 17.2, 22.2, 'medium-high', 75.5, 74.0, 77.0, '9', 'A great yeast choice for any cask-conditioned British Ale and one that is especially well suited for hoppy bitters, IPAs and Australian ales. Produces a nice malt profile, and finishes crisp and slightly tart. Low to moderate fruit ester producer that clears well without filtration.', 'Bitters, Brown Ales, IPAs, Blonde Ale', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-gigayeast-british-haze-gy128', 'British Haze', 'ale', 'liquid', 'GigaYeast', 'GY128', 18.3, 23.3, 'medium-high', 73.0, 71.0, 75.0, NULL, 'This strain is one of the most widely used yeast strains for New England IPA’s.  A slightly sweet finish and light, fruity flavor provides the perfect canvas for hazy beers as well as traditional, malt-forward ales.  Beers fermented with this strain will finish with a pronounced body and a soft mouthfeel.', 'New England IPA, American IPA, English IPA, Bitter, Brown Ale', 'WY1318,RVA-132,WLP066,OYL-011,A38', 'Saccharomyces cerevisiae', 0, 0),
  ('bm-yeast-brussels-brett-escarpment-labs', 'Brussels Brett', 'ale', 'liquid', 'Escarpment Labs', NULL, 22.2, 25.0, 'medium-low', 80.0, 80.0, 80.0, '12', 'This Brettanomyces bruxellensis strain displays a balanced selection of fruity characteristics, with testers noting plum, red berry, citrus, and red apple, alongside subtle acidity. It is suitable for primary or secondary fermentation, but does shine in secondary with extended aging, where it displays prominent funky flavours.', 'Sours', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp4613-brussels-brettanomyces-blend-the-yeast-bay', 'Brussels Brettanomyces Blend', 'ale', 'liquid', 'The Yeast Bay', 'WLP4613', 21.1, 26.7, 'medium', 85.0, 80.0, 90.0, '14', 'Comprised of two Brettanomyces bruxellensis strains isolated from a unique lambic produced in the Brussels region of Belgium, the isolates in this blend produce a pronounced barnyard funk with mild tartness and fruitiness.', NULL, NULL, 'Brettanomyces bruxellensis', 0, NULL),
  ('bm-yeast-gb001-brussels-bruxellensis-gigayeast', 'BRUSSELS BRUXELLENSIS', 'ale', 'liquid', 'GigaYeast', 'GB001', 20.0, 26.7, 'low', 58.0, 58.0, 58.0, '12', 'Produces classic Brett Barnyard characteristics plus some subtle fruity aroma and moderate acidity. Adds a tart complexity to any beer. Brettanomyces Bruxellensis This yeast is highly attenuative when left for long periods of time but tends to ferment slowly. Typically best used in combination with faster fermenting yeast in the primary or added to the secondary to add complexity while aging.', 'Saison, Brett Beer, Sour Beer', NULL, 'Brettanomyces Bruxellensis', 0, NULL),
  ('bm-yeast-gb156-brux-blend-gigayeast', 'BRUX BLEND', 'ale', 'liquid', 'GigaYeast', 'GB156', 20.0, 26.7, NULL, 79.0, 79.0, 79.0, NULL, 'A blend of Brettanomyces yeast that produces stone fruit esters and a hint of barnyard. Creates a moderate amount of acid that adds a tart complexity to the brew. ', 'Saison, Sour Beer, Lambic', NULL, 'Brettanomyces', 0, NULL),
  ('bm-yeast-wy2000-budvar-lager-wyeast', 'Budvar Lager', 'lager', 'liquid', 'Wyeast', 'WY2000', 8.9, 13.3, 'medium-high', 73.0, 71.0, 75.0, '9', 'The Budvar style strain has a nice malty nose with subtle fruit tones and a rich malt profile on the palate. It finishes malty but dry, well balanced and crisp. Hop character comes through in the finish.', 'Lager, Helles', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-ecy01-bugfarm-east-coast-yeast', 'BugFarm', 'ale', 'liquid', 'East Coast Yeast', 'ECY01', NULL, NULL, NULL, 0.0, 0.0, 0.0, NULL, 'A large complex blend of cultures to emulate sour beers such as lambic style ales. Over time displays a citrus sourness and large barnyard profile. Contains yeast (S. cerevisiae and S. fermentati), several Brettanomyces strains, Lactobacillus and Pediococcus. The BugFarm blend changes every year and can be added at any stage of fermentation.', NULL, NULL, 'S. cerevisae, S. fermentati, Brettanomyces, Lactobacillus, Pediococcus', 0, NULL),
  ('bm-yeast-wlp095-burlington-ale-yeast-white-labs', 'Burlington Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP095', 19.4, 21.1, 'medium', 75.5, 73.0, 78.0, '11', 'Signature strain for a brewery in the Northeast U.S., making it ideal for New England-style IPAs. The estersand body blend with hop flavors and aromas while balancing bitterness.', 'Pale Ale, IPA, Double IPA', 'OYL-052,GY054,WLP4000,A04,ECY29,RVA-104,ES-VT,LB-NE', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp023-burton-ale-yeast-white-labs', 'Burton Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP023', 20.0, 22.8, 'medium', 72.0, 69.0, 75.0, '9', 'This strain is sourced from Burton upon Trent, England which is known for pushing IPAs into the spotlight.It produces a subtle fruity ester profile which can be described as notes of apple, clover honey and pear.', NULL, 'WY1275, WLP023, Lallemand Windsor', NULL, 0, NULL),
  ('bm-yeast-wy1203-burton-ipa-blend-wyeast', 'Burton IPA Blend', 'ale', 'liquid', 'Wyeast', 'WY1203', 17.8, 23.3, 'medium-high', 72.5, 71.0, 74.0, '10', 'The revival of interest in historic and classic English IPA styles calls for a specialized yeast. This blend highlights hop bitterness and aroma while still allowing full expression of authentic water profiles and pale malts. Low to moderate ester level can be manipulated through fermentation temperature and pitching rate. Palate finish is typically neutral to mildly fruity with some maltiness. Good flocculation characteristics make this an excellent candidate for cask conditioning.', 'English IPA, Bitters, Porters, Stouts', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-217-c2c-american-farmhouse-omega-yeast', 'C2C American Farmhouse', 'ale', 'liquid', 'Omega Yeast', 'OYL-217', 20.0, 26.7, 'low', 77.5, 70.0, 85.0, '10', 'A coast to coast blend of one saison strain from a famous Northeast U.S. brewery and one Brett strain from a Northwest U.S. brewery. The blend results in a fast developing fruity and funky farmhouse ale.', 'Farmhouse, Saison', 'WLP670, WY2484', 'Saccharomyces cerevisiae, Brettanomyces ', 0, 1),
  ('bm-yeast-l05-cablecar-imperial-yeast', 'Cablecar', 'lager', 'liquid', 'Imperial Yeast', 'L05', 12.8, 18.3, 'medium-high', 73.0, 71.0, 75.0, '10', 'The classic strain for California Common style beers. Cablecar can produce clean pseudo lagers at ale temperatures but is also willing to work as a traditional lager strain down to the mid-50s. Not just limited to steam beers/California commons, this strain works well in a variety of fermentations, keeping flavor profiles clean and crisp. ', 'California Common, Pre-Prohibition Lager, Bière de Garde, Cream Ale, Blonde Ale, American Lager, American Amber Lager, Helles, Vienna Lager, Schwarzbier, Baltic Porter, Czech Amber Lager, Czech Dark Lager, Mexican Lager', 'M54, WLP810, WY2112', NULL, 0, NULL),
  ('bm-yeast-cali-ale-escarpment-labs', 'Cali Ale', 'ale', 'liquid', 'Escarpment Labs', NULL, 18.3, 22.2, 'medium', 77.5, 75.0, 80.0, '14', 'An exceptionally versatile ale yeast, suitable for nearly any style. Clean fermentation at a wide temperature range, and accentuates hop character. Can be slow to flocculate.', 'Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp001-california-ale-yeast-white-labs', 'California Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP001', 20.0, 22.8, 'medium', 76.5, 73.0, 80.0, '14', 'This is our best-selling yeast, famous for its clean flavors and hardy fermentations. Known for its use in hoppy beers, it accentuates hop flavors and aromas and attenuates well, even for high gravity beers.', 'Pale Ale, IPA, Ales', 'WY1056,US-05,RVA-101,A07,OYL-004,BRY-97,M44,BBUSA1,GY001', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy2112-california-lager-wyeast', 'California Lager', 'lager', 'liquid', 'Wyeast', 'WY2112', 14.4, 20.0, 'high', 69.0, 67.0, 71.0, '9', 'This strain is particularly well suited for producing California Common-style beers. It retains lager characteristics at temperatures up to 65 °F (18 °C) and produces malty, brilliantly clear beers. This strain is not recommended for cold temperature fermentation.', 'California Common, Cream Ale, Porter, Seasonal Beers, Pale Ales', 'WLP810, L05, M54', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-m54-california-lager-mangrove-jack', 'California Lager', 'lager', 'dry', 'Mangrove Jack', 'M54', 17.8, 20.0, 'high', 79.5, 77.0, 82.0, NULL, 'California Lager yeast produces clean and crisp lagers, this yeast is excellent for
producing anything from a hoppy pilsner to a helles, allowing excellent malt and hop
character to be expressed. California Lager yeast produces a clean lager aroma without the associated sulphur, this
yeast is perfect for most kinds of lager.', 'Lagers, California Common', 'L05, WLP810, WY2112', NULL, 0, NULL),
  ('bm-yeast-wlp051-california-v-ale-yeast-white-labs', 'California V Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP051', 18.9, 21.1, 'medium-high', 72.5, 70.0, 75.0, '11', 'This strain is a big ester producer, showcasing notes of cherry and apple. This strain''s characteristic lower attenuation results in a full-bodied malt forward beer.', NULL, 'WY1272', NULL, 0, NULL),
  ('bm-yeast-wy3864-canadian-belgian-ale-wyeast', 'Canadian/Belgian Ale', 'ale', 'liquid', 'Wyeast', 'WY3864', 17.8, 26.7, 'medium', 77.0, 75.0, 79.0, '12', 'This alcohol-tolerant strain produces complex and well-balanced Belgian Abbey-style ales. Banana and fruit esters are complemented nicely with mild levels of phenolics and hints of acidity. Ester levels may be elevated by increasing gravity and fermentation temperatures.', 'Belgian Ales', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-berlin-lager-cellar-science-dry', 'CellarScience Berlin', 'lager', 'liquid', 'CellarScience', NULL, 12.2, 16.7, 'high', 0.0, 0.0, 0.0, NULL, 'Berlin is a popular yeast strain with a Berlin lineage that is famous for producing amazing lagers with soft malt character and balanced esters.', 'lagers', 'WLP820, WY2206, S-23', 'Saccharomyces pastorianus', 0, 0),
  ('bm-yeast-cali-cellar-science-dry', 'CellarScience Cali', 'ale', 'liquid', 'CellarScience', NULL, 15.0, 22.2, 'medium', 77.5, 75.0, 80.0, NULL, 'The classic American ale strain, probably Chico if we had to guess. Famous for its clean, neutral flavor and its ability to be used in any style. It emphasizes malt and hop flavors and attenuates well.', 'Stouts, Ales, Porters', 'WLP001, WY1056, US-05', 'Saccharomyces Cerevisiae', 0, 0),
  ('bm-yeast-cellar-science-english-ale-dry', 'CellarScience English', 'ale', 'liquid', 'CellarScience', NULL, 15.0, 21.1, 'high', 0.0, 0.0, 0.0, NULL, 'A rapid fermenting English ale strain that is loved for its clean flavor, neutral aroma and dry finish. This yeast settles quickly and forms a compact sediment.', 'English Ales', 'WLP007, WY1098, S-04', 'Saccharomyces Cerevisiae', 0, 0),
  ('bm-yeast-german-lager-cellar-science-dry', 'CellarScience German', 'lager', 'liquid', 'CellarScience', NULL, 12.2, 16.7, 'high', 0.0, 0.0, 0.0, NULL, 'The classic lager strain from Weihenstephan Germany that has been used for generations to produce clean, balanced lagers from pilsners to doppelbocks.', 'Bocks, German Ales, Pilsners', 'WLP830, WY2124, W-34/70', 'Saccharomyces pastorianus', 0, 0),
  ('bm-yeast-nectar-cellar-science-dry', 'CellarScience Nectar', 'ale', 'liquid', 'CellarScience', NULL, 17.8, 22.2, 'medium', 0.0, 0.0, 0.0, NULL, 'This is a fun, unique yeast with a UK pedigree that emphasis fresh malt flavor while producing fruity, citrus and floral flavors. Nectar yeast can be direct pitched with great results by sprinkling it onto the surface of the wort in your fermenter.', 'IPA, Pale Ales', NULL, 'Saccharomyces Cerevisiae', 0, 0),
  ('bm-yeast-cerberus-escarpment-labs', 'Cerberus', 'ale', 'liquid', 'Escarpment Labs', NULL, 22.2, 27.8, 'low', 75.0, 70.0, 80.0, '9', 'This enigmatic strain has proven itself in many breweries who use it alone or paired with Vermont Ale to produce fruit-forward, hoppy beers. Produces and enhances tropical fruit flavours. If used alone, we recommend a highly fermentable wort. This strain is non-phenolic, but contains the STA1 gene potentially resulting in diastatic activity. However, we have not typically seen aggressive attenuation with this strain. ', 'IPA, Pale Ale', NULL, 'Saccharomyces cerevisiae', 0, 1),
  ('bm-yeast-wlp1983-charlies-fist-bump-yeast-white-labs', 'Charlie''s Fist Bump Yeast', 'lager', 'liquid', 'White Labs', 'WLP1983', 12.8, 14.4, 'low', 68.0, 66.0, 70.0, '9', 'Licensed from Charlie Papazian, this strain can ferment at both ale and lager temperatures, allowing brewers toproduce diverse beer styles.', NULL, NULL, NULL, 0, 0),
  ('bm-yeast-rva-101-chico-rva-yeast-labs', 'Chico Ale', 'ale', 'liquid', 'RVA Yeast Labs', 'RVA-101', 19.4, 22.8, 'medium', 77.5, 74.0, 81.0, '11', 'This versatile workhorse yeast will produce a clean crisp flavor profile with muted yeast character allowing hops and malt to take center stage.  The American IPA has gained international acclaim and this is the yeast that did it.  ', 'Pale Ale, IPA', 'WY1056,WLP001,US-05,A07,OYL-004,BRY-97,M44,BBUSA1,GY001', 'Saccharomyces cerevisae', 0, NULL),
  ('bm-yeast-rva-131-chiswick-ale-rva-yeast-labs', 'Chiswick Ale', 'ale', 'liquid', 'RVA Yeast Labs', 'RVA-131', 18.3, 21.1, 'very-high', 68.5, 65.0, 72.0, '8', 'This classic English strain from Fuller''s Brewery will produce a very clear beer with some residual sweetness.  ', 'Porter, Stout, Mild Ale, ESB', NULL, 'Saccharomyces cerevisae', 0, NULL),
  ('bm-yeast-a20-citrus-imperial-yeast', 'Citrus', 'ale', 'liquid', 'Imperial Yeast', 'A20', 19.4, 26.7, 'low', 76.0, 74.0, 78.0, '10', 'Wild saccharomyces yeast strain known to produce a huge citrus fruit ester profile. Citrus cranks out orange and lemon aromas along with some tropical fruit. Use this strain at high temps for big ester production. A wild saccharomyces strain, it will get a bit funky without the worries of a brettanomyces strain. Keep an eye on your fermentations, it does like to hit a false terminal and then slowly finish out the rest of fermentation. This strain tests positive for the STA1 gene via PCR analysis and is therefore considered to be Saccharomyces cerevisiae var. diastaticus ', 'Hazy IPA, American Pale Ale, Imperial IPA, Red IPA, White IPA, Red Ale, American Wheat Beer, Black IPA, Robust Porter, American Stout, Winter Seasonal Beer, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, Cream Ale, Blonde Ale', 'A04, A24, A38, A43, WLP644', 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-oyl-041-cl-50-ale-omega-yeast', 'CL-50 ALE', 'ale', 'liquid', 'Omega Yeast', 'OYL-041', 15.6, 21.1, 'low', 75.0, 74.0, 76.0, '10', 'Producing a notably big-body and soft texture, this versatile, well-attenuating strain''s profile is a launch pad for the gamut of malt and hop characteristics. It achieves substantial maltiness without being overly sweet.', 'Pale Ale, Brown Ale, Red Ale, IPA, Stout, Porter, Cream Ale', 'WY1450,WY2450,WLP051,BRY-97,US-05', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-bbusa1-class-c-american-bootleg-biology', 'Classic American', 'ale', 'liquid', 'Bootleg Biology', 'BBUSA1', 18.3, 22.2, 'medium', 75.5, 73.0, 78.0, '11', 'Professional brewers fondly refer to this culture as Chico. This is THE yeast for recreating authentic hop-forward beer styles like American Pale Ales, West Coast IPAs, East Coast IPAs, Brut IPAs, & Black IPAs. Reliably produces no-nonsense Blonde Ales, American Porters and Stouts. Ideal for fermenting quick sours due to its low pH tolerance. Classic American will delightfully emphasize malt character, the stickiness of hops and the refreshing qualities of bitterness. This culture will not make a pillowy beer.', 'American Pale Ales, West Coast IPAs, East Coast IPAs, Brut IPAs, Black IPAs, Stouts', 'WY1056,WLP001,US-05,RVA-101,A07,OYL-004,BRY-97,M44,GY001', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-bbxeng1-classic-english-bootleg-biology', 'Classic English', 'ale', 'liquid', 'Bootleg Biology', 'BBXELG', 16.7, 22.2, 'low', 74.0, 72.0, 76.0, '9', 'Classic English produces soft, juicy, and tropical fruit flavors when fermenting beers made with citrusy hops. This culture has become the de facto standard for making hazy New England-style IPAs in addition to the Classic New England culture. Ideal for fermenting Milkshake IPA, Brut IPA and other IPA sub-styles.

Traditionally used for making ester-drive Porters, Stouts, Pale Ales, Bitters, and most English-style ales.', 'IPA, Pale Ales, Brut IPA, Bitters, Porters, Stouts', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-classic-witbier-escarpment-labs', 'Classic Witbier', 'ale', 'liquid', 'Escarpment Labs', NULL, 18.9, 23.9, 'medium-low', 75.0, 72.0, 78.0, '9', 'A genre-defining Witbier strain, famous for balanced phenol and ester character with slight tartness that emphasizes wheat flavour. ', 'Witbier', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp067-coastal-haze-ale-yeast-blend-white-labs', 'Coastal Haze Ale Yeast Blend', 'ale', 'liquid', 'White Labs', 'WLP067', 20.0, 22.2, 'medium-low', 72.5, 70.0, 75.0, '11', 'This blend of New England-style IPA strains is great for producing beers with a hazy appearance and tropical,fruit-forward esters. Producing dry, yet juicy beers, with mango and pineapple characteristics.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-copenhagen-lager-escarpment-labs', 'Copenhagen Lager', 'lager', 'liquid', 'Escarpment Labs', NULL, 7.8, 12.8, 'medium-low', 74.0, 71.0, 77.0, '11', 'A workhorse lager strain, and a great choice for accentuating hops and/or more mineral-rich water profiles.', 'Lagers', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-wlp850-copenhagen-lager-yeast-white-labs', 'Copenhagen Lager Yeast', 'lager', 'liquid', 'White Labs', 'WLP850', 10.0, 14.4, 'medium', 75.0, 72.0, 78.0, '9', 'This northern European lager strain emphasizes clean and crisp characteristics. Malt flavors tend to be secondary,promoting clean drinkability.', NULL, 'WY2042', NULL, 0, NULL),
  ('bm-yeast-wlp080-cream-ale-yeast-blend-white-labs', 'Cream Ale Yeast Blend', 'ale', 'liquid', 'White Labs', 'WLP080', 18.3, 21.1, 'medium', 77.5, 75.0, 80.0, '11', 'A blend of ale and lager yeast, this strain produces a classic cream ale. The blend produces a pleasing lightfruity note with clean pilsner-like flavors, and slightly subdued hop bitterness.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-wlp802-czech-budejovice-lager-yeast-white-labs', 'Czech Budejovice Lager Yeast', 'lager', 'liquid', 'White Labs', 'WLP802', 10.0, 12.8, 'medium', 77.5, 75.0, 80.0, '9', 'A pilsner lager yeast from southern Czech Republic, this strain produces dry and crisp lagers with low diacetylproduction. This strain will make a dry beer and showcase rounded hop bitterness.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-czech-lager-escarpment-labs', 'Czech Lager', 'lager', 'liquid', 'Escarpment Labs', NULL, 8.9, 12.8, 'medium', 74.0, 74.0, 74.0, '9', 'This traditional Czech Pilsner yeast rewards patience with a clean, crisp profile and accentuates subtleties in selected malt and hops. We recommend cold fermentation and sufficient lagering when using this strain to deliver an authentic flavour.', 'Czech Pilsners', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-wy2278-czech-pils-wyeast', 'Czech Pils', 'lager', 'liquid', 'Wyeast', 'WY2278', 10.0, 14.4, 'medium-high', 72.0, 70.0, 74.0, '9', 'Originating from the home of great Pilsners in the Czech Republic, this classic strain will finish dry and malty. It is the perfect choice for Bohemian-style Pilsners. Sulfur produced during fermentation can be reduced with warmer fermentation temperatures 58 °F (14 °C) and will dissipate with conditioning.', 'Lager, Bock, Munich Dunkel', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-gy002-czech-pilsner-gigayeast', 'CZECH PILSNER', 'lager', 'liquid', 'GigaYeast', 'GY002', 8.9, 12.8, 'medium-high', 77.0, 75.0, 79.0, NULL, 'Bottom fermenting yeast from a world famous pilsner. Finishes dry and leaves a hint of malt flavor. ', 'Pilsners, Lagers', NULL, NULL, 0, NULL),
  ('bm-yeast-oyl-104-danish-lager-omega-yeast', 'DANISH LAGER', 'lager', 'liquid', 'Omega Yeast', 'OYL-104', 7.8, 13.3, 'low', 75.0, 73.0, 77.0, '9', 'A powdery low flocculator, this strain produces a crisp and dry, soft and round profile that''s great for supporting hop flavors. Ferments relatively cool and has low attenuation. Allow for long conditioning to help clear. Good in Dortmund lagers, Munich helles, and American lagers.', 'Lagers', 'WY2042', NULL, 0, NULL),
  ('bm-yeast-wy2042-danish-lager-wyeast', 'Danish Lager', 'lager', 'liquid', 'Wyeast', 'WY2042', 7.8, 13.3, 'low', 75.0, 73.0, 77.0, '9', 'This yeast is a good choice for Dortmund-style lagers. It will ferment crisp and dry with a soft, rounded profile that accentuates hop characteristics.', 'Helles, Lager', 'WLP850', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-wlp4653-dark-belgian-cask-the-yeast-bay', 'Dark Belgian Cask', 'ale', 'liquid', 'The Yeast Bay', 'WLP4653', 20.0, 23.9, 'medium', 82.5, 80.0, 85.0, '14', 'Dark Belgian Cask is a blend a classic Belgian Saccharomyces cerevisiae strain and our Brettanomyces bruxellensis - Strain TYB184. Together these strains produce a dry beer with a vinous quality and a flavor profile of dried dark fruit, plum, leather, and a mild earthy funk and acidity. Both strains in this blend are very alcohol tolerant (10-15%). While this blend is fairly versatile, its complexity truly shines in dark beers. ', NULL, NULL, 'Saccharomyces cerevisiae, Brettanomyces bruxellensis', 0, NULL),
  ('bm-yeast-a10-darkness-imperial-yeast', 'Darkness', 'ale', 'liquid', 'Imperial Yeast', 'A10', 16.7, 22.2, 'medium', 73.0, 71.0, 75.0, '12', 'Brewers love this yeast strain for dark beers. Its high alcohol tolerance make it a go-to for big beers. A beautiful strain for stout, porter, brown, and amber ales. Darkness produces a unique character that matches up perfectly with roasted and caramel malts. This strain is alcohol tolerant, so don''t hesitate to throw high gravity worts its way.', 'Stout, Irish Dry, American Stout, American Barleywine, Black IPA, American Brown Ale, Robust Porter, Winter Seasonal Beer, Imperial Stout, American Strong Ale, Brown Porter, Stout, Sweet, Stout, Oatmeal, Stout, Foreign Extra, Stout, Tropical, British Strong Ale, Wee Heavy, Irish Red Ale, Red IPA, Red Ale, Wheatwine, English Mild, Extra Special Bitter, Bitter, English IPA, Scottish Ale, English Barleywine, Old Ale, American IPA, American Pale Ale, Imperial IPA', 'A31, A07, A15, GY080, WLP004, WY1084', NULL, 0, NULL),
  ('bm-yeast-wy1450-dennys-favorite-50-ale-wyeast', 'Denny''s Favorite 50 Ale', 'ale', 'liquid', 'Wyeast', 'WY1450', 15.6, 21.1, 'low', 75.0, 74.0, 76.0, '10', 'This terrific all-round yeast can be used for almost any beer style, and is a mainstay of one of our local homebrewers, Mr. Denny Conn. It is unique in that it produces a big mouthfeel and accentuates the malt, caramel, or fruit character of a beer without being sweet or under-attenuated.', 'Amber Ale, Barleywine, Pale Ale, Brown Ale, Red Ale, IPA, Stout, Porter, Cream Ale', 'WY2450,OYL-041,WLP051,BRY-97,US-05', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-g03-dieter-imperial-yeast', 'Dieter', 'ale', 'liquid', 'Imperial Yeast', 'G03', 15.6, 20.6, 'medium', 75.0, 73.0, 77.0, '10', 'Traditional Kolsch yeast strain, fairly flocculent and versatile. Dieter is a clean, crisp, traditional German Kolsch strain. A very low ester profile makes this strain perfect for Kolsch, Alt and other light colored delicate beers. Dieter has better flocculation characteristics than most Kolsch strains which allow brewers to produce clean, bright beers in a shorter amount of time.', 'Kolsch, Altbier, Gose, Bière de Garde, American IPA, Cream Ale, American Pale Ale, Berliner Weisse', 'G02, GY021, K-97, WLP029, WY2565', NULL, 0, NULL),
  ('bm-yeast-oyl-052-dipa-ale-omega-yeast', 'DIPA ALE', 'ale', 'liquid', 'Omega Yeast', 'OYL-052', 18.3, 22.2, 'medium-low', 76.0, 72.0, 80.0, '11', 'A strong fermenter popularly referred to as Conan. Its peach, apricot and pineapple notes are steroids for hops, complementing modern fruity hop profiles in particular. A diacetyl rest is suggested if  fermented in the lower temperature range.', 'IPA, Double IPA, Pale Ale', 'GY054,WLP4000,WLP095,A04,ECY29,RVA-104,ES-VT,LB-NE', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-dry-belgian-ale-escarpment-labs', 'Dry Belgian Ale', 'ale', 'liquid', 'Escarpment Labs', NULL, 22.2, 26.1, 'medium-low', 85.0, 85.0, 85.0, '12', 'Obtained from an American producer of Belgian-style beers. This strain exhibits classic dry Belgian flavours, and displays an aggressive primary fermentation. We especially like this strain for Strong Golden, Tripel, and other Belgian-style beers. NOTE: This strain contains the STA1 gene, meaning it is a diastatic yeast. Many industrial yeasts are diastatic, due to the desire for very high attenuation levels. However extra care must be taken to ensure these yeasts do not cross-contaminate non-diastatic yeasts.', 'Ales, Belgian Ales', NULL, 'Saccharomyces cerevisiae', 0, 1),
  ('bm-yeast-wlp4025-dry-belgian-ale-the-yeast-bay', 'Dry Belgian Ale', 'ale', 'liquid', 'The Yeast Bay', 'WLP4025', 20.0, 23.3, 'high', 92.5, 85.0, 100.0, '14', 'Dry Belgian Ale is single strain of STA1+ Saccharomyces cerevisiae isolated from a unique golden strong ale showcasing an ester profile of apple, pear and light citrus fruit with some mild spicy and peppery notes. This strain is highly attenuative and alcohol tolerant. It produces beers with a surprising amount of body without the use of specialty grains or adjuncts. This strain exhibits high diastatic activity.', 'Ales', NULL, 'Saccharomyces cerevisiae', 0, 1),
  ('bm-yeast-wlp007-dry-english-ale-yeast-white-labs', 'Dry English Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP007', 18.3, 21.1, 'medium-high', 75.0, 70.0, 80.0, '11', 'This yeast is known for its high attenuation, achieving 80% even with 10% ABV beers. This eliminatesresidual sweetness, making the yeast well-suited for high gravity ales and clean, well-attenuated beer styles.', NULL, 'WY1098', NULL, 0, NULL),
  ('bm-yeast-a24-dry-hop-imperial-yeast', 'Dry Hop', 'ale', 'liquid', 'Imperial Yeast', 'A24', 17.8, 23.3, 'medium', 76.0, 74.0, 78.0, '10', 'A blend of two highly popular yeast strains, well suited for hop forward beers. Dry Hop is a blend of A20 Citrus and A04 Barbarian. When this blend goes to work on your hoppy beer, the hop aroma blows up. The combination of these strains produces amazing aromas of citrus, peach, and apricot that will accentuate your IPA, pale ale, and any other hop-driven beer. This blend contains a strain that tests positive for the STA1 gene via PCR analysis and is therefore considered to be Saccharomyces cerevisiae var. diastaticus.', 'Hazy IPA, American IPA, American Pale Ale, Imperial IPA, White IPA, Red IPA, Red Ale, Pale Ale, English IPA, Black IPA, Robust Porter, American Stout, Winter Seasonal Beer, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, Cream Ale, American Wheat Beer, Blonde Ale', 'A04, A20, A38', 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-wlp036-dusseldorf-alt-ale-yeast-white-labs', 'Düsseldorf Alt Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP036', 18.3, 20.6, 'medium', 68.5, 65.0, 72.0, '9', 'A traditional altbier-style yeast from Düsseldorf, Germany. This strain keeps the contribution of hopbitterness in the background while promoting sweet malt notes.', NULL, 'WY1007', NULL, 0, NULL),
  ('bm-yeast-oyl-032-east-coast-ale-omega-yeast', 'EAST COAST ALE', 'ale', 'liquid', 'Omega Yeast', 'OYL-032', 20.0, 22.8, 'medium-low', 72.5, 70.0, 75.0, '10', 'Thought to be the famous Bostonian strain. It is suitable for a broad range
of beer styles with an American spin. Using West Coast Ale I (OYL-004) for
comparison, it is a little tart and slightly muting of hop bitterness. Slightly less
flocculent and attenuating, too, but every bit as versatile, carrying an overall
clean and neutral flavor character.', 'Ales', 'WLP008', NULL, 0, NULL),
  ('bm-yeast-wlp008-east-coast-ale-yeast-white-labs', 'East Coast Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP008', 20.0, 22.8, 'medium-low', 72.5, 70.0, 75.0, '9', 'Cleaner and crisper than other haze producing strains, this strain''s attenuation leaves some mouthfeeland residual sweetness which balances hop bitterness.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-white-labs-wlp039-east-midlands-ale-yeast', 'East Midlands Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP039', 18.9, 21.1, 'medium-high', 77.5, 73.0, 82.0, '10', 'East Midlands yeast from White Labs is another British strain with some unique properties. It is a very attenuative strain of British yeast, which leaves beers very dry. It is good to use on British and American style ales when a dry finish is desired. It can produce low to moderate levels of both esters and fusel alcohols, giving beers a slight fruit character, with the beer remaining fairly neutral overall. This strain has been used with great success to produce a wide range of British and American style ales.', 'Pale Ale, Amber, Porter, Stout, English Ales, Red Ale, ESB', 'LB-NOTT', 'Yeast', NULL, 0),
  ('bm-yeast-ebbegarden-kveik-blend-escarpment-labs', 'Ebbegarden Kveik Blend', 'ale', 'liquid', 'Escarpment Labs', NULL, 22.2, 36.7, 'medium', 75.0, 75.0, 75.0, '14', 'This kveik yeast blend from Stordal was sourced from Jens Aage Øvrebust. This blend displays prominent fruity esters, leaning toward tropical guava and mango, lending well to traditional as well as modern aromatic styles like NEIPA. Note that this blend accentuates hop bitterness slightly, so we recommend adjusting wort production to only use hops in the whirlpool and dry hop. Attenuation: 70-80% // Optimum Temp: 22-37ºC // Alcohol tolerance:', NULL, NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp028-edinburgh-scottish-ale-yeast-white-labs', 'Edinburgh Scottish Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP028', 18.3, 21.1, 'medium', 72.5, 70.0, 75.0, '11', 'Produces underlying esters of pear and melon which work well with hop and malt derived notes. Can beneutral at the low end of the fermentation temperature range or provide more esters at the higher range.', NULL, 'WY1728', NULL, 0, NULL),
  ('bm-yeast-m15-empire-ale-mangrove-jack', 'Empire Ale', 'ale', 'dry', 'Mangrove Jack', 'M15', 17.8, 22.2, 'high', 72.5, 70.0, 75.0, NULL, 'A top-fermenting ale yeast suitable for a variety of full bodied ales, with exceptional depth. Ferments with full, rich dark fruit flavors.', 'Scottish Heavy Ales, American Amber Ales, Sweet Stouts', NULL, NULL, 0, NULL),
  ('bm-yeast-english-ale-i-escarpment-labs', 'English Ale I', 'ale', 'liquid', 'Escarpment Labs', NULL, 18.3, 20.6, 'very-high', 67.0, 63.0, 71.0, '9', 'A classic English ale yeast, fermenting and flocculating quickly, leaving residual sugars and accentuating malt character. Suitable for production of most English ale styles. ', 'English Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-english-ale-ii-escarpment-labs', 'English Ale II', 'ale', 'liquid', 'Escarpment Labs', NULL, 18.3, 22.2, 'medium-high', 76.0, 72.0, 80.0, '9', 'Higher attenuation than English Ale I, while still very flocculant. Suited for higher gravity English ales, and also great as a workhorse yeast strain for most English/American beer styles.', 'English Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-english-ale-iii-escarpment-labs', 'English Ale III', 'ale', 'liquid', 'Escarpment Labs', NULL, 18.3, 22.2, 'medium', 76.0, 72.0, 80.0, '9', 'Higher attenuation than English Ale I, while still very flocculant. Suited for higher gravity English ales, and also great as a workhorse yeast strain for most English/American beer styles.', 'English Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp002-english-ale-yeast-white-labs', 'English Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP002', 18.3, 20.0, 'very-high', 66.5, 63.0, 70.0, '9', 'This is a classic ESB strain from one of England''s largest independent breweries. Residual sweetnessaccentuates malt character and mild fruity esters, adding complexity to the flavor and aroma of finished beers.', NULL, 'WY1968', NULL, 0, NULL),
  ('bm-yeast-wy1768-english-special-bitter-wyeast', 'English Special Bitter', 'ale', 'liquid', 'Wyeast', 'WY1768', 17.8, 22.2, 'high', 70.0, 68.0, 72.0, '9', 'A great yeast for malt-predominate ales. Produces light fruit and ethanol aromas along with soft, nutty flavors. Exhibits a mild malt profile with a neutral finish. Bright beers are easily achieved without any filtration. It is similar to our 1968 London ESB Ale but slightly less flocculent.', 'Bitters, English IPA, Pale Ale, Brown Ale, Blonde Ale, Stout', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-090-espe-kveik-omega-yeast', 'ESPE KVEIK', 'ale', 'liquid', 'Omega Yeast', 'OYL-090', 20.0, 36.7, 'medium', 77.5, 75.0, 80.0, '12', 'Originating from the village of Grodås in Norway, Espe offers the unique profile of lychee, pear, and tropical fruit cup. The strain bolsters the sweet aromatics of modern IPAs, but is versatile enough for your flagship pale ale or seasonal brew. Espe is most expressive when fermented at 90°F+ (32°C+), but still reveals its character at lower ale-pitching temperatures.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy2247-european-lager-wyeast', 'European Lager', 'lager', 'liquid', 'Wyeast', 'WY2247', 7.8, 13.3, 'low', 75.0, 73.0, 77.0, '10', 'This strain exhibits a very clean and dry flavor profile often found in aggressively-hopped lagers. Produces mild aromatics and slight sulfur notes typical of classic pilsners. This yeast is a good attenuator resulting in beers with a distinctively crisp finish.', 'German Pils, Lager', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-wy3726-farmhouse-ale-wyeast', 'Farmhouse Ale', 'ale', 'liquid', 'Wyeast', 'WY3726', 21.1, 28.9, 'medium', 76.5, 74.0, 79.0, '12', 'This strain produces complex esters balanced with earthy/spicy notes. Slightly tart and dry with a peppery finish. A perfect strain for farmhouse ales and saisons.', 'Biere de Garde, Saison, Belgian Ales', 'B56', 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-ecy03-farmhouse-brett-east-coast-yeast', 'Farmhouse Brett', 'ale', 'liquid', 'East Coast Yeast', 'ECY03', 25.6, 27.8, NULL, 80.0, 80.0, 80.0, NULL, 'Saison brasserie blend (ECY08) with a pure Brettanomyces isolate from a small but fascinating producer of Saison. Produces a fruity and funky profile with some acidity gradually increasing over time. ', 'Saison', NULL, 'Saccharomyces boulardii', 0, NULL),
  ('bm-yeast-gb121-farmhouse-sour-gigayeast', 'FARMHOUSE SOUR', 'ale', 'liquid', 'GigaYeast', 'GB121', 20.0, 26.7, NULL, 89.0, 89.0, 89.0, NULL, 'A blend of Belgian ale yeast, Brett and lactic acid bacteria- sweet, sour and a little funky.', 'Saison, Sour Beer, Lambic', NULL, 'Brettanomyces & Bacteria', 0, NULL),
  ('bm-yeast-wlp4675-farmhouse-sour-ale-the-yeast-bay', 'Farmhouse Sour Ale', 'ale', 'liquid', 'The Yeast Bay', 'WLP4675', 21.1, 25.6, 'medium-low', 90.0, 80.0, 100.0, '11', 'This blend contains two farmhouse STA1+ Saccharomyces cerevisiae isolates, Lactobacillus brevis, and Lactobacillus delbrueckii. The two Saccharomyces strains will combine to create a delightful ester profile of grapefruit and orange zest accompanied by a mild earthiness and spiciness, while the Lactobacillus strains will produce a balanced acid profile. This blend exhibits high diastatic activity.', 'Sours, Farmhouse Ale', NULL, 'Saccharomyces cerevisiae, Lactobacillus brevis, Lactobacillus delbruecki', 0, 1),
  ('bm-yeast-a07-flagship-imperial-yeast', 'Flagship', 'ale', 'liquid', 'Imperial Yeast', 'A07', 15.6, 22.2, 'medium-low', 75.0, 73.0, 77.0, '12', 'Commonly referred to as chico" this yeast is a craft brewing standard. This strain is the go-to for craft brewers, highly popular- this strain performs well at standard ale temperatures but can be used in the low 60s to produce exceptionally crisp ales. Flocculation is in the middle of the road and will typically require filtration or fining to achieve crystal clear beers. ', 'American IPA, American Pale Ale, American Stout, Stout, Tropical, Cream Ale, American Wheat Beer, Imperial IPA, Blonde Ale, American Amber Ale, American Brown Ale, California Common, Black IPA, Irish Red Ale, Wee Heavy, Hazy IPA, British Strong Ale, Red IPA, English Barleywine, White IPA, Red Ale, Robust Porter, Winter Seasonal Beer, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, Berliner Weisse, Gose, Pale Ale, Stout, Irish Dry, Brown Porter, English IPA, Scottish Ale, Stout, Sweet, Stout, Oatmeal, Old Ale, Stout, Foreign Extra, Bière de Garde', 'WY1056,WLP001,US-05,RVA-101,OYL-004,BRY-97,M44,BBUSA1,GY001', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy3739-flanders-golden-ale-wyeast', 'Flanders Golden Ale', 'ale', 'liquid', 'Wyeast', 'WY3739', 17.8, 26.7, 'medium-low', 76.0, 74.0, 78.0, '12', 'This well-balanced strain from northern Belgium will produce moderate levels of both fruity esters and spicy phenols while finishing dry with a hint of malt. 3739-PC is a robust and versatile strain that performs nicely in a broad range of Belgian styles.', 'Belgian Ales', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-wlp4001-flanders-specialty-ale-the-yeast-bay', 'Flanders Specialty Ale', 'ale', 'liquid', 'The Yeast Bay', 'WLP4001', 20.0, 26.7, 'medium', 80.0, 78.0, 82.0, '14', 'Flanders Specialty Ale is a single strain of Saccharomyces cerevisiae isolated from a fascinating Belgian producer of a wide array of traditional Belgian beer styles. This is a versatile yeast that will ferment fairly dry and produce a balanced flavor and aroma profile laced with a myriad of esters and phenols.', NULL, NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-ecy02-flemish-ale-east-coast-yeast', 'Flemish Ale', 'ale', 'liquid', 'East Coast Yeast', 'ECY02', NULL, NULL, NULL, 0.0, 0.0, 0.0, NULL, 'A unique blend of yeast and bacterial cultures. Produces dry beers with sourness and notes of leather, fruit, and cherry stone. ', 'Sour Ales', NULL, 'S. cerevisae, Brettanomyces, Lactobacillus, Pediococcus', 0, NULL),
  ('bm-yeast-foggy-london-ale-escarpment-labs', 'Foggy London Ale', 'ale', 'liquid', 'Escarpment Labs', 'ES-FOG', 17.8, 22.8, 'medium', 78.0, 73.0, 83.0, '11', 'This yeast strain was originally isolated from a brewery in London. It displays a balanced fruity flavour profile, and accentuates malt and hop flavours. It is especially suited to production of fruity, hazy IPAs.', 'IPA, Pale Ales, Hazy IPAs', 'A38,WY1318,RVA-132,WLP066,OYL-011,GY128,LAL-VERDANT', 'Saccharomyces cerevisiae', 0, 0),
  ('bm-yeast-wy3463-forbidden-fruit-wyeast', 'Forbidden Fruit', 'ale', 'liquid', 'Wyeast', 'WY3463', 17.2, 24.4, 'low', 74.0, 72.0, 76.0, '12', 'A widely-used strain in the production of Witbier and Grand Cru. This yeast will produce spicy phenolics which are balanced nicely by a complex ester profile. The subtle fruit character and dry tart finish will complement wheat malt, orange peel and spice additions typical of Wits.', 'Witbier, White IPA', 'WLP720', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp4051-framgarden-kveik-the-yeast-bay', 'Framgarden Kveik', 'ale', 'liquid', 'The Yeast Bay', 'WLP4051', 26.7, 35.0, 'medium', 80.0, 78.0, 82.0, '14', 'A single strain of Saccharomyces cerevisiae, it was isolated from source material collected from Petter Øvrebust. It exhibits a vibrant bouquet of hull melon and cantaloupe esters across a broad temperature range. This strain is well suited to any hop forward or farmhouse-inspired beers.', NULL, NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp4030-franconian-dark-lager-the-yeast-bay', 'Franconian Dark Lager', 'lager', 'liquid', 'The Yeast Bay', 'WLP4030', 7.8, 10.6, 'medium-low', 76.0, 74.0, 78.0, '11', 'Franconian Dark Lager is a single strain of Saccharomyces pastorianus that hails from the Franconia region of Germany. This yeast exhibits a short lag time and has flavor profile characteristics that complement dark, roasted malts. While the dark malt complementarity makes this yeast a perfect fit for any big malt driven dark lagers, it''s also able to produce crisp light lagers. ', 'Lagers', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy3711-french-saison-wyeast', 'French Saison', 'ale', 'liquid', 'Wyeast', 'WY3711', 18.3, 25.0, 'low', 80.0, 77.0, 83.0, '12', 'A very versatile strain that produces Saison or farmhouse style beers as well as other Belgian style beers that are highly aromatic (estery), peppery, spicy and citrusy. This strain enhances the use of spices and aroma hops, and is extremely attenuative but leaves an unexpected silky and rich mouthfeel. This strain can also be used to re-start stuck fermentations or in high gravity beers.', 'Saison, Witbier, Belgian Ales', 'B64, GY018', 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-oyl-026-french-saison-omega-yeast', 'FRENCH SAISON', 'ale', 'liquid', 'Omega Yeast', 'OYL-026', 18.3, 25.0, 'low', 85.0, 80.0, 90.0, '12', 'This citrusy, lightly phenolic saison strain is so attenuative and reliable in performance that people joke it could ferment a shoe. The French Saison strain results in great body consistency. It is good for any of the characteristically aromatic Belgian styles and is highly compatible with hops and spice aromas.', 'Ales', 'WY3711', NULL, 0, NULL),
  ('bm-yeast-m29-french-saison-ale-mangrove-jack', 'French Saison Ale', 'ale', 'dry', 'Mangrove Jack', 'M29', 26.1, 32.2, 'medium', 87.5, 85.0, 90.0, '14', 'French Saison yeast is an exceptional, highly attenuative top-fermenting ale
yeast, creating distinctive beers with spicy, fruity and peppery notes. Ideal for
fermentation of farmhouse style beer. This is a highly characterful yeast strain that will dominate all but the highest hopping
rates and complex malt bills. Beers fermented with this yeast will tend to be dry in
finish, often with a slight drying acidity and peppery notes, aiding drinkability at
higher alcohol levels. Higher alcohol beers may have an increased ester production and
warming alcohol notes. ', NULL, NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp590-french-saison-ale-yeast-white-labs', 'French Saison Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP590', 20.6, 23.9, 'medium', 76.5, 73.0, 80.0, '9', 'One of our most popular saison strains, it produces flavors and aromas of pear, apple and cracked pepper.This strain is a high attenuator producing a very dry and drinkable finishing beer.', 'Saison', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-fruit-bomb-saison-escarpment-labs', 'Fruit Bomb Saison', 'ale', 'liquid', 'Escarpment Labs', NULL, 22.2, 27.2, 'medium-low', 80.0, 80.0, 80.0, '12', 'This high-character blend contains a Saison strain with balanced ester and spice aromas, an enigmatic Brettanomyces anomala strain with tropical characteristics, and a complex and fruity Brettanomyces bruxellensis strain. Highly suited to aroma hop or fruit-forward farmhouse ales/saisons. NOTE: the Saison yeast in this blend contains the STA1 gene, meaning it is a diastatic yeast. Many Saison yeasts are diastatic, due to the desire for very high attenuation levels. However extra care must be taken to ensure these yeasts do not cross-contaminate non-diastatic yeasts. ', 'Saison', NULL, NULL, 0, 1),
  ('bm-yeast-fruity-witbier-escarpment-labs', 'Fruity Witbier', 'ale', 'liquid', 'Escarpment Labs', NULL, 16.7, 23.9, 'medium-low', 75.5, 71.0, 80.0, '12', 'A Witbier strain which produces lots of complex fruity esters while still prominently displaying classic Witbier character. Medium-low flocculation helps ensure classic Witbier haze. ', 'Witbier', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-bb0022-funk-weapon-1-bootleg-biology', 'Funk Weapon #1', 'ale', 'liquid', 'Bootleg Biology', 'BB0022', 18.3, 23.9, 'low', 87.5, 80.0, 95.0, '9', 'This rare, and commercially unavailable yeast isolate, produces pungent horse blanket and fresh leather aromas. Perfect for breaking out the funk in farmhouse-style beers.Funk Weapon #1 is featured in the Trinity & Epic Brewing collaboration Wild Apple Saison, and Trinity''s Magical Brettanomyces Tour #4.', 'Saison', NULL, 'Brettanomyces bruxellensis', 0, NULL),
  ('bm-yeast-bb0035c-funk-weapon-2-bootleg-biology', 'Funk Weapon #2', 'ale', 'liquid', 'Bootleg Biology', 'BB0035C', 18.3, 23.9, 'medium-low', 87.5, 80.0, 95.0, '9', 'This rare, and commercially unavailable yeast isolate is perfect for 100% Brettanomyces fermentations, especially Brett IPAs. Amplifies citrus and tropical fruit-forward hop flavors and aromas into a punchy ripeness. With extended time under CO2 pressure, pineapple and tropical fruit aromas will be more pronounced. Great for maintaining the nuance of hops in beer with better keeping qualities than a Brewer''s Yeast fermentation.', 'Brett IPA', NULL, 'Brettanomyces bruxellensis', 0, NULL),
  ('bm-yeast-bb0022-funk-weapon-3-bootleg-biology', 'Funk Weapon #3', 'ale', 'liquid', 'Bootleg Biology', 'BB0022', 18.3, 23.9, 'medium', 87.5, 80.0, 95.0, '9', 'Funk Weapon #3 is a versatile culture that creates wildly different flavor and aroma profiles depending on the age of fermentation. Young fermentations produce mild musty funk and ripe tropical fruit, while older and bottle conditioned ferments show off unique flavors and aromas of strawberry, cherry and tropical candy. This commercially unavailable yeast isolate is ideal for 100% Brettanomyces fermentations or as a secondary strain along with a phenolic Brewer''s Yeast culture.', 'Sours, Bretts', NULL, 'Brettanomyces bruxellensis', 0, NULL),
  ('bm-yeast-wlp4627-funktown-pale-ale-the-yeast-bay', 'Funktown Pale Ale', 'ale', 'liquid', 'The Yeast Bay', 'WLP4627', 20.0, 23.3, 'medium-low', 81.5, 78.0, 85.0, '11', 'Funktown Pale Ale is a blend of The Yeast Bay''s Vermont Ale strain and a unique strain of STA1 + Saccharomyces cerevisiae that is well suited for primary fermentation. The combination of citrus, peach, pineapple and mango esters produce a unique flavor and aroma profile that is fruit-forward and complements any hop-forward beer. This blend exhibits low diastatic activity. ', 'Pale Ales', NULL, 'Saccharomyces cerevisiae', 0, 1),
  ('bm-yeast-wy2002-gambrinus-style-lager-wyeast', 'Gambrinus Style Lager', 'lager', 'liquid', 'Wyeast', 'WY2002', 8.9, 13.3, 'medium-high', 73.0, 71.0, 75.0, '9', 'Czech-style lager strain with very mild floral aroma, nice lager character in nose. Malt dominates profile with subtle floral/fruit notes. Full, complex flavor profile with full mouthfeel. Finishes soft and smooth with nice lingering maltiness.', 'Lager, Helles, Czech Lager', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-wy1007-german-ale-wyeast', 'German Ale', 'ale', 'liquid', 'Wyeast', 'WY1007', 12.8, 20.0, 'low', 75.0, 73.0, 77.0, '11', 'A true top cropping yeast with low ester formation and a broad temperature range. Fermentation at higher temperatures may produce mild fruitiness. This powdery strain results in yeast that remains in suspension post fermentation. Beers mature rapidly, even when cold fermentation is used. Low or no detectable diacetyl.', 'Wheat, Berliner Weisse, Altbier, Kolsch, Lagers, Gose', 'WLP036, G02, K-97', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-gy094-german-ale-yeast-gigayeast', 'German Ale Yeast', 'ale', 'liquid', 'GigaYeast', 'GY094', 17.8, 22.2, 'medium', 76.0, 75.0, 77.0, NULL, 'Ale yeast from a traditional Dusseldorf brewery famous for malty, balanced alt-style brews.  ', 'Alt, Sticke, Dopplesticke, malt forward beers', NULL, NULL, 0, NULL),
  ('bm-yeast-oyl-111-german-bock-omega-yeast', 'GERMAN BOCK', 'lager', 'liquid', 'Omega Yeast', 'OYL-111', 8.9, 12.8, 'medium', 73.0, 70.0, 76.0, '10', 'Thought to be from the famous Alpine brewery in Aying, Bavaria. This is a versatile, malty-charactered lager strain that balances malt and hop flavors well. It is superb for bocks, doppelbocks, Oktoberfest lagers, helles and a favorite for American pilsners, too.', 'Lagers', 'WLP833', NULL, 0, NULL),
  ('bm-yeast-wlp833-german-bock-lager-yeast-white-labs', 'German Bock Lager Yeast', 'lager', 'liquid', 'White Labs', 'WLP833', 8.9, 12.8, 'medium', 73.0, 70.0, 76.0, '11', 'From the Alps of southern Bavaria, this yeast produces a beer that is well-balanced between malt and hop character.This yeast is characterized by a malty finish, balanced aroma and great flocculation. It is a strong fermenter which', NULL, 'WY2487', NULL, 0, NULL),
  ('bm-yeast-gy045-german-lager-gigayeast', 'GERMAN LAGER', 'lager', 'liquid', 'GigaYeast', 'GY045', 10.0, 15.6, 'medium-low', 76.0, 74.0, 78.0, NULL, 'Bottom fermenting German yeast used in commercial breweries around the world. Produces a dry, clean beer with a malty finish. ', 'Lagers, Keller Bier, Marzen, Schwarz Bier, Bock, Pilsner', NULL, NULL, 0, NULL),
  ('bm-yeast-oyl-106-german-lager-i-omega-yeast', 'GERMAN LAGER I', 'lager', 'liquid', 'Omega Yeast', 'OYL-106', 7.2, 20.0, 'medium-low', 75.0, 73.0, 77.0, '9', 'Versatile, crisp, malty profile, light esters and a wide fermentation range. This is thought to be the world''s most used lager strain and can produce a convincing lager at ale temperatures. Fermenting in the low temperature range (45-55), it maintains a more crisp profile. Temperatures higher in range (65-68) bring out slightly heightened esters. Rest for diacetyl.', 'Lagers', 'WY2124, WLP830', NULL, 0, NULL),
  ('bm-yeast-oyl-109-german-lager-ii-omega-yeast', 'GERMAN LAGER II', 'lager', 'liquid', 'Omega Yeast', 'OYL-109', 10.0, 12.8, 'medium-high', 72.0, 68.0, 76.0, '9', 'Great for Bavarian styles. A confident fermenter with good attenuation resulting in a smooth, full-bodied, malty finish and balanced aroma. Slight sulfur and low diacetyl.', 'Lagers', 'WY2308, WLP838', NULL, 0, NULL),
  ('bm-yeast-wlp830-german-lager-yeast-white-labs', 'German Lager Yeast', 'lager', 'liquid', 'White Labs', 'WLP830', 10.0, 12.8, 'medium', 76.5, 74.0, 79.0, '9', 'Our most popular lager yeast, this strain is one of the most widely used lager strains in the world. It tends to produce clean and crisp beers with some accentuation of hop characteristics.', 'Märzen, Lager', 'WY2124,OYL-107,WLP820,RVA-303,WY2633,WY2206,W-34/70,S-23', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-wy3333-german-wheat-wyeast', 'German Wheat', 'ale', 'liquid', 'Wyeast', 'WY3333', 17.2, 23.9, 'high', 73.0, 70.0, 76.0, '10', 'A highly flocculent German wheat beer strain that is the perfect choice for use in Kristallweizen. This yeast strain produces a beautiful and delicate balance of banana esters and clove phenolics similar to the popular Wyeast 3068. However, this strain will sediment rapidly, resulting in bright beer without filtration. The balance can be manipulated towards ester production through increasing fermentation temperature, increasing the wort density, and decreasing the pitch rate. Over pitching can result in a near complete loss of banana character. Sulfur is commonly produced, but will dissipate with conditioning.', 'Hefeweizen, Weissbier, Wheats, Bock', 'GY107,OYL-021,OYL-022,WLP300,WLP380,WY3068,G01,WB-06,T-58,M20', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp029-german-kolsch-ale-yeast-white-labs', 'German/Kolsch Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP029', 18.3, 20.6, 'medium', 75.0, 72.0, 78.0, '9', 'Sourced from a small brewpub in Cologne, Germany, this strain is fitting for German ales. Known foraccentuating hop flavor and bitterness while creating crisp, clean lager like characters.', NULL, 'K-97, G03, GY021, WY2565', NULL, 0, NULL),
  ('bm-yeast-gb110-gigayeast-lacto-gigayeast', 'GigaYeast Lacto', 'ale', 'liquid', 'GigaYeast', 'GB110', 20.0, 36.7, 'low', 27.5, 15.0, 40.0, NULL, 'A robust, fast souring lactic acid bacteria. Produces a clean tart flavor.', 'Saison, Sour Beer, Lambic,Berliner Weisse', 'OYL-605,WY5335,WLP672', 'Lactobacillus ', 0, NULL),
  ('bm-yeast-l13-global-imperial-yeast', 'Global', 'lager', 'liquid', 'Imperial Yeast', 'L13', 7.8, 13.3, 'medium-low', 75.0, 73.0, 77.0, '10', 'Wildly popular lager strain, produces a classic lager profile. The world''s most popular lager strain is ready for you. Global is an all-around solid lager strain that produces clean, bright and crispy lager beers with a very low ester profile. This strain is extremely powdery, so long lagering times or filtration is required for bright beer.', 'German Pils, Pre-Prohibition Lager, Dortmunder Export, Helles, Vienna Lager, American Amber Lager, Schwarzbier, Rauchbier, Maibock, Marzen, Doppelbock, Eisbock, American Lager, Czech Pilsner, Czech Amber Lager, Czech Dark Lager, Dunkels, Bock, Baltic Porter, Bière de Garde', 'L17, W-34/70, WLP830, WY2124', NULL, 0, NULL),
  ('bm-yeast-b45-gnome-imperial-yeast', 'Gnome', 'ale', 'liquid', 'Imperial Yeast', 'B45', 18.3, 25.0, 'medium', 76.0, 74.0, 78.0, '12', 'Versatile and unique Belgian ale yeast, excellent choice for Belgian pale ales or IPAs. Gnome is the yeast for brewing Belgian inspired beers in a hurry. This strain is extremely flocculent and drops out of the beer quickly after fermentation. Gnome produces a nice phenolic character that plays nicely with hops, as well as with caramel and toffee malt flavors. Great for Belgian ales that need to be crystal clear without filtration. Highly versatile, use Gnome in an array of Belgian beers. ', 'Belgian IPA, Belgian Pale Ale, Blonde Ale, Trappist Single, Witbier, Bière de Garde, Saison, Belgian Golden Strong Ale, Belgian Dark Strong Ale, Belgian Dubbel, Belgian Tripel, Belgian Quad', 'WLP550, WY3522', NULL, 0, NULL),
  ('bm-yeast-gy005-golden-gate-lager-gigayeast', 'GOLDEN GATE LAGER', 'lager', 'liquid', 'GigaYeast', 'GY005', 12.8, 21.1, 'medium', 81.0, 79.0, 83.0, NULL, 'Versatile Lager yeast used to create the California Common style. Ferments warm and still retains a lager character. ', 'California Common, Cream Ale, Stout', NULL, NULL, 0, NULL),
  ('bm-yeast-gy048-golden-pear-belgian-gigayeast', 'GOLDEN PEAR BELGIAN', 'ale', 'liquid', 'GigaYeast', 'GY048', 18.3, 26.7, 'low', 84.0, 83.0, 85.0, '10', 'From the originator of the Belgian Golden Strong Ale style. Estery profile reminiscent of apple and pear with a subdued level of spicy phenolics. Excellent choice for high gravity belgian and farmhouse style ales. ', 'Belgian Golden Strong Ale, Farmhouse Ale, Tripel, Saison, Dubbel, Biere De Garde', 'WLP570, WY1388', NULL, 0, NULL),
  ('bm-yeast-oyl-023-grand-cru-omega-yeast', 'GRAND CRU', 'ale', 'liquid', 'Omega Yeast', 'OYL-023', 17.2, 24.4, 'low', 74.0, 72.0, 76.0, '12', 'Made for wits or any other Belgian ale—even sweet mead or cider—this strain''s clove phenolics, esters and tart and dry ending was historically enhanced by orange peel and coriander. The well-known Belgian wheat beer was brought back from extinction in its historic home of Hoegaarden by Pierre Celis, from which this strain is thought to come.', 'Ales', 'WY3463, WLP720', NULL, 0, NULL),
  ('bm-yeast-oyl-501-gulo-ale-omega-yeast', 'GULO ALE', 'ale', 'liquid', 'Omega Yeast', 'OYL-501', 20.0, 25.0, 'medium', 87.5, 85.0, 90.0, '12', 'Gulo Ale is the latest creation to emerge from the curious minds of our R&D team. The progeny of Irish Ale (OYL-005) and French Saison (OYL-026), this true genetic hybrid is a beast at devouring sugars, which creates a very dry beer without any of the peppery, clove phenolics associated with saisons and Belgian ales. Expect a citrus-forward aroma with hints of peach and a clean finish. Gulo Ale excels in any style where a high level of attenuation is desired without phenolics. We love using it in an IPA (including a brut IPA), stout, or Bière de Garde. Non-phenolic.', 'Saison, Ales, IPA, Brut IPA, Stout, Bière de Garde', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-l17-harvest-imperial-yeast', 'Harvest', 'lager', 'liquid', 'Imperial Yeast', 'L17', 10.0, 15.6, 'medium', 72.0, 70.0, 74.0, '10', 'Brewers love this lager yeast strain for its versatility; it will impress you with it''s ability to ferment pretty much any lager style you throw at it. This great lager strain combines good flocculation characteristics with low sulfur and low diacetyl. Clean fermentations produce amazing bock, Helles, pilsner, dunkles, and just about any other lager style you throw its way. Fantastic choice for a house lager strain. ', 'Helles, Dunkels, Bock, Vienna Lager, Doppelbock, German Pils, Pre-Prohibition Lager, Schwarzbier, Rauchbier, Dortmunder Export, Maibock, Marzen, American Amber Lager, Eisbock, American Lager, Czech Pilsner, Czech Amber Lager, Czech Dark Lager, Mexican Lager, Baltic Porter, Bière de Garde', 'L13, L28, WLP6860, WY2352', NULL, 0, NULL),
  ('bm-yeast-wlp4042-hazy-daze-the-yeast-bay', 'Hazy Daze', 'ale', 'liquid', 'The Yeast Bay', 'WLP4042', 17.8, 21.1, 'medium-low', 81.0, 79.0, 83.0, '11', 'Hazy Daze contains a proprietary blend of three Saccharomyces cerevisiae strains, all of which offer unique contributions to the production of crisp, hop forward beers. Expect this blend to throw bountiful amounts of peach, apricot, nectarine and grapefruit citrus esters and achieve good attenuation. ', 'IPA, Hazy IPA, Pale Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp4044-hazy-daze-ii-the-yeast-bay', 'Hazy Daze II', 'ale', 'liquid', 'The Yeast Bay', 'WLP4044', 18.9, 22.2, 'medium-low', 83.0, 81.0, 85.0, '11', 'Hazy Daze II is a proprietary blend of three Saccharomyces cerevisiae strains and one STA1+ Saccharomyces cerevisiae strain. It will exhibit an strong ester profile of stone fruit (peach, apricot, nectarine and), tropical fruit (mango, guava) and grapefruit citrus esters. It ferments faster and finishes slightly drier compared to our Hazy Daze. This blend exhibits low diastatic activity.', 'IPA, Hazy IPA, Pale Ales', NULL, 'Saccharomyces cerevisiae var. dia', 0, 1),
  ('bm-yeast-oyl-021-hefeweizen-ale-i-omega-yeast', 'Hefeweizen Ale I', 'ale', 'liquid', 'Omega Yeast', 'OYL-021', 17.8, 23.9, 'low', 75.0, 73.0, 77.0, '10', 'A classic German wheat strain, it''s a cloudy, big top cropper. Presenting banana
and clove, the esters turn up with increased temperatures, wort density and
decreased pitch rate, or stay muted at lower temperatures where clove stands
out. Over pitching can lessen the banana. Sulfur conditions out. See also
Belgian Ale A (OYL-024) for an alternate complexity.', 'Hefeweizen, Ales', 'GY107,OYL-022,WLP300,WLP380,WY3068,WY3333,G01,WB-06,T-58,M20', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-022-hefeweizen-ale-ii-omega-yeast', 'Hefeweizen Ale II', 'ale', 'liquid', 'Omega Yeast', 'OYL-022', 17.2, 23.9, 'high', 73.0, 70.0, 76.0, '10', 'Identical to Hefeweizen Ale I (OYL-021) except flocculent, Hefeweizen Ale II produces a crystal clear body with no additional steps and is a big top cropper. Up esters with upper fermentation temperatures, wort density and decreased pitch rate, or keep esters muted to let clove show. Turn down banana by over pitching. Sulfur conditions out.', 'Hefeweizen, Ales', 'WY3333, WLP380', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp300-hefeweizen-ale-yeast-white-labs', 'Hefeweizen Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP300', 20.0, 22.2, 'low', 74.0, 72.0, 76.0, '9', 'This popular German strain produces a high level of isoamyl acetate, giving the resulting beer notes of banana. With balanced phenol production, this strain produces notes of clove but remains banana forward.', 'Hefeweizen, Weissbier, Weizenbock, Roggenbier', 'WY3068', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp380-hefeweizen-iv-ale-yeast-white-labs', 'Hefeweizen IV Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP380', 18.9, 21.1, 'low', 76.5, 73.0, 80.0, '9', 'Produces clove-like phenols in the aroma and flavor while keeping banana flavors and aromas to a minimum. Creates refreshing citrus and apricot notes. This strain has low flocculation and minor sulfur production.', 'Hefeweizen, Weissbier, Weizenbock, Roggenbier', 'GY107,OYL-021,OYL-022,WLP300,WY3068,WY3333,G01,WB-06,T-58,M20', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy2487-hella-bock-lager-wyeast', 'Hella Bock Lager', 'lager', 'liquid', 'Wyeast', 'WY2487', 8.9, 13.3, 'medium', 72.0, 70.0, 74.0, '12', 'Direct from the Austrian Alps, this strain will produce rich, full-bodied and malty beers with a complex flavor profile and a great mouth feel. Attenuates well while still leaving plenty of malt character and body. Beers fermented with this strain will benefit from a temperature rise for a diacetyl rest at the end of primary fermentation.', 'Helles, Marzen, Munich Dunkel, Bock', 'WLP833, ', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-wlp4035-hessian-pils-the-yeast-bay', 'Hessian Pils', 'lager', 'liquid', 'The Yeast Bay', 'WLP4035', 7.2, 8.9, 'medium', 74.5, 73.0, 76.0, '7', 'Hessian Pils is a single strain of Saccharomyces pastorianus that hails from the Hess region of Germany. It exhibits everything you want in a great Pilsner yeast: it''s a clean fermenter with low ester formation, exhibits a short lag time, ferments wort quickly and attenuates well even at the low end of the temperature range. These characteristics allow the malt and hop profile to really shine, and creates a crisp finished beer. ', 'Pilsners, Lagers', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp925-high-pressure-lager-yeast-white-labs', 'High Pressure Lager Yeast', 'lager', 'liquid', 'White Labs', 'WLP925', 16.7, 20.0, 'medium', 77.5, 73.0, 82.0, '9', 'Used to ferment lager beer in one week. Ferment at room temperature; 62-68°F (17-20°C) under 1.0 bar (14.7 PSI)until final gravity is obtained, lager the beer at 35°F (2°C), 15 PSI, for 3-5 days to condition. Malt-forward and clean.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-rva-104-hoptopper-ale-rva-yeast-labs', 'Hoptopper Ale', 'ale', 'liquid', 'RVA Yeast Labs', 'RVA-104', 17.8, 24.4, 'medium-low', 77.5, 75.0, 80.0, '11', 'Isolated from a very well regarded example of a Double IPA, this strain will produce fruity esters which serve well to complement a heavy hop load.  Great for a variety of pale ales and bitters.', 'IPA, Double IPA, Pale Ale, Bitters', 'OYL-052,GY054,WLP4000,WLP095,A04,ECY29,ES-VT,LB-NE', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp4050-hornindal-kveik-the-yeast-bay', 'Hornindal Kveik', 'ale', 'liquid', 'The Yeast Bay', 'WLP4050', 26.7, 35.0, 'medium-low', 79.0, 77.0, 81.0, '14', 'A truly unique strain of Saccharomyces cerevisiae isolated from source material collected on Terje Raftevold’s farmstead. It exhibits a beautiful bouquet of stone fruit and tropical esters across a broad temperature range and can be used across a broad spectrum of styles, and is well suited to any hop forward beer.', 'IPA, Pale Ale, Stout, Porter, English Ale', 'OYL-091,GY135,WLP521,ES-HORN,A46', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp521-hornindal-kveik-white-labs', 'Hornindal Kveik', 'ale', 'liquid', 'White Labs', 'WLP521', 22.2, 36.7, 'high', 78.5, 75.0, 82.0, '15', 'Hornindal is a Kveik strain shared with the world by Terje Raftevold from Hornindal, Norway. It produces an intense tropical flavor and aroma with notes of fresh tangerine, mango, and pineapple, ideal to be used with fruit-forward hops.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', 'OYL-091,GY135,WLP4050,ES-HORN,A46', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-091-hornindal-kveik-omega-yeast', 'Hornindal Kveik', 'ale', 'liquid', 'Omega Yeast', 'OYL-091', 22.2, 36.7, 'high', 78.5, 75.0, 82.0, '16', 'A wonderfully unique Norwegian farmstead kveik, Hornindal produces a tropical flavor and complex aroma that can present itself as stonefruit, pineapple, and dried fruit leather, which complement fruit-forward hops. Add even more dimension to C hops and increase ester intensity with a high fermentation temperature. Ferments well at 90°F+. Non-phenolic and no fusels, even at higher temperatures.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', 'GY135,WLP4050,WLP521,ES-HORN,A46', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-gy135-hornindal-kveik-5-gigayeast', 'Hornindal Kveik #5', 'ale', 'liquid', 'GigaYeast', 'GY135', 21.1, 37.8, 'medium-high', 73.5, 72.0, 75.0, '16', 'A traditional Norwegian Kveik yeast that can be fermented at 85-100 F for fast fermentation and no off flavors. Subtle notes of tropical fruit make this yeast an excellent choice for clean hop-forward IPAs and Pale Ales.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', 'OYL-091,WLP4050,WLP521,ES-HORN,A46', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-hornindal-kveik-blend-escarpment-labs', 'Hornindal Kveik Blend', 'ale', 'liquid', 'Escarpment Labs', 'ES-HORN', 15.0, 35.0, 'medium-high', 75.0, 70.0, 80.0, '14', 'This is a selection of two of our favourite strains from Terje Raftevold''s Hornindal Kveik. The blend shows mixed fruity character. We recommend highly fermentable wort and yeast nutrients to ensure complete attenuation. Highly flocculant but will produce haze in hoppy beers. This versatile yeast can be pitched cooler to yield a more neutral, lager-like profile as well.', 'IPA, Pale Ales, Hazy IPAs', 'WLP521, GY135, OYL-091, WLP4050', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-057-hothead-ale-omega-yeast', 'HOTHEAD ALE', 'ale', 'liquid', 'Omega Yeast', 'OYL-057', 22.2, 36.7, 'medium-high', 80.0, 75.0, 85.0, '11', 'A highly flocculent Norwegian ale strain with an astoundingly wide temperature range and little change in flavor across the range. Clean enough for both American and English styles, it has a unique honey-like aroma with overripe mango. Complementary to modern, fruity hops. Temperature control is unnecessary with this strain. Non-phenolic and no fusels, even at higher temperatures', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-a01-house-imperial-yeast', 'House', 'ale', 'liquid', 'Imperial Yeast', 'A01', 16.7, 21.1, 'high', 74.0, 73.0, 75.0, '10', 'Extremely versatile English ale strain, allowing both malt and hops to shine. The best of both worlds, House is clean and allows malt and hops to shine. This strain is extremely versatile and flocculent enough to drop out of the beer quickly. Best strain choice for any and all English inspired recipes however, does extremely well in hopped up American styles too. House is clean at cold temperatures with increased esters as fermentation temperatures rise.', 'English IPA, Extra Special Bitter, Pale Ale, English Mild, Bitter, Stout, Sweet, Brown Porter, Irish Red Ale, Stout, Oatmeal, Stout, Tropical, British Strong Ale, English Barleywine, Old Ale, Stout, Foreign Extra, American IPA, Black IPA, American Pale Ale, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, Imperial IPA, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, Stout, Irish Dry, Scottish Ale, Wee Heavy, Cream Ale, American Wheat Beer, Blonde Ale, American Amber Ale, American Brown Ale, Hazy IPA, White IPA, California Common', 'A07, GY031, WLP007, WY1098, S-04', NULL, 0, NULL),
  ('bm-yeast-a15-independence-imperial-yeast', 'Independence', 'ale', 'liquid', 'Imperial Yeast', 'A15', 15.6, 22.2, 'medium', 74.0, 72.0, 76.0, '12', 'American ale yeast strain, slightly ester forward and loves to play with hops. Independence is the strain for bringing some new character into your hop-driven beers. Higher in esters than Flagship, this yeast will give some fruit character that will take your hoppy beers to a new level. While it shines in pale ales and IPAs, Independence is a great all-around strain and will also work well in stouts and English ales.', 'American IPA, American Pale Ale, Blonde Ale, Stout, Sweet, Stout, Oatmeal, Cream Ale, California Common, American Amber Ale, American Brown Ale, Black IPA, Hazy IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, Imperial IPA, American Barleywine, Irish Red Ale, Imperial Stout, American Strong Ale, Wheatwine, English Mild, Extra Special Bitter, Bitter, Pale Ale, Stout, Irish Dry, Brown Porter, English IPA, Scottish Ale, Stout, Tropical, British Strong Ale, English Barleywine, Old Ale, Stout, Foreign Extra, Wee Heavy, American Wheat Beer, White IPA', 'A07, A01', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-irish-ale-escarpment-labs', 'Irish Ale', 'ale', 'liquid', 'Escarpment Labs', NULL, 17.8, 21.7, 'medium-high', 72.5, 70.0, 75.0, '9', 'Irish ale yeast from a classic brewery, producing slight fruitiness and caramel notes. Great for Irish stouts, porters, red ales, and pale ales.', 'Stouts, Pale Ales, Porters', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-005-irish-ale-omega-yeast', 'IRISH ALE', 'ale', 'liquid', 'Omega Yeast', 'OYL-005', 16.7, 22.2, 'medium', 72.0, 69.0, 75.0, '12', 'Ireland''s storied stout is thought to be balanced by this dry, crisp, lightly fruity, versatile and powerful strain. A good fermenter with reliable, average flocculation (some diacetyl possible), and a hint of fruit at the lowest recommended temperatures, which increases in complexity at higher temperatures (64+). Successful in dark and high gravity beers. Sláinte!', 'Ales, British Ales', 'WY1084, WLP004', NULL, 0, NULL),
  ('bm-yeast-wy1084-irish-ale-wyeast', 'Irish Ale', 'ale', 'liquid', 'Wyeast', 'WY1084', 16.7, 22.2, 'medium', 73.0, 71.0, 75.0, '12', 'This versatile yeast ferments extremely well in dark worts. It is a good choice for most high gravity beers. Beers fermented in the lower temperature range produce a dry, crisp profile with subtle fruitiness. Fruit and complex esters will increase when fermentation temperatures are above 64°F (18°C).', 'Stouts, Red Ales, Porters, Double IPA, Wee Heavy, Scottish Ales', 'WLP004, A10, GY080', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp004-irish-ale-yeast-white-labs', 'Irish Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP004', 18.3, 20.0, 'medium-high', 71.5, 69.0, 74.0, '11', 'This yeast is from one of the oldest stout-producing breweries in the world. Medium attenuation helpswith a dry finish that promotes roasty notes.', NULL, 'WY1098', NULL, 0, NULL),
  ('bm-yeast-gy080-irish-stout-gigayeast', 'IRISH STOUT', 'ale', 'liquid', 'GigaYeast', 'GY080', 17.8, 22.2, 'medium', 84.0, 82.0, 86.0, NULL, 'From one of the most famous stouts in the world. Creates a crisp, dry beer with a subtle fruity profile and a slightly tangy finish. ', 'Stout, Porter, Imperial Stout, Amber/Red Ale, English Pale Ale', 'A10, WLP004, WY1084', NULL, 0, NULL),
  ('bm-yeast-isar-lager-escarpment-labs', 'Isar Lager', 'lager', 'liquid', 'Escarpment Labs', NULL, 10.0, 15.0, 'medium-high', 77.0, 72.0, 82.0, '11', 'One of our favourite German lager yeasts! Accentuates malt character, with a reliable fermentation profile and good flocculation and diacetyl reduction. We recommend raising fermentation temperature to 15ºC toward the end of fermentation in order to ensure full attenuation and diacetyl reduction. Can be used for both traditional and fast turnaround lagers.', 'Lagers', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-oyl-033-jovaru-lithuanian-farmhouse-omega-yeast', 'JOVARU LITHUANIAN FARMHOUSE', 'ale', 'liquid', 'Omega Yeast', 'OYL-033', 21.1, 35.0, 'medium-low', 82.5, 80.0, 85.0, '10', 'Borne from an exclusive partnership with the famed Jovaru Brewery''s queen of Lithuanian farmhouse beer, this unique yeast complements farmhouse beers with citrusy esters and restrained phenols. The strain produces a character of lemon pith, black pepper, and a soft mouthfeel.', 'Farmhouse', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-a18-joystick-imperial-yeast', 'Joystick', 'ale', 'liquid', 'Imperial Yeast', 'A18', 15.6, 21.1, 'medium-high', 75.0, 73.0, 77.0, '12', 'Clean American brewing yeast strain. Excellent choice for big, high alcohol, hoppy beers. This strain is a fast mover and can be used at the low end of the ale fermentation spectrum to keep it clean. Joystick is a great choice for big, high alcohol, malt forward beers but will shine just as well in a hoppy double IPA. ', 'American Barleywine, American Strong Ale, Robust Porter, Imperial Stout, American Stout, American Amber Ale, American Brown Ale, Black IPA, Red Ale, Winter Seasonal Beer, California Common, Wheatwine, English Mild, Extra Special Bitter, American Pale Ale, Stout, Irish Dry, Cream Ale, American Wheat Beer, Blonde Ale, American IPA, Hazy IPA, Red IPA, Imperial IPA, Altbier', 'WY1764,RVA-103,A07', 'Saccharomyces cerevisae', 0, NULL),
  ('bm-yeast-a38-juice-imperial-yeast', 'Juice', 'ale', 'liquid', 'Imperial Yeast', 'A38', 17.8, 23.3, 'medium', 74.0, 72.0, 76.0, '10', 'The go-to for juicy, hazy, NE IPAs. Hardly a one-trick pony, it can also be a great choice as a house ale strain. Juicy. Fruity. Juice is the go-to strain for hazy, juicy New England style IPAs. The ester profile of Juice brings out the aromas and flavors of the new school hops and creates a beer that is greater than the sum of its parts. Resulting in a beer that is at once round in mouthfeel but retains a nice sharp citrus edge. Keep an eye on this strain, it likes to move to the top of fermentation and will climb out the fermenter if too full. This strain has demonstrated the need for higher wort dissolved oxygen (DO) levels than most ale strains. Target 20-25 ppm DO or set the oxygen regulator flow to 50 higher than normal.', 'Hazy IPA, American IPA, American Stout, English IPA, Extra Special Bitter, Bitter, Pale Ale, Stout, Irish Dry, Brown Porter, Stout, Oatmeal, Black IPA, Red IPA, White IPA, American Pale Ale, Red Ale, Robust Porter, Winter Seasonal Beer, Imperial IPA, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, English Mild, Irish Red Ale, Stout, Tropical, Cream Ale, American Wheat Beer, Blonde Ale, California Common, American Amber Ale, American Brown Ale', 'WY1318,RVA-132,ES-FOG,WLP066,OYL-011,GY128,LAL-VERDANT', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-g02-kaiser-imperial-yeast', 'Kaiser', 'ale', 'liquid', 'Imperial Yeast', 'G02', 13.3, 18.3, 'low', 75.0, 73.0, 77.0, '10', 'Traditional Alt yeast strain however, this German ale strain can do just about anything. Kaiser is ready to produce an array of German-style beers. It will keep the beer clean and allow the delicate malt flavors and aromas to shine through. Characteristics of this strain make it a good choice for traditional Berliner Weisse fermentations. Kaiser is a low flocking strain, so expect long clarification times, but very low diacetyl levels.', 'Altbier, Kolsch, Berliner Weisse, Gose, Bière de Garde, Blonde Ale, Pale Ale, American IPA', 'G03, K-97, WLP036, WY1007', NULL, 0, NULL),
  ('bm-yeast-ecy28-kellerbier-east-coast-yeast', 'Kellerbier', 'lager', 'liquid', 'East Coast Yeast', 'ECY28', 7.8, 12.2, NULL, 75.0, 74.0, 76.0, NULL, 'This yeast exhibits a clean, crisp lager in traditional northern German character. Use in German Pilsners including Kellerbier. ', 'German Pilsners', NULL, NULL, 0, NULL),
  ('bm-yeast-wy2565-kolsch-wyeast', 'Kolsch', 'ale', 'liquid', 'Wyeast', 'WY2565', 13.3, 21.1, 'low', 75.0, 73.0, 77.0, '10', 'This strain is a classic, true top cropping yeast strain from a traditional brewery in Cologne, Germany. Beers will exhibit some of the fruity character of an ale, with a clean lager like profile. It produces low or no detectable levels of diacetyl. This yeast may also be used to produce quick-conditioning pseudo-lager beers and ferments well at cold 55-60 °F (13-16 °C) range. This powdery strain results in yeast that remain in suspension post fermentation. It requires filtration or additional settling time to produce bright beers.', 'Kolsch, Wheat, Cream Ale, Berliner Weisse, Fruit Beer, Amber Lager', 'K-97, G03, WLP029, GY021, OYL-044', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-kolsch-ale-escarpment-labs', 'Kolsch Ale', 'ale', 'liquid', 'Escarpment Labs', NULL, 18.3, 20.6, 'medium', 75.0, 72.0, 78.0, '9', 'This balanced and clean ale yeast is of course great for Altbier and Kölsch production, but also for a wide range of beers including Blond ales, American Wheat, Berliner Weisse, Gose, and anywhere a clean fermentation is desired. Extended chilling or filtration is suggested to obtain clear beer.', 'Blonde ales, American Wheat, Berliner Weisse, Gose', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-gy021-kolsch-bier-gigayeast', 'KOLSCH BIER', 'ale', 'liquid', 'GigaYeast', 'GY021', 15.6, 22.2, 'medium-high', 81.0, 79.0, 83.0, NULL, 'From one of the oldest Kolsch breweries in Koln. Ferments cold to produce crisp tasting lager-like ales. ', 'Kolsch, Pale Ale, Alt, India Pale Ale, Cream Ale, Amber', 'K-97, G03, WLP029, WY2565', NULL, 0, NULL),
  ('bm-yeast-oyl-017-kolsch-i-omega-yeast', 'KOLSCH I', 'ale', 'liquid', 'Omega Yeast', 'OYL-017', 13.3, 21.1, 'low', 75.0, 73.0, 77.0, '10', 'An enthusiastically top cropping, lager-like ale strain from Koln, Kolsch I is lightly fruity, crisp and clean, and accentuates hop flavors well. This strain can be fermented colder than Kolsch II (OYL- 044), and is powdery and slow to drop clear (filtering recommended). Kolsch II (OYL-044) is a little easier to manage. Sulfur disappears with age.', 'Ales', 'WY2565', NULL, 0, NULL),
  ('bm-yeast-oyl-044-kolsch-ii-omega-yeast', 'KOLSCH II', 'ale', 'liquid', 'Omega Yeast', 'OYL-044', 18.3, 20.6, 'medium-low', 75.0, 72.0, 78.0, '10', 'This Kolsch strain is warmer fermenting than Kolsch I (OYL-017), flocculates much better and clears more quickly, so is a little easier to manage. It is a lager-like ale strain that''s lightly fruity, crisp and clean with a hint of sulfur that disappears with age to leave a clean ale. Accentuates hop flavors.', 'Ales', 'WLP029, K-97, WLP003', NULL, 0, NULL),
  ('bm-yeast-wy2575-kolsch-ii-wyeast', 'Kolsch II', 'ale', 'liquid', 'Wyeast', 'WY2575', 12.8, 21.1, 'low', 75.0, 73.0, 77.0, '10', 'This authentic Kӧlsch strain from one of Germany''s leading brewing schools has a rich flavor profile which accentuates a soft malt finish. It has low or no detectable diacetyl production and will also ferment well at colder temperatures for fast lager type beers.', 'Kolsch, Altbier, Amber Lager', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-ecy21-kolschbier-east-coast-yeast', 'Kolschbier', 'ale', 'liquid', 'East Coast Yeast', 'ECY21', 14.4, 18.9, NULL, 76.5, 75.0, 78.0, NULL, 'Produces a clean lager-like profile at ale temperatures. Smooth mineral and malt characters come through with a clean, lightly yeasty flavor and aroma in the finish', 'Kolsch', NULL, NULL, 0, NULL),
  ('bm-yeast-krispy-escarpment-labs', 'Krispy', 'ale', 'liquid', 'Escarpment Labs', NULL, 17.8, 30.0, 'medium-high', 76.0, 70.0, 82.0, '14', 'KRISPY is a special blend of kveik yeasts selected by our lab wizards for optimal crispiness and crushability in beer. It can be used to make clean, lager-like beers in a fraction of the time since fermentations can be performed in the 20-30ºC range. KRISPY is a selection of two strains from the Skare kveik.', NULL, NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-gy134-kveik-1-gigayeast', 'Kveik #1', 'ale', 'liquid', 'GigaYeast', 'GY134', 26.7, 37.8, 'medium', 76.0, 74.0, 78.0, NULL, 'A traditional Norwegian Kviek yeast that can be fermented at 85-100 F for fast fermentations and no off flavors.  We have found a 15 P wort attenuates to 74 - 78 in as little as 48 hours at 90F.   Subtle notes of citrus fruit make this yeast an excellent choice for clean hop-forward IPAs and Pale Ales with citrus hop additions  ', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-a44-kveiking-imperial-yeast', 'Kveiking', 'ale', 'liquid', 'Imperial Yeast', 'A44', 23.9, 36.1, 'low', 80.0, 75.0, 85.0, '12', 'Blend of 3 kveik strains conquers wort, leaving tropical fruit flavors in its wake. Kveiking [Kuh-vahy-king] noun: A blend of three Kveik strains that can produce an insane amount of pineapple, guava and other exotic tropical fruit aromas. verb: Hopefully not an Old Norse term for an activity we should not be promoting. The Kveiking blend thrives in hot fermentations when big complex ester profiles are desired. A low pitch rate can be used to drive these aromatics even higher but the brewer should ensure this low pitch rate can be combined with a continuously high fermentation temperature. If the temperature drops too low, the corresponding level of attenuation can be low, with high terminal gravities. This blend contains flocculent and non-flocculent yeast strains, therefore the clarity of the final beers produced can be variable. Use this blend for anything from new school hazy IPAs to traditional Norwegian farmhouse brews. The Kveiking blend also works well when fermenting kettle soured worts for a strong tropical fruit character.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', 'A43, A04', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-605-lactobacillus-blend-omega-yeast', 'Lactobacillus Blend', 'ale', 'liquid', 'Omega Yeast', 'OYL-605', 20.0, 35.0, 'low', 67.5, 65.0, 70.0, '7', 'A Lactobacillus brevis and plantarum blend with a wide temperature range. The Lacto plantarum, isolated in collaboration with Marz Community Brewing, sours efficiently at its higher end. Do not sour above 95°F to prevent stalling. Max souring develops within 24-48 hrs. Extremely hop sensitive, even 2 IBUs can prevent souring.', 'Farmhouse,Sours,Lambic,Berliner Weiss', 'WLP672,WY5335', 'Lactobacillus brevis, plantarum', 0, NULL),
  ('bm-yeast-wlp4682-lactobacillus-blend-the-yeast-bay', 'Lactobacillus Blend', 'ale', 'liquid', 'The Yeast Bay', 'WLP4682', 21.1, 32.2, NULL, 67.5, 65.0, 70.0, NULL, 'The Lactobacillus Blend is comprised of three strains, one strain of Lactobacillus plantarum and two strains of Lactobacillus brevis.  One of the strains of L. brevis was isolated from an unintentionally sour hoppy blonde ale from a Mexican craft brewery, and exhibits strong hop tolerance (15-20 IBU). ', NULL, NULL, 'Lactobacillus plantarum, Lactobacillus brevis', 0, NULL),
  ('bm-yeast-lactobacillus-blend-20-escarpment-labs', 'Lactobacillus Blend 2.0', 'ale', 'liquid', 'Escarpment Labs', NULL, 30.0, 45.0, 'low', 67.5, 65.0, 70.0, '7', 'This blend is a product of our ongoing research into optimizing Lactobacillus strain selection. It is a blend of our main L. plantarum strain with a strain of Lactobacillus rhamnosus. This blend has a wide temperature range ( 30ºC to 40ºC) and enhances fruit flavours in the finished beer, with tasters noting red fruit and guava aromas. It is intended for kettle/quick souring but can also be used in 0 IBU wort.', 'Sours,Berliner Weiss,Lambic', 'OYL-605,WY5335,WLP672', 'lactobacillus', 0, NULL),
  ('bm-yeast-lactobacillus-brevis-escarpment-labs', 'Lactobacillus brevis', 'ale', 'liquid', 'Escarpment Labs', NULL, 35.0, 45.0, NULL, 0.0, 0.0, 0.0, NULL, 'A single strain of Lactobacillus brevis. It performs well in kettle souring/sour worting where complex acidity is desired. We recommend pre-acidifying wort to 4.5 with lactic acid, then pitching the Lactobacillus blend in a CO2-purged kettle or fermentor at 35-40ºC.', 'Sours', NULL, NULL, 0, NULL),
  ('bm-yeast-wlp672-white-labs-lactobacillus-brevis', 'Lactobacillus Brevis', 'ale', 'liquid', 'White Labs', 'WLP672', 21.1, 23.9, 'low', 80.0, 80.0, 80.0, '10', 'This is a rod-shaped Lactobacillus bacteria used for souring beers through either traditional or kettle souring techniques. This strain typically produces more lactic acid than strains like WLP677 Lactobacillus delbrueckii, making it an ideal addition to any sour program.', 'Berliner Weisse, Flanders Brown, Flanders Red, Gose, Geuze, Lambic', 'WY5335,WLP677', 'Lactobacillus Brevis', 0, NULL),
  ('bm-yeast-wlp4681-lactobacillus-brevis-strain-tyb282-the-yeast-bay', 'Lactobacillus brevis - Strain TYB282', 'ale', 'liquid', 'The Yeast Bay', 'WLP4681', 21.1, 32.2, NULL, 4.0, 4.0, 4.0, NULL, 'TYB282 is a single strain of Lactobacillus brevis isolated out of an unintentionally soured golden ale produced by a Mexican craft brewery. This strain produces a nice, clean lactic acidity (down to ~pH 3.16-3.18) in unhopped wort within 36 hours at a temperature of ~72-77 °F. The higher the temperature up to 90 °F, the faster the acid production. This is a great strain for kettle souring, but really shines in souring fermented beer as a result of its hop tolerance (15-20 IBU).', NULL, NULL, 'Lactobacillus brevis', 0, NULL),
  ('bm-yeast-wy5335-wyeast-lactobacillus-buchneri', 'Lactobacillus buchneri', 'ale', 'liquid', 'Wyeast', 'WY5335', 15.6, 35.0, 'low', 9.0, 9.0, 9.0, NULL, 'This culture produces moderate levels of acidity and is commonly found in many types of beers including gueuze, lambics, sour brown ales and Berliner Weisse. It is always used in conjunction with S. cerevisiae and often with various wild yeast. Use in wort or beer below 10 IBU is recommended due to the culture’s sensitivity to hop compounds.', 'Lambic,Gueuze,Flanders Red Ale,Berliner Weisse,Oud Bruin', 'GB110,OYL-605', 'Lactobacillus buchneri', 0, NULL),
  ('bm-yeast-wlp677-white-labs-lactobacillus-delbrueckii', 'Lactobacillus delbrueckii', 'ale', 'liquid', 'White Labs', 'WLP677', 21.1, 35.0, 'low', 78.5, 75.0, 82.0, '10', 'This lactic acid bacteria produces moderate levels of acidity and sour flavors.  Souring will need maturation times around 3+ months- Low sugar requirements will be necessary for these organisms to produce acidity- Organisms will have a difficult time growing in environments below a pH of 3.5. General brewing pitch rates apply for primary fermentation- Fermentation timeline will be slower – closer to 15-21 days depending on the strain', 'Lambic, Berliner Weisse, Sours, Gueze', 'WLP672', 'Lactobacillus delbrueckii', 0, NULL),
  ('bm-yeast-oyl-100-lager-i-omega-yeast', 'LAGER I', 'lager', 'liquid', 'Omega Yeast', 'OYL-100', 8.9, 13.3, 'medium-high', 73.0, 71.0, 75.0, '9', 'Early inspiration for light American lager and thought to be from Budejovice, this crisp, balanced strain is lightly malty and finishes with very slight fruit notes. It is the backbone of the classic Czech Pilsner profile where the yeast character should neither dominate nor disappear among the beer''s subtle balance of malts and hops.', 'Lagers', 'WY2000', NULL, 0, NULL),
  ('bm-yeast-lalbrew-abbaye-lallemand', 'LalBrew Abbaye', 'ale', 'dry', 'Lallemand', NULL, 17.2, 25.0, 'medium-high', 85.0, 80.0, 90.0, NULL, 'LalBrew Abbaye is an ale yeast of Belgian origin. Selected for its ability to ferment Belgian style beers ranging from low to high alcohol, LalBrew Abbaye produces the spiciness and fruitiness typical of Belgian and Trappist style ales. When fermented at higher temperatures, typical flavors and aromas include tropical, spicy and banana. At lower temperatures, LalBrew Abbaye produces darker fruit aromas and flavors of raisin, date, and fig. ', 'Belgian White, Belgian Blonde, Belgian Golden, Dubbel, Tripel, Quad', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-lalbrew-belle-saison-lallemand', 'LalBrew Belle Saison', 'ale', 'dry', 'Lallemand', NULL, 15.0, 35.0, 'low', 85.0, 80.0, 90.0, NULL, 'LalBrew Belle Saison is a Belgian-style ale yeast selected specifically for its ability to create Saison-style beers. Belle Saison is a diastaticus strain that allows the brewers to achieve the high attenuation characteristic of this classic style. Designed for warm-temperature fermentation true to traditional Farmhouse production methods, beers brewed with LalBrew Belle Saison are fruity, spicy and refreshing.', 'Saison', NULL, 'Saccharomyces cerevisiae var. diastaticu', 0, NULL),
  ('bm-yeast-lalbrew-bry-97-lallemand', 'LalBrew BRY-97', 'ale', 'dry', 'Lallemand', 'BRY-97', 15.0, 22.2, 'high', 77.5, 75.0, 80.0, '11', 'LalBrew BRY-97 is an American West Coast-style ale yeast that was selected from the Siebel Institute Culture Collection for its ability to produce high quality ales. LalBrew BRY-97 is a neutral strain with a high flocculation ability that can be used to make a wide variety of American-style beers. Through expression of a beta-glucosidase enzyme, LalBrew BRY-97 can promote hop biotransformation and accentuate hop flavor and aroma. ', 'Cream Ale, American Wheat, Scotch Ale, American Pale Ale, American Amber, American Brown, American IPA, American Stout, Russian Imperial Stout, Imperial IPA, Roggen/Rye, Old Ale, American Barleywine', 'WY1056,WLP001,US-05,RVA-101,A07,OYL-004,M44,BBUSA1,GY001', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-lalbrew-cbc-1-lallemand', 'LalBrew CBC-1', 'ale', 'dry', 'Lallemand', 'CBC-1', 15.0, 25.0, NULL, 0.0, 0.0, 0.0, NULL, 'LalBrew CBC-1 has been specifically selected from the Lallemand Yeast Culture Collection for its refermentation properties and is recommended for Cask and Bottle Conditioning. LalBrew CBC-1 referments beer efficiently due to its high resistance to alcohol and pressure. The flavor is neutral, therefore the original character of the beer is preserved. The yeast will settle and form a tight mat at the end of refermentation. LalBrew CBC-1 can also be used for primary fermentation of dry ciders or mead. Maltotriose is not metabolized during primary fermentation of beer, so LalBrew CBC-1 is well suited for sweeter fruit beers or fullbodied, malty ales.', 'fruit beers, dry cider, mead ', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-lalbrew-diamond-lager-lallemand', 'LalBrew Diamond Lager', 'lager', 'dry', 'Lallemand', NULL, 10.0, 15.0, 'high', 85.0, 80.0, 90.0, NULL, 'LalBrew Diamond Lager yeast is a true lager strain originating in Germany. Chosen for its robust character, LalBrew Diamond Lager yeast delivers excellent fermentation performance, and has the ability to  produce clean, authentic lagers. ', 'Munich Helles, Dortmunder Export, German Pilsner, Bohemian Pilsner, American Pilsner,  Vienna Lager, Oktoberfest/Marzen, Dark American Lager, Munich Dunkel, Schwarzbier, Traditional Bock, Doppelbock, Eisbock, California Common', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-lalbrew-koln-lallemand', 'LalBrew Koln', 'ale', 'dry', 'Lallemand', NULL, 12.2, 20.0, 'medium-high', 75.0, 73.0, 77.0, NULL, 'LalBrew Koln is ideal for brewing traditional Kolsch-style beers and other neutral ales.  The neutral character of this strain accentuates delicate hop aromas while imparting subtle fruity esters.  Through expression of a beta-glucosidase enzyme LalBrew Koln can promote hop biotransformation and accentuate hop flavor and aroma. Colder fermentations will be more neutral in character, while warmer fermentations will have more fruit-forward ester profile.', 'Kolsch, IPA', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-lalbrew-london-lallemand', 'LalBrew London', 'ale', 'dry', 'Lallemand', NULL, 18.3, 22.2, 'low', 85.0, 80.0, 90.0, NULL, 'LalBrew London is a true English ale strain selected for reliable fermentation performance and moderate  ester production that lets the flavors and aromas of malt and hops shine through. LalBrew London was  selected from the Lallemand yeast culture library, and is an excellent choice for brewing authentic heritage UK styles.', 'Pale Ale, Bitters, Mild Ale', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-lalbrew-munich-classic-lallemand', 'LalBrew Munich Classic', 'ale', 'dry', 'Lallemand', NULL, 17.2, 22.2, 'low', 77.5, 75.0, 80.0, NULL, 'LalBrew Munich Classic is a Bavarian wheat beer strain that can easily express the spicy and estery aroma profile typical to German wheat beer styles. This strain is simple to use over a wide range of recipe variations and fermentation conditions, making it a great choice for a number of traditional styles of wheat beer. A true top cropping yeast, LalBrew Munich Classic yeast can be skimmed off the top of classic open fermentation vessels in the traditional manner. ', 'Weizen/Weissbier, Dunkelweizen, Weizenbock', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-lalbrew-new-england-lallemand', 'LalBrew New England', 'ale', 'dry', 'Lallemand', 'LB-NE', 15.0, 22.2, 'medium', 75.0, 73.0, 77.0, '11', 'LalBrew New England is an ale strain selected specifically for its ability to produce a unique fruit forward ester profile desired in East Coast styles of beer. A typical fermentation with LalBrew  New England will produce tropical and fruity esters, notably stone fruits like peach. Through expression of a β-glucosidase enzyme, LalBrew New England can promote hop biotransformation and accentuate hop flavor and aroma. LalBrew New England exhibits medium to high attenuation with medium flocculation, making it a perfect choice for East Coast style ales.', 'Hazy IPAs, Pale Ales, IPAs', '052,GY054,WLP4000,WLP095,A04,ECY29,RVA-104,ES-VT', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-lalbrew-nottingham-lallemand', 'LalBrew Nottingham', 'ale', 'dry', 'Lallemand', 'LB-NOTT', 10.0, 22.2, 'high', 85.0, 80.0, 90.0, '14', 'LalBrew Nottingham is an English style ale yeast selected for its high performance and versatility for a wide variety of styles and fermentation conditions. Traditional styles brewed with this yeast include but are not limited to Pale Ales, Ambers, Porters, Stouts and Barleywines. LalBrew Nottingham is a relatively neutral ale strain that is stress tolerant making it a good choice for high gravity, sour and other challenging fermentation conditions.', 'Golden Ale, Kolsch, Lagers, IPA, Imperial Stout, Pale Ales, Ambers, Porters, Stouts, Barleywines', 'WLP039', 'Saccharomyces cerevisiae', 0, 0),
  ('bm-yeast-lallemand-lalbrew-verdant-ipa', 'LalBrew Verdant IPA', 'ale', 'liquid', 'Lallemand', 'LAL-VERDANT', 17.8, 22.8, 'medium', 77.5, 75.0, 80.0, '10', 'LalBrew Verdant IPA was specially selected in collaboration with Verdant Brewing Co. (UK) for its ability to produce a variety of hop-forward and malty beers. Prominent notes of apricot and undertones of tropical fruit and citrus merge seamlessly with hop aromas. With medium-high attenuation, LalBrew Verdant IPA leaves a soft and balanced malt profile with slightly more body than a typical American IPA yeast strain. This highly versatile strain is well suited for a variety of beer styles.', 'NEIPA, English IPA, American Pale, English Bitter, Sweet Stout and Sour', 'GY128,WY1318,RVA-132,WLP066,OYL-011,A38', 'Saccharomyces cerevisiae', 0, 0),
  ('bm-yeast-lalbrew-voss-lallemand', 'LalBrew Voss', 'ale', 'dry', 'Lallemand', NULL, 25.0, 40.0, 'very-high', 77.5, 75.0, 80.0, NULL, 'Kveik is a Norwegian word meaning yeast. In the Norwegian farmhouse tradition, kveik was preserved by drying and passed from generation to generation. Kveik is the original, traditional dried yeast! The LalBrew Voss strain was obtained from Sigmund Gjernes (Voss, Norway), who has maintained this culture using traditional methods since the 1980s and generously shared it with the wider brewing community. LalBrew Voss supports a wide range of fermentation temperatures between 25-40°C (77-104°F) with a very high optimal range of 35-40°C (95-104°F). Very fast fermentations are achieved within the optimal temperature range with full attenuation typically achieved within 2-3 days. The flavor profile is consistent across the entire temperature range: neutral with subtle fruity notes of orange and citrus. Flocculation is very high producing clear beers without filtration or use of process aids.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', 'OYL-061', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-lalbrew-windsor-lallemand', 'LalBrew Windsor', 'ale', 'dry', 'Lallemand', NULL, 15.0, 22.2, 'low', 75.0, 73.0, 77.0, NULL, 'LalBrew Windsor ale yeast is a true English strain that produces a balanced fruity aroma and imparts a slight fresh yeasty flavor. Beers created with Windsor are usually described as full-bodied, fruity English ales. Brewers choose LalBrew Windsor to produce beers that range from Pale Ale to Porter with moderate alcohol levels and the flavor and aroma characteristics of the best traditional ales. ', 'Pale Ale, Milds, Bitters, Irish Reds, English Brown Ales, Porters, Sweet Stouts', 'WY1028, WLP013', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-lalbrew-wit-lallemand', 'LalBrew Wit', 'ale', 'dry', 'Lallemand', NULL, 17.2, 22.2, 'medium-high', 67.5, 65.0, 70.0, NULL, 'LalBrew Wit yeast is a relatively neutral strain which can be used to produce a wide variety of wheat beer styles. Ester and phenol production is lower than for traditional hefeweizen strains such as Munich Classic. LalBrew Wit provides a baseline profile of banana and spice aromas, but leaves space for the brewer to showcase other spice additions typical of Belgian style beers.', 'Belgian Witbier, American Wheat, Berliner Weiss, Gose, Hefeweizen, Dunkelweis, Weizenbock', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-m36-liberty-bell-ale-mangrove-jack', 'Liberty Bell Ale', 'ale', 'dry', 'Mangrove Jack', 'M36', 17.8, 22.8, 'high', 76.0, 74.0, 78.0, NULL, 'A top fermenting ale yeast suitable for a wide variety of hoppy and distinctive style beers. This strain produces light, delicate fruity esters and helps to develop malt character.', 'Pale Ales, Extra Special Bitters, Golden Ales', NULL, NULL, 0, NULL),
  ('bm-yeast-wlp4052-lida-kveik-the-yeast-bay', 'Lida Kveik', 'ale', 'liquid', 'The Yeast Bay', 'WLP4052', 26.7, 32.2, 'low', 78.5, 75.0, 82.0, '14', 'This culture is a single strain of Saccharomyces cerevisiae isolated from Samuel Lien’s house culture, which he received from Hans Øen around 1980. It exhibits a fermentation profile of apricot, stone fruit and white wine grape esters, with a balanced malt character coming through on the finish. ', NULL, NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp4623-lochristi-brettanomyces-blend-the-yeast-bay', 'Lochristi Brettanomyces Blend', 'ale', 'liquid', 'The Yeast Bay', 'WLP4623', 21.1, 26.7, 'medium-low', 84.0, 80.0, 88.0, '14', 'This blend combines Brettanomyces bruxellensis strains isolated from a unique beer produced in the Lochristi area in East Flanders. One strain provides a moderate funk and light fruitiness, while the other strain adds a more assertive fruitiness dominated by hints of strawberry.', NULL, NULL, 'Brettanomyces bruxellensis', 0, NULL),
  ('bm-yeast-a43-loki-imperial-yeast', 'Loki', 'ale', 'liquid', 'Imperial Yeast', 'A43', 18.3, 37.8, 'medium-high', 80.0, 75.0, 85.0, '10', 'Norwegian Voss Kveik Strain. Highly versatile, can be used in a wide variety of beer styles. A traditional Norwegian Kveik strain that has an extremely wide fermentation temperature range. This strain has been traditionally used in Norwegian farmhouse style beers however, due to it''s fermentation temp range can be used in a variety of beers from pseudo lagers, Belgian inspired, and hop forward beers. The possibilities seem endless when fermenting with Loki. On the cool end of the range Loki is super clean; producing little to no esters. On the high end of the fermentation range, 85-95F, it tends to produce a huge fruit ester profile.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', 'A24, A38', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-003-london-ale-omega-yeast', 'LONDON ALE', 'ale', 'liquid', 'Omega Yeast', 'OYL-003', 18.9, 22.2, 'medium', 72.0, 67.0, 77.0, '11', 'The London Ale strain is a high attenuator that has obvious English character in its pronounced mineral and mild fruit. It performs best for dry, crisp beers, and in highlighting hop bitterness. For more neutral strains, try West Coast Ale I (OYL-004), or keep the English deportment with British Ale I (OYL-006) or British Ale VI (OYL-013).', 'Ales, British Ales', 'WY1028, WLP013', NULL, 0, NULL),
  ('bm-yeast-wy1028-london-ale-wyeast', 'London Ale', 'ale', 'liquid', 'Wyeast', 'WY1028', 15.6, 22.2, 'medium-low', 75.0, 73.0, 77.0, '11', 'A rich mineral profile that is bold and crisp with some fruitiness. Often used for higher gravity ales and when a high level of attenuation is desired.', 'Dark Mild, Brown Ales, Porters, Stouts, IPA, Pale Ales', 'WLP013', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy1318-london-ale-iii-wyeast', 'London Ale III', 'ale', 'liquid', 'Wyeast', 'WY1318', 17.8, 23.3, 'high', 73.0, 71.0, 75.0, '10', 'Originating from a traditional London brewery, this yeast has a wonderful malt and hop profile. It is a true top cropping strain with a fruity, very light and softly balanced palate. This strain will finish slightly sweet. London Ale III has become synonymous with the production of New England IPAs, also known as juicy or hazy IPAs, and balances well with the tropical fruit qualities from late and dry hop additions.', 'Hazy IPA, IPA, Bitters, Stout, Barleywine', 'A38,RVA-132,ES-FOG,WLP066,OYL-011,GY128,LAL-VERDANT', 'Saccharomyces cerevisiae', 0, 0),
  ('bm-yeast-wlp013-london-ale-yeast-white-labs', 'London Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP013', 18.9, 21.7, 'medium', 71.0, 67.0, 75.0, '9', 'Oak ester character makes this yeast well-suited for classic British beer styles. Medium flocculationallows attenuation up to 75% leaving beer dry while adding malt complexity and pushing hop bitterness.', NULL, 'WY1028', NULL, 0, NULL),
  ('bm-yeast-wy1968-london-esb-ale-wyeast', 'London ESB Ale', 'ale', 'liquid', 'Wyeast', 'WY1968', 17.8, 22.2, 'high', 69.0, 67.0, 71.0, '9', 'A very good cask conditioned ale strain, this extremely flocculent yeast produces distinctly malty beers. Attenuation levels are typically less than most other yeast strains which results in a slightly sweeter finish. Ales produced with this strain tend to be fruity, increasingly so with higher fermentation temperatures of 70-74 °F (21-23 °C). A thorough diacetyl rest is recommended after fermentation is complete. Bright beers are easily achieved within days without any filtration.', 'Bitters, English IPA, Dark Mild, Brown Ale, Strong Ale, Barleywine', 'WLP002, A09, Lallemand London ESB, OYL-016', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp066-london-fog-ale-yeast-white-labs', 'London Fog Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP066', 17.8, 22.2, 'medium-low', 78.5, 75.0, 82.0, '11', 'This is the go-to strain for New England-style IPAs. It leaves some residual sweetness, helping accentuateboth malt and hop flavors and aromas, while retaining a velvety mouthfeel. Produces a medium ester profile.', 'IPA, Pale Ale, Hazy IPA', 'A38,WY1318,RVA-132,ES-FOG,OYL-011,GY128,LAL-VERDANT', 'Saccharomyces cerevisiae', 0, 0),
  ('bm-yeast-oyl-071-lutra-kveik-omega-yeast', 'Lutra Kveik', 'ale', 'liquid', 'Omega Yeast', 'OYL-071', 20.0, 35.0, 'medium-high', 78.5, 75.0, 82.0, '11', 'Isolated from our Hornindal Kveik (OYL-091) culture, Lutra is shockingly clean with unrivaled speed when pitched at 90°F (32°C). The strain is perfect for brewing a refreshing pseudo-lager without the lead time of a lager. Lutra is your worry-free way to navigate the evolving demand for cold ones.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', 'OYL-091', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-rva-132-manchester-ale-rva-yeast-labs', 'Manchester Ale', 'ale', 'liquid', 'RVA Yeast Labs', 'RVA-132', 18.3, 22.2, 'high', 72.5, 70.0, 75.0, '10', 'Dryer than the Chiswick, this English classic will create a touch of esters and leave a hint of residual sweetness and malt backbone.', 'IPA, Brown Ale, ESB', 'A38,WY1318,ES-FOG,WLP066,OYL-011,GY128,LAL-VERDANT', 'Saccharomyces cerevisae', 0, 0),
  ('bm-yeast-wlp4633-melange-sour-blend-the-yeast-bay', 'Mélange - Sour Blend', 'ale', 'liquid', 'The Yeast Bay', 'WLP4633', 20.0, 25.6, 'medium-low', 92.5, 85.0, 100.0, '14', 'Mélange is made up of a rich diversity of fermentative organisms, intended for use in the production of sour beers with a perfect balance of esters, earthiness, funk and sourness is desired. ', NULL, NULL, 'Saccharomyces cerevisiae, Saccharomyces cerevisiae var. diastaticus, Saccharomyces fermentati, Brett', 0, 1),
  ('bm-yeast-wlp4650-metschnikowia-reukaufii-the-yeast-bay', 'Metschnikowia reukaufii ', 'ale', 'liquid', 'The Yeast Bay', 'WLP4650', 15.6, 32.2, 'low', 22.5, 20.0, 25.0, '9', 'M. reukaufii is a nectar specialist that was isolated from flowers in the Berkeley Hills of California. Evolutionarily, these yeast likely evolved to produce a more odorous and attractive nectar for pollinators by enzymatically altering otherwise inodorous nectar compounds like glycosides.  While only attenuating to 20-25% in brewer’s wort and not utilizing maltose or maltose polymers, in co-fermentations it has been shown to drop gravity and pH of the fermentation faster, accentuate and modulate the flavor and aroma profile and soften the perceived bitterness of the finished product.  This strain MUST be used in conjunction with other yeast that can ferment brewer’s wort (capable of fermenting maltose).', NULL, NULL, 'M. reukaufii', 0, NULL),
  ('bm-yeast-mexican-lager-escarpment-labs', 'Mexican Lager', 'lager', 'liquid', 'Escarpment Labs', NULL, 10.0, 13.9, 'medium', 75.0, 75.0, 75.0, '9', 'A workhorse North American lager strain, produces clean and crisp beers; not just limited to light lager styles! ', 'Lagers', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-oyl-113-mexican-lager-omega-yeast', 'MEXICAN LAGER', 'lager', 'liquid', 'Omega Yeast', 'OYL-113', 10.0, 12.8, 'medium', 74.0, 70.0, 78.0, '9', 'This great lager strain is thought to originate from a well known Mexican brewery. Simply put, it is clean, crisp, bright and versatile.', 'Lagers', 'WLP940', NULL, 0, NULL),
  ('bm-yeast-wlp940-mexican-lager-yeast-white-labs', 'Mexican Lager Yeast', 'lager', 'liquid', 'White Labs', 'WLP940', 10.0, 12.8, 'medium', 74.0, 70.0, 78.0, '9', 'From Mexico City, this strain produces clean lager beers with a crisp finish. It keeps drinkability on the forefrontwhile allowing malt and hop flavors and aromas to be background notes.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-wlp4053-midtbust-kveik-the-yeast-bay', 'Midtbust Kveik', 'ale', 'liquid', 'The Yeast Bay', 'WLP4053', 23.9, 35.0, 'low', 78.0, 76.0, 80.0, '14', 'This single strain of Saccharomyces cerevisiae isolated from Odd H Midtbust’s house culture exhibits a cleaner fermentation character and restrained ester profile, allowing the malt and hop character to shine. Perfect for use in any style where malt and/or hop character is at the forefront of the profile. ', NULL, NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp4040-midwestern-ale-the-yeast-bay', 'Midwestern Ale', 'ale', 'liquid', 'The Yeast Bay', 'WLP4040', 17.8, 22.2, 'medium', 78.0, 76.0, 80.0, '11', 'Midwestern Ale yeast is a single strain of Saccharomyces cerevisiae isolated from a storied brewery in the heartland of America, well suited for fermentation of a broad spectrum of worts. A relatively fast fermenter with good attenuation, expect this yeast to ferment cleaner with a low ester profile at the cooler fermentation temperatures, and produce a more pronounced ester profile at warmer fermentation temperatures. This yeast is a great choice for a versatile house yeast.', 'Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp500-monastery-ale-yeast-white-labs', 'Monastery Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP500', 18.3, 22.2, 'medium-low', 77.5, 75.0, 80.0, '14', 'Sourced from a Belgian monastery, this strain produces characteristic notes of plum and cherry with a hint of bubble gum.', 'Belgian Ales, Tripel, Dubbel, Trappist', 'WY1214, B63, GY014, T-58', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy2308-munich-lager-wyeast', 'Munich Lager', 'lager', 'liquid', 'Wyeast', 'WY2308', 8.9, 13.3, 'medium', 72.0, 70.0, 74.0, '9', 'This is a unique strain, capable of producing fine lagers. It is very smooth, well-rounded and full-bodied. A thorough diacetyl rest is recommended after fermentation is complete. ', 'Lager, Festbier, Marzen, Bock, Munich Dunkel', 'WLP838', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-munich-lager-escarpment-labs', 'Munich Lager', 'lager', 'liquid', 'Escarpment Labs', NULL, 12.2, 15.0, 'medium', 78.0, 78.0, 78.0, '14', 'A classic and commonly used German lager strain. Produces characteristic lager sulfur aromas. We recommend raising fermentation temperature to 15ºC toward the end of fermentation in order to ensure full attenuation and diacetyl reduction', 'Lagers', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-wy2352-munich-lager-ii-wyeast', 'Munich Lager II', 'lager', 'liquid', 'Wyeast', 'WY2352', 11.1, 16.7, 'medium', 73.0, 72.0, 74.0, '10', 'From a famous brewery in Munich, this strain is a low diacetyl and low sulfur aroma producer. An excellent choice for malt-driven lagers.', 'Helles, Munich Dunkel, Marzen, Bock', 'L17, WLP860', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-muntons-premium-gold-muntons', 'Muntons Premium Gold', 'ale', 'dry', 'Muntons', NULL, 17.8, 21.1, NULL, 73.5, 72.0, 75.0, '8', 'Muntons Premium Gold brewer''s yeast has proved itself for many years as a particular favorite for brewers of all malt beer recipes or recipes that call for a high percentage of malt in the grist formulation. It has the ability to resist ‘sticking'' a problem often experienced with all malt recipe beers. And it has excellent crusting characteristics; the yeast residue sticks to the bottom of the fermenter, bottle or pressure barrel in a firm mass, resisting disturbance, meaning you get more beer, less waste.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-muntons-standard-ale-muntons', 'Muntons Standard Ale', 'ale', 'dry', 'Muntons', NULL, 17.8, 21.1, NULL, 73.5, 72.0, 75.0, '8', 'Muntons brewer''s yeast has been a popular favourite for many years amongst the homebrew community worldwide, gaining an enviable reputation for its consistent healthy performance, its hardy nature and its clean finish. Muntons brewer''s yeast is a dried brewer''s yeast that produces a powdery flocculation with an apparent attenuation of 70%. Ideal fermentation temperature is between 64° - 70°F to produce an alcohol tolerance of 8% ABV. It provides low ester formation but with relatively high residual sugar giving good body and mouth feel.', 'Ales', 'WY1968, WLP002, US-05, Lalbrew Nottingham, BBUSA1', NULL, 0, NULL),
  ('bm-yeast-b64-napoleon-imperial-yeast', 'Napoleon', 'ale', 'liquid', 'Imperial Yeast', 'B64', 18.3, 25.6, 'low', 80.0, 77.0, 83.0, '12', 'Classic strain to produce French Saison where a balance of fruit esters and spicy phenols are necessary. This yeast is an insane wort attenuator. Napoleon will destroy the sugars in your saison and farmhouse beers - even the ones in which most brewer''s strains have no interest. When all is said and done, Napoleon produces very dry, crisp beers with nice citrus aromas balanced by subtle black pepper phenols. Yeast settling times can be long, usually requiring filtration for bright beers. This strain tests positive for the STA1 gene via PCR analysis and is therefore considered to be Saccharomyces cerevisiae var. diastaticus', 'Saison', 'GY018, WY3711', 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-bbxnpa-neepah-blend-bootleg-biology', 'NEEPAH Blend', 'ale', 'liquid', 'Bootleg Biology', 'BBXNPA', 18.9, 21.1, 'low', 78.5, 75.0, 82.0, '7', 'The NEEPAH IPA Blend is our secret weapon for delivering the juiciest, tropical fruit bomb you''ve ever made. Carefully cultivated from a special blend of fruit-forward yeast strains, the NEEPAH Blend is here to amplify the gorgeous rainbow of flavors in your New England-Style IPAs by providing an extra punch of danky goodness. Now you can spend less money on expensive hops and spend more time drinking the best made hazy pale in town. Looking for a versatile culture that''ll deliver a new take on flavorful English Ales? The NEEPAH Blend creates decadent beers that out class those made with tired ESB strains. This blend works especially well for Brut IPAs, emphasizing the fruity hop character and reducing the perception of bitterness in dry beers.', 'IPA, Hazy IPA, Pale Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-new-world-saison-escarpment-labs', 'New World Saison', 'ale', 'liquid', 'Escarpment Labs', NULL, 20.0, 25.0, 'medium', 80.0, 80.0, 80.0, '12', 'A new world Saison blend containing Saccharomyces and Brettanomyces to produce a fruity, funky beer with rustic charm. Brett character increases during aging. NOTE: the Saison yeast in this blend contains the STA1 gene, meaning it is a diastatic yeast. Many Saison yeasts are diastatic, due to the desire for very high attenuation levels. However extra care must be taken to ensure these yeasts do not cross-contaminate non-diastatic yeasts.', 'Saison', NULL, NULL, 0, 1),
  ('bm-yeast-m42-new-world-strong-ale-mangrove-jack', 'New World Strong Ale', 'ale', 'dry', 'Mangrove Jack', 'M42', 16.1, 22.2, 'very-high', 79.5, 77.0, 82.0, NULL, 'A top-fermenting ale strain suitable for many types of ales of all strengths.
Ferments with a neutral yeast aroma to ensure the full character of the malts and
hops are prominent in each beer.', 'IPA, Porters, Russian Imperial Stouts', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-gy001-norcal-ale-1-gigayeast', 'NorCal Ale #1', 'ale', 'liquid', 'GigaYeast', 'GY001', 17.8, 25.0, 'medium', 78.0, 76.0, 80.0, '11', 'Clean fermenting, versatile strain from one of the most famous California pale ales. Excellent for emphasizing hop flavor and aroma. Strong attenuation and good flocculation. ', 'Barley Wine, Pale Ale, Bitter, Scotch Ale, India Pale Ale, Stout', 'WY1056,WLP001,US-05,RVA-101,A07,OYL-004,BRY-97,M44,BBUSA1', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-gy029-norcal-ale-5-gigayeast', 'NORCAL ALE #5', 'ale', 'liquid', 'GigaYeast', 'GY029', 19.4, 23.9, 'medium-high', 71.0, 69.0, 73.0, NULL, 'Slightly more flocculant and less attenuative than GY001. Leaves a clear beer with slight residual sweetness. ', 'Brown, Porter, Amber, Pale, Stout', NULL, NULL, 0, NULL),
  ('bm-yeast-ecy43-nordic-farmhouse-east-coast-yeast', 'Nordic Farmhouse', 'ale', 'liquid', 'East Coast Yeast', 'ECY43', 32.2, 40.6, NULL, 80.5, 78.0, 83.0, NULL, 'igmund strain of Kveik yeast (Saccharomyces cerevisiae). Traditionally used in the production of Norwegian Farmhouse Ale yielding spicy orange peel flavor, particularly if underpitched.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy2272-north-american-lager-wyeast', 'North American Lager', 'lager', 'liquid', 'Wyeast', 'WY2272', 11.1, 14.4, 'high', 73.0, 70.0, 76.0, '9', 'A traditional culture of North American and Canadian lagers, light pilsners, and adjunct beers. Mildly malty profile, medium ester profile, well balanced. Malty finish.', 'Lager', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-ecy029-north-east-ale-east-coast-yeast', 'North East Ale', 'ale', 'liquid', 'East Coast Yeast', 'ECY29', 18.9, 22.2, 'medium-low', 81.0, 80.0, 82.0, '11', 'Replication of the famous Conan strand of yeast. Unique strand with an abundance of citrus esters accentuating American Style hops in and IPA, Double IPA, or strong ale.', 'IPA, Double IPA, Strong Ale', 'OYL-052,GY054,WLP4000,WLP095,A04,RVA-104,ES-VT,LB_NE', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp4015-northeastern-abbey-the-yeast-bay', 'Northeastern Abbey', 'ale', 'liquid', 'The Yeast Bay', 'WLP4015', 20.0, 23.9, 'medium-low', 79.0, 77.0, 81.0, '11', 'Northeastern Abbey is a strain of Saccharomyces cerevisiae isolated from a beer crafted by a well-known producer of Belgian-style ales in the Northeastern United States. This yeast produces a very mild spiciness and earthy character, complemented by a magnificent array of fruity esters, including pear and citrus fruit. Expect this yeast to produce a large, thick krausen.', NULL, NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy1332-northwest-ale-wyeast', 'Northwest Ale', 'ale', 'liquid', 'Wyeast', 'WY1332', 18.3, 23.9, 'high', 69.0, 67.0, 71.0, '10', 'One of the classic ale strains from a Northwest U.S. Brewery. It produces a malty and mildly fruity ale with good depth and complexity.', 'Pale Ale, IPA, Strong Ale, Brown Ale', 'WLP005, S-04', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-216-northwest-farmhouse-brett-omega-yeast', 'NORTHWEST FARMHOUSE BRETT', 'ale', 'liquid', 'Omega Yeast', 'OYL-216', 20.0, 26.7, 'low', 77.5, 70.0, 85.0, '10', 'Enjoy the lighter side of funkiness with this B. bruxellensis variant that hails from a Northwest U.S. brewery. It''s known for its wonderful white wine character and light funk, and develops its character rather quickly. Brett character will be apparent within a few weeks of reaching terminal gravity and will continue to develop if given additional conditioning time.', 'Farmhouse', NULL, 'Brettanomyces Bruxellensis', 0, NULL),
  ('bm-yeast-wy2633-octoberfest-lager-blend-wyeast', 'Octoberfest Lager Blend', 'lager', 'liquid', 'Wyeast', 'WY2633', 7.2, 14.4, 'medium-low', 75.0, 73.0, 77.0, '9', 'This blend of lager strains is designed to produce a rich, malty, complex and full bodied Octoberfest style beer. It attenuates well while leaving plenty of malt character and mouthfeel. This blend is low in sulfur production.', 'Festbier, Märzen, Vienna Lager, Rauchbier', 'OYL-107,WLP820,WLP830,RVA-303,WY2206,W-34/70,S-23', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-oyl-107-oktoberfest-omega-yeast', 'Oktoberfest', 'lager', 'liquid', 'Omega Yeast', 'OYL-107', 7.8, 14.4, 'medium-high', 75.0, 73.0, 77.0, '9', 'This strain is a slow fermenter but said to be worth the wait by fans of Märzenbier and Oktoberfest Lagers particularly. It facilitates a smooth, rich, balanced beer with full, malty profile. Make sure to give it a thorough diacetyl rest.', 'Lagers, Märzen', 'WLP820,WLP830,RVA-303,WY2633,WY2206,W-34/70,S-23', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-rva-303-oktoberfest-lager-rva-yeast-labs', 'Oktoberfest Lager', 'lager', 'liquid', 'RVA Yeast Labs', 'RVA-303', 11.1, 14.4, 'medium', 69.0, 65.0, 73.0, '12', 'This is a bock-style lager yeast that accentuates maltiness. ', 'Märzen, Oktoberfest, Bock, Lagers', 'OYL-107,WLP820,WLP830,WY2633,WY2206,W-34/70,S-23', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-wlp820-oktoberfest-marzen-lager-yeast-white-labs', 'Oktoberfest/Märzen Lager Yeast', 'lager', 'liquid', 'White Labs', 'WLP820', 11.1, 14.4, 'medium', 69.0, 65.0, 73.0, '11', 'This strain is ideal for producing malty lagers. Residual sweetness further helps promote malt nuances while contributing to a balanced finish. Great for lagers with a wide gravity range.', 'Märzen, Lagers', 'OYL-107,WLP830,RVA-303,WY2633,WY2206,W-34/70,S-23', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-wy9097-old-ale-blend-wyeast', 'Old Ale Blend', 'ale', 'liquid', 'Wyeast', 'WY9097', 20.0, 23.9, 'medium', 77.5, 75.0, 80.0, '14', 'To bring in a bit of English brewing heritage we developed the Old Ale blend. It includes an attenuative ale strain along with a small amount of Brettanomyces. The blend will ferment well in dark worts, producing fruity beers with nice complexity. The Brettanomyces adds a pie cherry-like flavor and sourness during prolonged aging.', 'Strong Ale, Barleywine, Old Ale', NULL, 'Saccharomyces cerevisiae, Brettanomyces', 0, NULL),
  ('bm-yeast-wlp920-old-bavarian-lager-yeast-white-labs', 'Old Bavarian Lager Yeast', 'lager', 'liquid', 'White Labs', 'WLP920', 10.0, 12.8, 'medium', 69.5, 66.0, 73.0, '11', 'From Southern Germany, this yeast finishes malty with a slight ester profile. Use in beers such as Oktoberfests,bocks, and dark lagers.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-ecy10-old-newark-ale-east-coast-yeast', 'Old Newark Ale', 'ale', 'liquid', 'East Coast Yeast', 'ECY10', 15.6, 20.0, 'high', 77.0, 76.0, 78.0, NULL, 'Sourced from a now defunct east coast brewery, this pure strain was identified as their ale pitching yeast. Good for all styles of American and English ales. Top fermenting, high flocculation with a solid sedimentation. Suggested fermentation temp: 60-68°F. Apparent Attenuation: 68-72% Resurrected from a freezed-dried deposit library, this pure strain of S. cerevisae is NOT the rumored Chico strain.  Rumored to be Ballantine.', 'American Ales, English Ales', NULL, NULL, 0, NULL),
  ('bm-yeast-old-world-saison-blend-escarpment-labs', 'Old World Saison Blend', 'ale', 'liquid', 'Escarpment Labs', NULL, 22.2, 26.7, 'medium-low', 85.0, 85.0, 85.0, '14', 'A characterful blend of two classic Saison strains. It produces complex fruit and black pepper notes along with a reliable, fast and high degree of attenuation. We strongly encourage a free rise fermentation, starting at 22C and rising to ~27C for optimal results. NOTE: One of the strains in this blend contains the STA1 gene, meaning it is a diastatic yeast. Many Saison yeasts are diastatic, due to the desire for very high attenuation levels. However extra care must be taken to ensure these yeasts do not cross-contaminate non-diastatic yeasts.', 'Saison', NULL, 'Saccharomyces cerevisiae', 0, 1),
  ('bm-yeast-ontario-farmhouse-ale-blend-escarpment-labs', 'Ontario Farmhouse Ale Blend', 'ale', 'liquid', 'Escarpment Labs', NULL, 22.2, 27.2, 'low', 80.0, 80.0, 80.0, '9', 'A combination of a rustic, earthy, fruity Saccharomyces strain we isolated from Ontario strawberries, with two subtly fruity and funky Brettanomyces strains isolated from Ontario wine barrels. A true expression of terroir. ', NULL, NULL, 'Saccharomyces cerevisiae, Brettanomyces', 0, NULL),
  ('bm-yeast-wlp518-opshaug-kveik-ale-yeast-white-labs', 'Opshaug Kveik Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP518', 25.0, 35.0, 'high', 75.0, 70.0, 80.0, '11', 'It is a clean fermenting yeast and has tolerated temperatures up to 95°F (35°C) while finishing fermentationwithin three to four days . The hop-forward, clean characteristics of this strain make it ideal for IPAs and pale ales.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-bbosl-oslo-bootleg-biology', 'OSLO', 'ale', 'liquid', 'Bootleg Biology', 'BBOSL', 23.9, 36.7, 'medium', 81.0, 76.0, 86.0, '9', 'OSLO is a modern take on traditional Norwegian farmhouse brewing cultures. OSLO can comfortably produce beautifully clean, lager-like beers at temperatures as high as 98F (37C) without noticeable off flavors. At the high end of fermentation temperature, beers can finish attenuating in as little as three days! This culture''s versatility and neutral flavor profile allows you to effortlessly produce most beer styles. Bootleg is the first yeast lab to release this unique Kveik-family culture sourced from a raw beer made by our good friends at Eik & Tid in Oslo, Norway.', 'Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy3209-oud-bruin-ale-blend-wyeast', 'Oud Bruin Ale Blend', 'ale', 'liquid', 'Wyeast', 'WY3209', 26.7, 29.4, 'varies', 75.0, 70.0, 80.0, '10', 'This exclusive sour blend is built for dark, malt-accented sour styles. Like 3763 Roeselare, it will create sharp acidity, but unlike 3763 it will leave the malt character intact, creating a balanced and complex end product. Excellent base for blending fruit in secondary (especially cherries or raspberries), and makes for an interesting Saison.', 'Sour Ale, Oud Bruin, Saison, Fruit Beer, ', NULL, 'Saccharomyces cerevisiae & Lactobacillus', 0, NULL),
  ('bm-yeast-wlp041-pacific-ale-yeast-white-labs', 'Pacific Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP041', 18.3, 20.0, 'high', 67.5, 65.0, 70.0, '9', 'Hailing from the Pacific Northwest, this strain is a mild ester producer while promoting malt character.This strain is a big ester producer, showcasing notes of cherry and apple. This strain''s characteristic lower', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-oyl-012-pacific-nw-ale-omega-yeast', 'PACIFIC NW ALE', 'ale', 'liquid', 'Omega Yeast', 'OYL-012', 18.3, 23.9, 'high', 69.0, 67.0, 71.0, '10', 'A strain from the Pacific NW, originally from the UK, the Pacific NW Ale strain presents a relatively neutral profile with notes of malt and light fruit that add depth of flavor. It is a healthy flocculator.', 'Ales', 'WY1332, WLP041', NULL, 0, NULL),
  ('bm-yeast-wy1764-rogue-pacman-yeast-wyeast', 'Pacman', 'ale', 'liquid', 'Wyeast', 'WY1764', 15.6, 22.2, 'medium-high', 75.0, 72.0, 78.0, '12', 'A versatile yeast strain from one of Oregon’s leading craft breweries. Pacman is alcohol tolerant, flocculent, attenuates well and will produce beers with little to no diacetyl. Very mild fruit complements a dry, mineral finish making this a fairly neutral strain. Pacman’s flavor profile and performance makes it a great choice for use in many different beer styles.', 'American Pale Ale, American Amber Ale, American Brown Ale, Brown Porter, Cream Ale, Irish Red Ale, Strong Scotch Ale, Dry Stout, American Stout, Russian Imperial Stout, American IPA, Imperial IPA, American Barleywine, Fruit Beer, Spice/Herb/or Vegetable Beer, Christmas/Winter Specialty Spice Beer, Other Smoked Beer, Wood-Aged Beer', 'A18,RVA-103', 'Saccharomyces cerevisae', 0, NULL),
  ('bm-yeast-rva-103-pacman-ale-rva-yeast-labs', 'Pacman Ale', 'ale', 'liquid', 'RVA Yeast Labs', 'RVA-103', 16.7, 22.2, 'medium-high', 76.0, 74.0, 78.0, '12', 'Originating from Rogue brewery in Newport, OR. Pacman is a very versatile yeast, and produces a dry, clean beer with little diacetyl and very mild esters. ', 'Pale Ale, Blonde Ale, American Wheat, Altbier, Amber Ale', 'WY1764,A18', 'Saccharomyces cerevisae', 0, NULL),
  ('bm-yeast-wlp4047-pakruojis-lithuanian-farmhouse-the-yeast-bay', 'Pakruojis Lithuanian Farmhouse', 'ale', 'liquid', 'The Yeast Bay', 'WLP4047', 23.9, 35.0, 'low', 95.0, 90.0, 100.0, '14', 'Pakruojis Lithuanian Farmhouse is a single strain of STA1+ Saccharomyces cerevisiae, isolated from a Lithuanian brewery. This yeast produces beer with a dry, crisp and silky mouthfeel, an ester profile of complex citrus fruit, and a balanced rustic earthiness with undertones of white peppercorn. This strain exhibits high diastatic activity.', NULL, NULL, 'Saccharomyces cerevisiae', 0, 1),
  ('bm-yeast-oyl-606-pediococcus-omega-yeast', 'PEDIOCOCCUS', 'ale', 'liquid', 'Omega Yeast', 'OYL-606', 20.0, 26.7, NULL, 0.0, 0.0, 0.0, NULL, 'This modestly hop tolerant Pedio strain produces a clean lactic tang over time. The strain can produce diacetyl so it is often paired with one or more Brett strains (to consume the diacetyl). While more hop tolerant than the Lacto Blend (OYL-605), IBUs over 5-10 IBU may inhibit souring. Souring time can vary depending on IBU level.', 'Farmhouse', NULL, 'Pediococcus brevis, plantarum', 0, NULL),
  ('bm-yeast-wy2007-pilsen-lager-wyeast', 'Pilsen Lager', 'lager', 'liquid', 'Wyeast', 'WY2007', 8.9, 13.3, 'medium', 73.0, 71.0, 75.0, '9', 'Wyeast 2007 is the classic American lager strain. This mild, neutral strain produces beers with a nice malty character and a smooth palate. It ferments dry and crisp with minimal sulfur or diacetyl. Beers from this strain exhibit the characteristics of the most popular lager in America.', 'American Lager, Lager, German Pils, Schwarzbier', 'WLP840', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-oyl-101-pilsner-i-omega-yeast', 'PILSNER I', 'lager', 'liquid', 'Omega Yeast', 'OYL-101', 8.9, 13.3, 'medium-high', 74.0, 72.0, 76.0, '9', 'Thought to be the H strain of the famous Plzen brewer, this lager strain has a dry and neutral taste profile and is gently malty with a lightly perceptible floral aroma. The first of the famous Czech strains inspiring America''s most famous light, brilliantly clear, golden lagers. Commonly produces sulfur during fermentation that clears during lagering. Watch out for diacetyl.', 'Lagers', 'WY2001, WLP800', NULL, 0, NULL),
  ('bm-yeast-oyl-108-pilsner-ii-omega-yeast', 'PILSNER II', 'lager', 'liquid', 'Omega Yeast', 'OYL-108', 10.0, 14.4, 'medium-high', 72.0, 70.0, 74.0, '9', 'Thought to be the D strain of the famous Pilsen brewer. With a dry and malty taste profile, it is the second of the famous Czech strains inspiring America''s most famous light, brilliantly clear, golden lagers.', 'Lagers', 'WY2278', NULL, 0, NULL),
  ('bm-yeast-wlp800-pilsner-lager-yeast-white-labs', 'Pilsner Lager Yeast', 'lager', 'liquid', 'White Labs', 'WLP800', 10.0, 12.8, 'medium-high', 74.5, 72.0, 77.0, '9', 'A classic pilsner strain from the Czech Republic, this strain produces a clean, crisp beer that''s somewhat drywith a malty finish.', NULL, 'WY2001', NULL, 0, NULL),
  ('bm-yeast-wy2001-pilsner-urquell-h-strain-wyeast', 'Pilsner Urquell H-Strain', 'lager', 'liquid', 'Wyeast', 'WY2001', 8.9, 13.3, 'medium-high', 74.0, 72.0, 76.0, '9', 'With a mild fruit and floral aroma this strain has a very dry and clean palate with a full mouthfeel and nice subtle malt character. It has a very clean and neutral finish.', 'Czech Lager', 'WLP800', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-a37-pog-imperial-yeast', 'POG', 'ale', 'liquid', 'Imperial Yeast', 'A37', 29.4, 37.8, 'high', 80.0, 75.0, 85.0, '10', 'Single isolate kveik known to produce huge tropical ester profile. After years of surviving in cold climates, this Kveik yeast is ready for the tropical lifestyle. When used at high temperatures, POG produces an extreme amount of tropical fruit aromas including pineapple and guava. At the lower end of the range, more delicate citrus, peach and kiwi aromas are noticeable. The beer style options are expansive for this yeast. Use it in a hazy/juicy IPA to complement the hops or use it in a sour fruited beer to maximize the extreme aromatics. POG likes to work fast at high fermentation temperatures. It is also strongly flocculent, which makes it great for a fast turnaround. This strain has demonstrated the need for higher wort dissolved oxygen (DO) levels than most ale strains. Target 20 ppm DO or set the oxygen regulator flow to ~50 higher than normal.
', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', 'A43, A44, A46', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-gy020-portland-hefe-gigayeast', 'PORTLAND HEFE', 'ale', 'liquid', 'GigaYeast', 'GY020', 17.8, 23.3, 'very-low', 78.0, 76.0, 80.0, '9', 'From the famous American Hefeweizen. Creates a delicious wheat beer with modest amounts of Banana and clove flavor ', 'American Wheat Beer, Weizenbock, Dunkelweizen, Hefeweizen', 'WLP320,WY1010,B44', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-lalvin-ec-1118-prise-de-mousse-wine', 'Prise de Mousse Wine Yeast', 'ale', 'liquid', 'Lallemand', 'EC-1118', 10.0, 30.0, 'medium-high', 85.0, 80.0, 90.0, '18', 'Lalvin EC-1118 is the perfect yeast for sparkling, fruity wines or to make cider. Ideal for low temperature fermentation and fast fermentation.

Lalvin EC-1118 (AKA Prise de Mousse / Saccharomyces bayanus) Champagne yeast is a low foaming, vigorous and fast fermenter good for both reds and whites. It is also ideal for ciders and sparkling wines. A very competitive yeast that will inhibit wild yeasts. It will restart stuck fermentations because of good alcohol and sulfite tolerance. EC-1118 yeast is a very neutral strain that will have very little effect on the varietal character of the grape. A popular strain that ferments fully and flocculates well producing compact lees. Good for cooler fermentations. Champagne, dry reds, whites, ciders and sparkling.', 'Wine, Cider, Champagne', NULL, 'Saccharomyces cerevisiae var. bayanus', 0, NULL),
  ('bm-yeast-a09-pub-imperial-yeast', 'Pub', 'ale', 'liquid', 'Imperial Yeast', 'A09', 20.6, 23.3, 'very-high', 67.0, 64.0, 70.0, '10', 'Beloved and highly flocculent British ale strain. Well suited for a variety of beer styles. Brewers swear by this strain to achieve super bright ales in a short amount of time. One of the most flocculent brewer''s strains around, Pub will rip through fermentation and then drop out of the beer quickly. Pub produces higher levels of esters than most domestic ale strains, making it an excellent choice for when balance between malt and yeast derived esters is necessary. Be sure to give beers made with Pub a sufficient diacetyl rest.
', 'Extra Special Bitter, English IPA, English Mild, Bitter, Old Ale, Winter Seasonal Beer, American Pale Ale, Stout, Irish Dry, Brown Porter, Irish Red Ale, Stout, Oatmeal, British Strong Ale, English Barleywine, Cream Ale, American Wheat Beer, Blonde Ale, California Common, American Amber Ale, American Brown Ale, American IPA, Black IPA, Hazy IPA, Red Ale, American Pale Ale, Robust Porter, American Stout, Winter Seasonal Beer, Imperial IPA, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine', 'A01, WLP002, WY1068', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-gy077-quebec-abbey-ale-gigayeast', 'QUEBEC ABBEY ALE', 'ale', 'liquid', 'GigaYeast', 'GY077', 20.0, 26.7, 'medium', 81.0, 79.0, 83.0, NULL, 'From one of the first breweries in North America to create a successful line of traditional Abbey style ales. This Belgian ale yeast creates a malt forward beer with subtle fruity esters and a very small amount of clove notes ', 'Belgian Ale, Dubbel, Belgian Strong, Tripel, Biere De Garde', NULL, NULL, 0, NULL),
  ('bm-yeast-wy1187-ringwood-ale-wyeast', 'Ringwood Ale', 'ale', 'liquid', 'Wyeast', 'WY1187', 17.8, 23.3, 'high', 70.0, 68.0, 72.0, '10', 'A top cropping yeast strain with unique fermentation and flavor characteristics. Expect distinct fruit esters with a malty, complex profile. Flocculation is high, and the beer will clear well without filtration. A thorough diacetyl rest is recommended after fermentation is complete. This strain can be a slow starter and fermenter.', 'Porter, Brown Ale, Stout, IPA', 'S-33, WLP005', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy2105-rocky-mountain-lager-wyeast', 'Rocky Mountain Lager', 'lager', 'liquid', 'Wyeast', 'WY2105', 8.9, 13.3, 'medium-high', 72.0, 70.0, 74.0, '9', 'A lager yeast said to be born high in the Colorado Rockies, this strain ferments well at cooler temperatures and is perfect for all North American Lagers, light pilsners, and adjunct beers. 2105-PC will create well-balanced beers with a mild malty profile, medium esters, and an emphasis on the malt finish.', 'Lager, German Pils', NULL, NULL, 0, NULL),
  ('bm-yeast-wy3763-roeselare-ale-blend-wyeast', 'Roeselare Ale Blend', 'ale', 'liquid', 'Wyeast', 'WY3763', 18.3, 29.4, 'varies', 80.0, 80.0, 80.0, '11', 'Our blend of lambic cultures produce beer with a complex, earthy profile and a distinctive pie cherry sourness. Aging up to 18 months is required for a full flavor profile and acidity to develop. Specific proportions of a Belgian style ale strain, a sherry strain, two Brettanomyces strains, a Lactobacillus culture, and a Pediococcus culture produce the desirable flavor components of these beers as they are brewed in West Flanders. Propagation of this culture is not recommended and will result in a change of the proportions of the individual components. This blend will produce a very dry beer due to the super-attenuative nature of the mixed cultures.', 'Lambic, Flanders Red Ale', NULL, 'Saccharomyces cerevisiae, Brettanomyces, Lactobacillus, & Pediococcus', 0, NULL),
  ('bm-yeast-b56-rustic-imperial-yeast', 'Rustic', 'ale', 'liquid', 'Imperial Yeast', 'B56', 20.0, 26.7, 'medium', 74.0, 72.0, 76.0, '12', 'Fantastic choice for a Belgian saison or farmhouse beer. This unique yeast can be used in your saison, farmhouse ale, or other Belgian styles where high ester levels are important. Rustic typically produces a lot of bubblegum and fruity/juicy aromas that compliment complex maltiness. Balanced by a light clove phenol profile, Rustic produces lovely flavor profiles indicative of those classic Belgain styles known and loved. 

This strain tests positive for the STA1 gene via PCR analysis and is therefore considered to be Saccharomyces cerevisiae var. diastaticus ', 'Saison, Blonde Ale, Bière de Garde', 'WY3726', 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-bb22204-s-arlingtonesis-bootleg-biology', 'S. arlingtonesis', 'ale', 'liquid', 'Bootleg Biology', 'BB22204', 12.8, 20.0, 'high', 90.5, 88.0, 93.0, '9', 'This culture ferments extremely clean in the 50''sF (lagers) & 60''sF (Kolsch and Lager hybrids), and has subtle fruity/citrus esters in the higher end of the Ale fermentation range (wheat-centric beers). May produce sulfur aromas during primary fermentation, but those will be eliminated within a couple weeks (allow longer aging if fermenting at lower temperatures). S. arlingtonesis is a higher attenuator than most ale strains, so adjustments made need to be made to grain bills or mash temperatures if a drier beer is not preferred.', 'Ales, Kolsch, Lager', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp644-saccharomyces-bruxellensis-trois-white-labs', 'Saccharomyces "Bruxellensis" Trois', 'ale', 'liquid', 'White Labs', 'WLP644', 21.1, 29.4, 'low', 85.0, 85.0, 85.0, '11', 'This Belgian strain, traditionally used for wild yeast fermentations, produces a slightly tart beer with delicate mango and pineapple characteristics.', 'Sours, Farmhouse Ale', 'A20', 'Saccharomyces Trois', 0, 1),
  ('bm-yeast-be-134-safale-be-134-fermentis', 'SafAle BE-134', 'ale', 'dry', 'Fermentis', 'BE-134', 17.8, 27.8, 'low', 91.0, 89.0, 93.0, '11', 'This typical brewer''s yeast strain is recommended for well-attenuated beers, produces fruity, floral and phenolic notes and a dry character. Produces highly refreshing beers, it is ideal for Belgian-Saison style.', 'Saison', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-be-256-safale-be-256-fermentis', 'SafAle BE-256', 'ale', 'dry', 'Fermentis', 'BE-256', 15.0, 20.0, 'high', 84.0, 82.0, 86.0, '11', 'Active dry brewer''s yeast recommended to ferment a diversity of Belgian type beers such as abbey style known for its fruitiness and high alcohol content. It ferments very fast and reveals strong fermentation aromas. To maintain the aromatic profile at the end of the fermentation, we do recommend to crop this yeast as soon as possible after fermentation', 'Belgian Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-f-2-safale-f-2-fermentis', 'SafAle F-2', 'ale', 'dry', 'Fermentis', 'F-2', 15.0, 25.0, NULL, 0.0, 0.0, 0.0, '12', 'SafAle™ F-2 brewing yeast has been selected specifically for secondary fermentation in bottle and in cask. This yeast assimilates very little amount of maltotriose but assimilates basic sugars (glucose, fructose, saccharose, maltose). It is characterized by a neutral aroma profile respecting the base beer character and settles very homogeneously at the end of fermentation.', 'Cask', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-k-97-safale-k-97-fermentis', 'SafAle K-97', 'ale', 'dry', 'Fermentis', 'K-97', 15.0, 20.0, 'low', 82.0, 80.0, 84.0, '11', 'German ale brewer''s yeast producing subtle fermentation character. Depending on the conditions tend to present floral and balanced fruity character. Ideal for delicate beers such as German Kolsch beers, Belgian Wits and some versions of Session Beers. Suitable for heavily hopped beers and has ability to form a large firm head when fermenting.', NULL, NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-s-04-safale-s-04-fermentis', 'SafAle S-04', 'ale', 'dry', 'Fermentis', 'S-04', 18.3, 21.1, 'medium-high', 78.0, 74.0, 82.0, '11', 'English ale brewer''s yeast selected for its fast fermentation profile. Produces balanced fruity and floral notes. Due to its flocculation power, tends to produce beers with higher clarity. Ideal for a large range of American and English Ales - including highly hopped beers - and is specially adapted to cask-conditioned and beers fermented in cylindro-conical tanks.', 'Ales', 'WY1099, A01, WLP007,', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-s-33-safale-s-33-fermentis', 'SafAle S-33', 'ale', 'dry', 'Fermentis', 'S-33', 15.0, 20.0, 'medium', 70.0, 68.0, 72.0, '11', 'Fruity driven strain, gives a high mouthfeel and body to the beer. Ideal for Belgian Ales (Blond, Dubbel, Tripel, Quadrupel Styles) and strong English ales (ex. Imperial Stouts). It is also ideal for New England IPA''s. Yeast with a medium sedimentation: forms no clumps but a powdery haze when resuspended in the beer.', NULL, 'WLP006', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-t-58-safbrew-t-58-fermentis', 'SafAle T-58', 'ale', 'dry', 'Fermentis', 'T-58', 15.0, 23.9, 'medium', 75.0, 73.0, 77.0, '11', 'Specialty brewer''s yeast selected for its strong fermentation character, intense fruity and phenolic flavors - especially banana, clove and peppery notes. Suitable for a great variety of wheat-base beers and fruity-spicy oriented styles. Yeast with a medium sedimentation: forms no clumps but a powdery haze when resuspended in the beer.
', 'Hefeweizen, Weissbier, Witbier', 'WY3724, WLP565', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-us-05-safale-us-05-fermentis', 'SafAle US-05', 'ale', 'dry', 'Fermentis', 'US-05', 15.0, 20.0, 'medium-low', 75.0, 72.0, 78.0, '11', 'American ale brewer''s yeast producing neutral and well-balanced ales, clean and crispy. Forms a firm foam head and presents a very good ability to stay in suspension during fermentation. Ideal for American beer types and highly hopped beers.
', 'Ales, Pale Ale, IPA', 'WY1056,WLP001,RVA-101,A07,OYL-004,BRY-97,M44,BBUSA1,GY001', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wb-06-safbrew-wb-06-fermentis', 'SafAle WB-06', 'ale', 'dry', 'Fermentis', 'WB-06', 17.8, 23.9, 'low', 88.0, 86.0, 90.0, '11', 'Brewer''s yeast providing fruity and phenolic character, varying with the fermentation conditions. Produces well-attenuated beers and it is ideal for wheat base beers, such as Belgian and German Styles (Ex. Wit Beers and Weizen Beers). Produces typical phenolic notes of wheat beers. Allows to brew beer with a high drinkability profile and presents a very good ability to suspend during fermentation.', 'Hefeweizen, Weissbier, Witbier', 'GY107,OYL-021,OYL-022,WLP300,WLP380,WY3068,WY3333,G01,T-58,M20', 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-da-16-safbrew-da-16-fermentis', 'SafBrew DA-16', 'ale', 'dry', 'Fermentis', 'DA-16', 20.0, 31.7, 'medium', 100.0, 98.0, 102.0, '16', 'SafBrew DA-16 is a powerful solution (consisting of Active Dry Yeast and enzymes) for the production of very dry and flavorful beers, particularly fruity and hoppy ones such as Brut IPAs. SafBrew™ DA-16 is also recommended for very high gravity wort, allowing a level of alcohol up to 16% ABV.', 'Brut IPA, IPA', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-ha-18-safbrew-ha-18-fermentis', 'SafBrew HA-18', 'ale', 'dry', 'Fermentis', 'HA-18', 25.0, 35.0, 'low', 100.0, 98.0, 102.0, '18', 'This product is a blend of active dry yeast and enzymes.  SafBrew HA-18 is a powerful solution (consisting of POF+ Active Dry Brewer''s Yeast and enzymes) for the production of high-gravity and particularly high alcoholic beers - such as strong ales, barley wines and barrel aged beers with very high density. It has a very good resistance to osmotic pressure and high fermentation temperatures (thermotolerant yeast).

Ingredients: Yeast (Saccharomyces cerevisiae), Maltodextrin, Glucoamylase from Aspergillus niger (EC3.2.1.3), Emulsifier E491 (Sorbitan monostearate)', 'Strong Ales, Barleywine', NULL, 'Saccharomyces cerevisiae', 1, NULL),
  ('bm-yeast-la-01-safbrew-la-01-fermentis', 'SafBrew LA-01', 'ale', 'dry', 'Fermentis', 'LA-01', NULL, NULL, NULL, 15.0, 15.0, 15.0, NULL, 'SafBrew LA-01, is a Saccharomyces cerevisiae var. chevalieri that has been specifically selected for the production of low and/or non-alcoholic beverages (<0.5ABV). This yeast does not assimilate maltose and maltotriose but assimilates simple sugars (glucose, fructose and sucrose) and is characterized by a subtle aroma profile. Yeast with a medium sedimentation: forms no clumps but a powdery haze when resuspended in the beer.', 'Non-Alcoholic', NULL, 'Saccharomyces cerevisiae var. chevalieri)', 0, NULL),
  ('bm-yeast-s-189-saflager-s-189-fermentis', 'SafLager S-189', 'lager', 'dry', 'Fermentis', 'S-189', 12.2, 15.0, 'high', 82.0, 80.0, 84.0, '11', 'Originating from the Hürlimann brewery in Switzerland. This lager yeast strain''s profile allows to brew fairly neutral flavor beers with a high drinkability. Depending on the conditions, it tends to present noticeable herbal and floral notes to lager beers.', 'Lagers', 'WLP885', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-s-23-saflager-s-23-fermentis', 'SafLager S-23', 'lager', 'dry', 'Fermentis', 'S-23', 12.2, 15.0, 'high', 82.0, 80.0, 84.0, '11', 'Bottom fermenting brewer’s yeast originating from Berlin in Germany. It’s recommended for the production of fruitier and more estery lagers. Its profile gives beers with a good length on the palate.', 'Lagers, Märzen', 'OYL-107,WLP820,WLP830,RVA-303,WY2633,WY2206,W-34/70', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-w-34-70-saflager-w-34-70-fermentis', 'SafLager W-34/70', 'lager', 'dry', 'Fermentis', 'W-34/70', 12.2, 15.0, 'high', 82.0, 80.0, 84.0, '11', 'This famous brewer''s yeast strain from Weihenstephan in Germany is used world-wide within the brewing industry. SafLager W-34/70 allows the brewing of beers with a good balance of floral and fruity aromas and gives clean flavors and high drinkable beers.', 'Lagers, Märzen', 'OYL-107,WLP820,WLP830,RVA-303,WY2633,WY2206,S-23,WL2124', 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-lp-652-safsour-lp-652-fermentis', 'SafSour LP 652', 'ale', 'dry', 'Fermentis', 'LP 652', NULL, NULL, NULL, 0.0, 0.0, 0.0, NULL, 'tropical, citrus, fruity', 'Sours', NULL, 'Lactobacillus plantarum', 0, NULL),
  ('bm-yeast-gy018-saison-1-gigayeast', 'SAISON #1', 'ale', 'liquid', 'GigaYeast', 'GY018', 17.8, 26.7, 'low', 82.0, 81.0, 83.0, NULL, 'Traditional Saison yeast from a French craft brewery. Strong attenuator that produces a dry beer with a beautiful fragrance and the traditional Saison taste of fruit and pepper. ', 'Saison, Farmhouse Ale, Belgian Ale, Biere De Garde', NULL, NULL, 0, NULL),
  ('bm-yeast-gy027-saison-2-gigayeast', 'SAISON #2', 'ale', 'liquid', 'GigaYeast', 'GY027', 17.8, 26.7, 'low', 81.0, 79.0, 83.0, NULL, 'From a traditional farmhouse saison. Produces a nice fruity nose and finishes slightly sweeter than GY018. ', 'Saison, Farmhouse Ale, Belgian Ale, Biere De Garde', 'Lallemand Belle Saison, WLP565, WY3724', NULL, 0, 0),
  ('bm-yeast-gy047-saison-blend-gigayeast', 'SAISON BLEND', 'ale', 'liquid', 'GigaYeast', 'GY047', 17.8, 26.7, 'low', 81.5, 80.0, 83.0, NULL, 'This Blend is a super robust attenuator that produces a complex flavor profile of fruit and spice. ', 'Belgian, Witbier, Belgian Pale Ale', NULL, NULL, 0, NULL),
  ('bm-yeast-wlp4007-saison-blend-the-yeast-bay', 'Saison Blend', 'ale', 'liquid', 'The Yeast Bay', 'WLP4007', 22.2, 27.8, 'medium-low', 81.0, 78.0, 84.0, '14', 'A blend of two unique Saccharomyces cerevisiae strains (one being STA1+) isolated from beers that embody the saison style, this blend is a balance of the many classic saison flavors and aromas. One yeast strain is a good attenuator that produces a spicy and mildly tart and tangy beer with a full mouthfeel, the other a good attenuator that produces a delightful ester profile of grapefruit and orange zest. This blend exhibits very low diastatic activity.', NULL, NULL, 'Brettanomyces, Saccharomyces cerevisiae', 0, 1),
  ('bm-yeast-wlp4021-saison-blend-ii-the-yeast-bay', 'Saison Blend II', 'ale', 'liquid', 'The Yeast Bay', 'WLP4021', 20.0, 26.7, 'medium', 92.5, 85.0, 100.0, '14', 'This blend contains two saison-style Saccharomyces cerevisiae isolates (Wallonian Farmhouse II and Wallonian Farmhouse III) and two Brettanomyces bruxellensis cultures (TYB184, TYB207).  This unique combination will produce a beer that is bursting with classic saison esters and earthiness, with a rustic kick of Brettanomyces fruitiness and funkiness.', NULL, NULL, 'Brettanomyces bruxellensi, Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-ecy08-saison-brasserie-blend-east-coast-yeast', 'Saison Brasserie Blend', 'ale', 'liquid', 'East Coast Yeast', 'ECY08', 23.9, 29.4, NULL, 80.0, 80.0, 80.0, NULL, 'A combination of several Saison yeasts for both fruity and spicy characteristics accompanied by dryness. Apparent Attenuation: up to 80%. Suggested fermentation temp: 75-85° F. ', 'Saison', NULL, NULL, 0, NULL),
  ('bm-yeast-saison-mason-escarpment-labs', 'Saison Maison', 'ale', 'liquid', 'Escarpment Labs', NULL, 22.2, 26.7, 'medium-low', 80.0, 80.0, 80.0, '11', 'This is a non-diastatic yeast isolated from a Belgian Saison. This is quite unique in the saison yeast world, as most saison yeasts contain the STA1 glucoamylase gene, resulting in extremely dry beers. This yeast is suitable for breweries who want to produce authentic Saisons but who are put off by the risk of diastatic yeasts. Saison Maison attenuates in a manner similar to many workhorse ale strains like Cali Ale. To produce an ultra-dry beer, amyloglucosidase enzyme products are recommended as an addition mid-ferment. We also recommend fermenting hot (up to 35ºC) and dosing additional oxygen.', 'Saison', NULL, NULL, 0, 1),
  ('bm-yeast-bbx0104-saison-parfait-bootleg-biology', 'Saison Parfait', 'ale', 'liquid', 'Bootleg Biology', 'BBX0104', 18.3, 29.4, 'medium-low', 95.0, 90.0, 100.0, '9', 'Saison Parfait pairs classic pepper & spice saison phenolics with prominent juicy fruit esters that evoke citrus and lemon peel, and a touch of banana for complexity. Even more unique, it finishes with a balanced, full-bodied and silky mouthfeel despite its high attenuation. 

Saison Parfait means the “Perfect Season”, and is our ode to the fall harvest season. A time for hard work and also celebration. The peasants of rural Flanders and Wallonia created the Saison, and what we now call Farmhouse beers, to drink for sustenance and merriment. Bruegel likely depicted the drinking of Saison beer in his classic paintings of rural country life, “The Harvesters” and “Peasant Wedding”.', 'Saison', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-gb124-saison-sour-gigayeast', 'SAISON SOUR', 'ale', 'liquid', 'GigaYeast', 'GB124', 20.0, 26.7, NULL, 78.0, 78.0, 78.0, NULL, 'Sour with fruity esters and black pepper ', 'Sour Beer, Saison, Wild Specialty Beer, Flanders Red Ale, Oud Bruin, Lambic, Gueze, Fruit Lambic', NULL, NULL, 0, NULL),
  ('bm-yeast-wy3031-saison-brett-blend-wyeast', 'Saison-Brett Blend', 'ale', 'liquid', 'Wyeast', 'WY3031', 18.3, 26.7, 'low', 85.0, 80.0, 90.0, '12', 'A blend of two saison strains and Brettanomyces creates a dry and complex ale. Classic earthy and spicy farmhouse character meets tropical and stone fruit esters. Aging brings elevated Brett flavor. Expect high attenuation with this blend.', 'Saison, Brett, Sour Ale, Belgian Strong Ale', NULL, 'Saccharomyces cerevisiae var. diastaticus, Brettanomyces', 0, 1),
  ('bm-yeast-wlp4626-saison-brettanomyces-blend-the-yeast-bay', 'Saison/Brettanomyces Blend', 'ale', 'liquid', 'The Yeast Bay', 'WLP4626', 21.1, 25.6, 'medium-low', 90.0, 80.0, 100.0, '14', 'This blend combines one of the Saccharomyces cerevisiae strains from the Saison Blend and two unique Brettanomyces isolates from our yeast library. The Saccharomyces strain is a strong attenuator that produces a delightful ester profile of grapefruit and orange zest and imparts a long, dry and earthy finish to the beer. The Brettanomyces strains are both good attenuators that produce some fruity esters and mild funk, and add a bright character to the beer. The resulting beer is dry with balanced ester and phenolic character.', NULL, NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp4636-saison-brettanomyces-blend-ii-the-yeast-bay', 'Saison/Brettanomyces Blend II', 'ale', 'liquid', 'The Yeast Bay', 'WLP4636', 22.2, 26.7, 'medium-low', 87.5, 85.0, 90.0, '14', 'This blend contains two saison-style Saccharomyces cerevisiae isolates (Wallonian Farmhouse II and Wallonian Farmhouse III) and two Brettanomyces bruxellensis cultures (TYB184, TYB207).  This unique combination will produce a beer that is bursting with classic saison esters and earthiness, with a rustic kick of Brettanomyces fruitiness and funkiness.', NULL, NULL, 'Saccharomyces cerevisiae, Brettanomyces bruxellensis', 0, NULL),
  ('bm-yeast-oyl-500-saisonsteins-monster-omega-yeast', 'SAISONSTEIN''S MONSTER', 'ale', 'liquid', 'Omega Yeast', 'OYL-500', 18.3, 25.6, 'low', 85.0, 80.0, 90.0, '11', 'An Omega-original, genetic hybrid of two Saison strains (French (OYL-026) and Belgian I (OYL-027)), Saisonstein''s Monster is versatile, aromatic and attenuative with a silky mouthfeel. Excels in high gravity, ferments more reliably and thoroughly than its parents, and is spicy, complex, tart, dry and crisp. Some bubblegum from the Belgian, more fruit and fewer phenolics than the French.', 'Saison', 'WLP566, WY3724', 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-wlp090-san-diego-super-ale-yeast-white-labs', 'San Diego Super Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP090', 18.3, 20.0, 'medium-high', 79.5, 76.0, 83.0, '14', 'A low ester producing strain, it''s known for quick fermentations and producing a neutral flavor and aromaprofile. Due to high attenuation, this strain produces very dry beers with increased perceived bitterness.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-wlp810-san-francisco-lager-yeast-white-labs', 'San Francisco Lager Yeast', 'lager', 'liquid', 'White Labs', 'WLP810', 14.4, 18.3, 'high', 67.5, 65.0, 70.0, '11', 'A unique lager strain because it can ferment at a wide range of temperatures while retaining lager-like characteristics.This strain is traditionally used to brew the California common or steam beer styles.', NULL, 'WY2112', NULL, 0, NULL),
  ('bm-yeast-gy044-scotch-ale-1-gigayeast', 'SCOTCH ALE #1', 'ale', 'liquid', 'GigaYeast', 'GY044', 17.8, 23.9, 'medium-low', 81.0, 80.0, 82.0, NULL, 'Neutral flavors that emphasize maltiness. Perfect in Stouts, Porters, Scottish Ales and Wee Heavys. ', 'Scotch Ale, Pale, Wee Beavy, Brown, Porter, Stout', 'A31, WLP028, WY1728', NULL, 0, NULL),
  ('bm-yeast-oyl-015-scottish-ale-omega-yeast', 'SCOTTISH ALE', 'ale', 'liquid', 'Omega Yeast', 'OYL-015', 17.2, 23.9, 'high', 74.5, 73.0, 76.0, '10', 'The Scottish Ale strain is a flocculent, versatile and reliable house strain that produces neutral to complex and malty profiles in its fairly wide temperature range. Hop character is not muted by this strain. More esters emerge at higher fermentation temperatures.', 'Ales, British Ales', 'WY1728, WLP028', NULL, 0, NULL),
  ('bm-yeast-wy1728-scottish-ale-wyeast', 'Scottish Ale', 'ale', 'liquid', 'Wyeast', 'WY1728', 12.8, 23.9, 'high', 71.0, 69.0, 73.0, '12', 'Our Scottish ale strain is ideally suited for the strong, malty ales of Scotland. This strain is very versatile, and is often used as a House strain as it ferments neutral and clean. Higher fermentation temperatures will result in an increased ester profile.', 'Scottish Ales, Wee Heavy, Stout, Double IPA, Barleywine', 'WLP028, A31, GY044', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-ecy07-scottish-heavy-east-coast-yeast', 'Scottish Heavy', 'ale', 'liquid', 'East Coast Yeast', 'ECY07', 15.6, 20.0, NULL, 78.5, 77.0, 80.0, NULL, 'Leaves a fruity profile with woody, oak esters reminiscent of malt whiskey. Well suited for 90/shilling or heavier ales including old ales and barleywines due to level of attenuation (77-80%) - recommend a dextrinous wort. Suggested fermentation temp: 60-68°F. ', 'Scottish Ales, Stouts, Old Ales', NULL, NULL, 0, NULL),
  ('bm-yeast-wlp4045-sigmund-s-voss-kveik-the-yeast-bay', 'Sigmund''s Voss Kveik', 'ale', 'liquid', 'The Yeast Bay', 'WLP4045', 21.1, 37.8, 'high', 80.5, 78.0, 83.0, '7', 'Sigmund''s Voss Kveik yeast is a single strain of Saccharomyces cerevisiae isolated from a sample of kveik generously provided by Sigmund Gjernes via Lars Garshol. This strain exhibits the ability to ferment wort over a large temperature range with a consistent ester profile and no production of any harsh phenolics or fusel alcohols. ', 'IPA, Pale Ales, Ales', 'Lallebrew Voss, OYL-061', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp4045-sigmunds-voss-kveik-the-yeast-bay', 'Sigmund''s Voss Kveik', 'ale', 'liquid', 'The Yeast Bay', 'WLP4045', 21.1, 37.8, 'high', 80.5, 78.0, 83.0, '7', 'Sigmund''s Voss Kveik yeast is a single strain of Saccharomyces cerevisiae isolated from a sample of kveik generously provided by Sigmund Gjernes via Lars Garshol. This strain exhibits the ability to ferment wort over a large temperature range with a consistent ester profile and no production of any harsh phenolics or fusel alcohols. ', 'IPA, Pale Ales, Ales', 'Lallebrew Voss, OYL-061', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp4046-simonaitis-lithuanian-farmhouse-the-yeast-bay', 'Simonaitis Lithuanian Farmhouse', 'ale', 'liquid', 'The Yeast Bay', 'WLP4046', 23.9, 35.0, 'high', 79.0, 76.0, 82.0, '14', 'This culture is a single strain of Saccharomyces cerevisiae, isolated from a Lithuanian Farmhouse mixed culture kindly provided by Julius Simonaitis via Lars Garshol. Across a wide temperature range this culture will throw a potent mix of orange, tropical fruit and stone fruit esters that is reminiscent of POG Juice® (passionfruit, orange, guava) accompanied by distinct spicy, earthy and herbal undertones.', NULL, NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-skare-kveik-escarpment-labs', 'Skare Kveik', 'ale', 'liquid', 'Escarpment Labs', NULL, 17.8, 30.0, 'low', 76.0, 76.0, 76.0, '7', 'The Skare Kveik (sourced from Gunnar Skare; actually pronounced "scar-uh") has gained a reputation in homebrew circles for quick and somewhat more neutral flavour profile. This blend of four isolates from Skare selects the best of the bunch and this blend can be used to produce clean beers quickly, including the recently popular "kveik lagers". ', 'Lagers', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-f08-sour-batch-kidz-imperial-yeast', 'Sour Batch Kidz', 'ale', 'liquid', 'Imperial Yeast', 'F08', 20.0, 24.4, 'low', 87.5, 80.0, 95.0, '12', 'An exclusive funky blend containing a low attenuating Belgian saison yeast, Lacto, and three Brett yeast strains. This blend is great for emulating lambics, Flanders reds, sour farmhouse ales and any other brew you would like to funk up. Keep your IBU''s under 3 to allow the lacto to work. Considering the components of this blend, allow for a long conditioning period of at least 6 months to really let the brett strains to shine. This blend contains a strain that tests positive for the STA1 gene via PCR analysis and is therefore considered to be Saccharomyces cerevisiae var. diastaticus.', 'Flanders Red Ale, Lambic, Oud Bruin, Gueuze', NULL, 'Brettanomyces, Lactobacillus, Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-gb150-sour-cherry-funk-gigayeast', 'SOUR CHERRY FUNK', 'ale', 'liquid', 'GigaYeast', 'GB150', 20.0, 26.7, NULL, 70.0, 51.0, 89.0, NULL, 'This blend creates an amazing complex, sour beer with fruity cherry esters.', 'Saison, Sour Beer, Brett Beer', NULL, NULL, 0, NULL),
  ('bm-yeast-gb123-sour-plum-belgian-gigayeast', 'SOUR PLUM BELGIAN', 'ale', 'liquid', 'GigaYeast', 'GB123', 20.0, 26.7, NULL, 77.0, 77.0, 77.0, NULL, 'Belgian ale yeast and lactic acid bacteria. Cleaner than GB121. Creates a beer with stone fruit/plum esters and sour notes.', 'Saison, Sour Beer, Lambic', NULL, NULL, 0, NULL),
  ('bm-yeast-bbxss-sour-solera-blend-bootleg-biology', 'Sour Solera Blend', 'ale', 'liquid', 'Bootleg Biology', 'BBXSS', 18.3, 23.9, 'medium', 98.0, 96.0, 100.0, '9', 'Sour Solera Blend contains a unique and complex collection of Saccharomyces, Brettanomyces, Lactobacillus, Pediococcus and other funky yeast and souring bacteria pulled from an active fermentation. This blend can sour in a matter of months at 70ºF or higher, or if you prefer a more prolonged fermentation, use large amounts of aged hops and/or ferment and hold at temperatures below 70ºF. This blend is available seasonally, and will always be changing and evolving due to the nature of solera fermentations. Warning: No two Sour Solera Blend releases will be the same, and neither will their fermentations.', 'Sours', NULL, 'Saccharomyces, Brettanomyces, Lactobacillus, Pediococcus', 0, NULL),
  ('bm-yeast-bbxswl-sour-weapon-l-bootleg-biology', 'Sour Weapon L', 'ale', 'liquid', 'Bootleg Biology', 'BBXSWL', 28.9, 36.7, 'low', 0.0, 0.0, 0.0, '7', 'If you''re looking to drop the pH of wort as quickly and low as possible, Sour Weapon L is your go to Lacto blend. At 98F, we''ve had trial batches drop the pH of wort to 3.0 after just 24 hours. When pitched at 84F, pH should reach 3.5 in 24 hours. This is the ideal bacteria blend to use for acidifying wort for quick/kettle sours, and is also very effective when co-pitched with a yeast strain. As with any Lactobacillus culture, we recommend only using in wort with zero IBUs as even small amounts of hops may prevent significant souring.', 'Sours', NULL, 'Lactobacillus plantarum', 0, NULL),
  ('bm-yeast-bbx0089-sour-weapon-p-bootleg-biology', 'Sour Weapon P', 'ale', 'liquid', 'Bootleg Biology', 'BBX0089', 28.9, 36.7, 'low', 0.0, 0.0, 0.0, '9', 'We''re excited to release our first 100% Lactic Acid Bacteria souring blend! We chose this specific blend because of its ability to sour quickly and cleanly at a range of temperatures, and due to its mild hop tolerance.

While not “yeast”, this culture blend of two unique strains of Pediococcus pentosaceus is part of our LYP collection because it was sourced entirely from the wild: an anaerobic malt starter, and flowers from Murfreesboro, TN given to us by our good friend Art Whitaker. Perfect for quickly acidifying unhopped wort for kettle/”quick” sours or co-pitching with yeast. ', 'Sours', NULL, 'Pediococcus pentosaceus', 0, NULL),
  ('bm-yeast-sourvisiae-lallemand', 'Sourvisiae', 'ale', 'dry', 'Lallemand', NULL, 15.0, 22.2, 'medium-high', 77.5, 75.0, 80.0, NULL, 'Sourvisiae is a bioengineered ale yeast strain (Saccharomyces cerevisiae) capable of producing lactic acid during fermentation to provide brewers with an easy, reproducible, and mono-culture product for sour-style beer production. Sourvisiae contains a single genetic modification, a lactate dehydrogenase gene from a food microorganism, which enables the yeast to produce high levels of lactic acid, the main compound that gives sour beers their flavor. Sourvisiae allows the brewer to ferment and sour the beer in one simple step, reducing cross-contamination risks, lowering costs, cutting total process time, and allowing brewers to obtain a consistent product. The brewing process is conducted without any modifications; Sourvisiae is pitched just like conventional yeast and ferments in a normal fermentation time. Sourvisiae does not produce other flavor compounds associated with Brettanomyces, Lachancea, or Lactic Acid Bacteria, providing a cleaner and more reproducible souring process, with much shorter fermentation times.', 'Brett, Sour, Farmhouse', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp838-southern-german-lager-yeast-white-labs', 'Southern German Lager Yeast', 'lager', 'liquid', 'White Labs', 'WLP838', 10.0, 12.8, 'medium-high', 72.0, 68.0, 76.0, '9', 'This yeast is characterized by a malty finish, balanced aroma and great flocculation. It is a strong fermenter which produces slight sulfur and low diacetyl during fermentation. This strain benefits from a diacetyl rest and conditioning.', NULL, 'WY2308', NULL, 0, NULL),
  ('bm-yeast-spooky-saison-escarpment-labs', 'Spooky Saison', 'ale', 'liquid', 'Escarpment Labs', NULL, 25.0, -17.8, 'low', 85.0, 85.0, 85.0, '11', 'This is a non-diastatic yeast isolated from a Belgian Saison. This is quite unique in the saison yeast world, as most saison yeasts contain the STA1 glucoamylase gene, resulting in extremely dry beers. This yeast is suitable for breweries who want to produce authentic Saisons but who are put off by the risk of diastatic yeasts. Saison Maison attenuates in a manner similar to many workhorse ale strains like Cali Ale. To produce an ultra-dry beer, amyloglucosidase enzyme products are recommended as an addition mid-ferment. We also recommend fermenting hot (up to 35ºC) and dosing additional oxygen', 'Saison', NULL, 'Saccharomyces cerevisiae', 0, 1),
  ('bm-yeast-st-remy-abbey-ale-escarpment-labs', 'St-Remy Abbey Ale', 'ale', 'liquid', 'Escarpment Labs', NULL, 17.8, 23.9, 'medium', 76.0, 76.0, 76.0, '10', 'This yeast strain isolated from a Belgian abbey is an excellent choice for Belgian-style beers, including abbey ales. This strain produces mixed fruity esters, while also highlighting malt aroma. One of the rare non-phenolic Belgian strains, meaning it can be used for clean beers as well.', 'Belgian Ales', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-st-lucifer-belgian-ale-escarpment-labs', 'St. Lucifer Belgian Ale', 'ale', 'liquid', 'Escarpment Labs', NULL, 20.0, 24.4, 'medium', 77.5, 75.0, 80.0, '12', 'A high-character Belgian ale strain, able to produce high gravity beers with strong fruity and medium phenolic character. Excellent for strong golden ales and Tripels, but versatile for all Belgian ale applications. We recommend a free rise fermentation for this strain. NOTE: This strain contains the STA1 gene, meaning it is a diastatic yeast. Many industrial yeasts are diastatic, due to the desire for very high attenuation levels. However extra care must be taken to ensure these yeasts do not cross-contaminate non-diastatic yeasts.', 'Ales', NULL, NULL, 0, 1),
  ('bm-yeast-wy2782-staro-prague-lager-wyeast', 'Staro Prague Lager', 'lager', 'liquid', 'Wyeast', 'WY2782', 10.0, 14.4, 'medium', 72.0, 70.0, 74.0, '11', 'This yeast will help create medium to full body lagers with moderate fruit and bready malt flavors. The balance is slightly toward malt sweetness and will benefit from additional hop bittering. A fantastic strain for producing classic Bohemian lagers. ', 'Lager, Helles, Czech Lager, Marzen, Munich Dunkel, Bock', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-g01-stefon-imperial-yeast', 'Stefon', 'ale', 'liquid', 'Imperial Yeast', 'G01', 17.2, 22.8, 'low', 75.0, 73.0, 77.0, '10', 'Brewers love this traditional hefeweizen strain for any of their weizen beer needs! This is a traditional German hefeweizen strain used to produce world-class Weizen beers. Balanced with mild clove and prominent banana esters, this strain will produce amazing beers. Stefon produces a slightly higher level of acidity to give your beer a super crisp finish. Slightly underpitching will help increase the banana character.', 'Hefeweize, Weissbier, Weizenbock, Roggenbier', 'GY107,OYL-021,OYL-022,WLP300,WLP380,WY3068,WY3333,WB-06,T-58,M20', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-stirling-al-escarpment-labs', 'Stirling Ale', 'ale', 'liquid', 'Escarpment Labs', NULL, 13.9, 22.2, 'medium', 78.0, 72.0, 84.0, '14', 'This is a solid, well-rounded ale strain useful for a wide range of beers, from IPAs to big imperial stouts. This strain can ferment colder than many ale strains as well, yielding exceptionally clean beers. The temperature can be raised for higher ester production. Attenuation is highly responsive to wort fermentability. ', 'Lagers', NULL, 'Saccharomyces pastorianus', 0, NULL),
  ('bm-yeast-w15-suburban-brett-imperial-yeast', 'Suburban Brett', 'ale', 'liquid', 'Imperial Yeast', 'W15', 17.8, 23.3, 'low', 77.5, 75.0, 80.0, '12', 'Proprietary to Imperial, this brettanomyces strain produces lovely pie cherry and tropical aromas. Suburban Brett really shines when used in wood barrels and will produce complex and balanced aromas of sour cherry, dried fruit and balanced by a unique tropical fruit profile. It can be used for as a primary strain for brett only beers as well as a secondary aging strain. Maturation times tend to be on the quicker side for brett fermentations. ', 'Brett Beer, Flanders Red Ale, Lambic, Gueuze, Oud Bruin, Old Ale', NULL, 'Brettanomyces', 0, NULL),
  ('bm-yeast-wlp099-super-high-gravity-ale-yeast-white-labs', 'Super High Gravity Ale Yeast', 'ale', 'liquid', 'White Labs', 'WLP099', 18.3, 20.0, 'medium', 90.0, 80.0, 100.0, '18', 'From England, this yeast can ferment up to 25% alcohol. Produces dry beer. Ideal for beers aging forextended periods of time. Produces more esters with increasing gravity. Malt dominates at lower gravities.', 'Strong Ale, Oatmeal Stout', NULL, 'Saccharomyces cerevisiae var. diastaticus', 0, 1),
  ('bm-yeast-gy144-sweet-flemish-brett-gigayeast', 'Sweet Flemish Brett', 'ale', 'liquid', 'GigaYeast', 'GY144', 20.0, 23.9, 'low', 84.5, 84.0, 85.0, '12', 'Produces a sweet, slightly fruity profile with just a hint of barnyard and spicy phenolics. GB144 on its own to make an all Brett beer, or in a primary fermentation with an ale yeast for a complex blended profile or in a secondary to add character during aging. Recommended for use in Saison, Brett Beers, Sour Beers, or other experimental ales. This is a Belgian Strain which has at times been classified as Brettanomyces and other times classified as Sacchromyces. For example, White Labs names this strain (or similar variant) as Sacchromyces "Bruxellensis" Trois WL644. GigaYeast identifies it as a Brettanomyces Bruxellensis subspecies. The character is different from other Brett strains. The pineapple and tropical fruity esters lend it to use in ales outside the common Belgian Brett traditions. Bear in mind that it will attenuate much higher than a standard Sacchromyces yeast, a common trait of Brettanomyces.', 'Saison, Brett Beer, Sour Beer, IPAs and NEIPA', NULL, 'Brettanomyces bruxellensis', 0, NULL),
  ('bm-yeast-gb002-tart-cherry-brett-gigayeast', 'TART CHERRY BRETT', 'ale', 'liquid', 'GigaYeast', 'GB002', 20.0, 26.7, 'low', 77.5, 70.0, 85.0, '12', 'Produces some Brett Barnyard funk plus stone fruit and cherry-like esters. This Strain also produces a moderate amount of acid that adds a tart complexity to the brew.', 'Saison, Sour Beer, Lambic', NULL, 'Brettanomyces Bruxellensis', 0, NULL),
  ('bm-yeast-a31-tartan-imperial-yeast', 'Tartan', 'ale', 'liquid', 'Imperial Yeast', 'A31', 18.3, 21.1, 'medium', 72.5, 70.0, 75.0, '10', 'Traditional Scottish brewers yeast strain, well suited for malt forward beers. Tartan is a traditional strain that accentuates the malt character of Scottish and other malt forward styles. But don''t put it in a corner, it can also be used for other styles and works well in IPAs due to its clean fermentation character. For a higher ester profile, use this ale yeast at the top end of the temperature range.', 'Wee Heavy, Red Ale, American Brown Ale, Cream Ale, American Wheat Beer, Blonde Ale, Black IPA, Robust Porter, American Stout, Winter Seasonal Beer, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, English Mild, Bitter, Extra Special Bitter, Pale Ale, Stout, Irish Dry, English IPA, Stout, Oatmeal, Stout, Tropical, British Strong Ale, English Barleywine, Old Ale, Stout, Foreign Extra, California Common, American Amber Ale, American IPA, Red IPA, American Pale Ale, Imperial IPA, Altbier', 'A01, A10, GY044, WLP028, WY1728', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy1275-thames-valley-ale-wyeast', 'Thames Valley Ale', 'ale', 'liquid', 'Wyeast', 'WY1275', 16.7, 22.2, 'medium-low', 74.0, 72.0, 76.0, '10', 'This strain produces classic British bitters with a rich, complex flavor profile. The yeast has a light malt character, low fruitiness, low esters and is clean and well balanced.', 'Bitters, Altbier, Brown Ale, Porter, Stout', 'WLP023', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy1882-thames-valley-ale-ii-wyeast', 'Thames Valley Ale II', 'ale', 'liquid', 'Wyeast', 'WY1882', 15.6, 21.1, 'high', 75.0, 72.0, 78.0, '10', 'This strain was originally sourced from a now defunct brewery on the banks of the River Thames outside of Oxford, England. Thames Valley II produces crisp, dry beers with a rich malt profile and moderate stone fruit esters. This attenuative strain is also highly flocculent resulting in bright beers not requiring filtration. A thorough diacetyl rest is recommended after fermentation is complete.', 'Bitters, Brown Ale, Altbier, Porter', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-bbxmad1-the-mad-fermentationist-saison-blend-bootleg-biology', 'The Mad Fermentationist Saison Blend', 'ale', 'liquid', 'Bootleg Biology', 'BBXMAD1', 20.0, 26.7, 'medium', 95.0, 90.0, 100.0, '9', 'Fine tuned over two years, this blend morphed over time to become an elegant powerhouse of classic Saison spice, stone-fruit Brett, lactic tartness and a dry but well-rounded body. The final master blend consists of Saison yeast, wild Saccharomyces, rare Brettanomyces and an opportunistic Lactobacillus culture.

At temperatures as low as 68F (20C) The Mad Fermentationist Saison Blend exhibits a relatively clean primary fermentation profile and high attenuation. Traditional saison temperatures (around 80F/27C) bring out citrus and elevated phenols (pepper and clove). The Brett character shifts depending on wort composition, as maltier beers emphasize cherry and stone fruit qualities.

This blend integrates beautifully with fruity and tropical hops, with the unique Brett culture keeping hop aromatics crisp and bright for an extended time. For best results use a highly fermentable wort, dry hopping during the tail of active fermentation, and carbonating naturally.', 'Saison', NULL, 'Saccharomyces, Brettanomyces and Lactobacillus', 0, NULL),
  ('bm-yeast-wlp4645-transatlantic-berliner-blend-the-yeast-bay', 'Transatlantic Berliner Blend', 'ale', 'liquid', 'The Yeast Bay', 'WLP4645', 18.9, 23.9, 'medium-low', 92.5, 85.0, 100.0, '11', 'Transatlantic Berliner Blend is a blend of a clean Saccharomyces cerevisiae strain (Germany), a healthy dose of Lactobacillus brevis – Strain TYB282 (Mexico) isolates, and a touch of our Beersel Brettanomyces Blend (Belgium) and Brettanomyces bruxellensis - Strain TYB184 (US). This culture will ferment to a crisp dryness over time and produce the trademark Berliner Weisse lactic acid backbone, with a touch of Brettanomyces tart citrus character and funk. ', 'Sours', NULL, 'Saccharomyces cerevisia, Lactobacillus brevis, Brettanomyces bruxellensis, Brettanomyces ', 0, NULL),
  ('bm-yeast-b48-triple-double-imperial-yeast', 'Triple Double', 'ale', 'liquid', 'Imperial Yeast', 'B48', 18.3, 25.0, 'medium', 76.0, 74.0, 78.0, '12', 'Classic high gravity Belgain strain for Trappist-style ales. The perfect strain for your classic abbey ales. Triple Double produces moderate esters with low to no phenolic characteristics. This strain is tried and true and works perfectly in a production environment. Keep an eye on Triple Double, it likes to sit on top of the wort throughout fermentation which may result in a slower than normal fermentation. This strain is very alcohol tolerant, so don''t be afraid to throw high gravity worts its way. ', 'Belgian Tripel, Belgian Golden Strong Ale, Belgian Dubbel, Belgian Quad, Trappist Single, Belgian Dark Strong Ale, Blonde Ale, Belgian Pale Ale', 'B63, WLP530, WY3787', NULL, 0, NULL),
  ('bm-yeast-oyl-200-tropical-ipa-omega-yeast', 'TROPICAL IPA', 'ale', 'liquid', 'Omega Yeast', 'OYL-200', 21.1, 29.4, 'low', 86.0, 82.0, 90.0, '10', 'A unique Saccharomyces strain that produces delicate, tart, tropical mango and pineapple fruit characteristics with a clean finish. Try higher fermentation temperatures to really bring out the tropical aspects. It''s stubbornly nonflocculent, but the results are worth the trouble.', 'Ales', 'WLP644', NULL, 0, NULL),
  ('bm-yeast-uberweizen-escarpment-labs', 'Uberweizen', 'ale', 'liquid', 'Escarpment Labs', NULL, 17.8, 23.9, 'medium', 76.0, 72.0, 80.0, '9', 'A slightly more attenuative German Hefeweizen strain which still displays prominent banana/clove profile. ', 'Hefeweizen', 'GY107,OYL-021,OYL-022,WLP300,WLP380,WY3068,WY3333,G01,WB-06,T-58,M20', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-l28-urkel-imperial-yeast', 'Urkel', 'lager', 'liquid', 'Imperial Yeast', 'L28', 11.1, 14.4, 'medium', 73.0, 71.0, 75.0, '10', 'Excellent choice for your Czech lager fermentations. Urkel allows for a nice balance between hops and malt. This strain can be slightly sulphery during fermentation, but it cleans up during lagering. Fermentation at the higher end of the range will produce a beer with minimal sulfur and a light ester profile with that classic Czech edge you are looking for. ', 'Czech Pilsner, Czech Amber Lager, Czech Dark Lager, American Lager, Pre-Prohibition Lager, Schwarzbier, American Lager, German Pils, Dunkels, Helles, Mexican Lager, Vienna Lager, Rauchbier, Dortmunder Export, Maibock, Bock, Marzen, Baltic Porter, Doppelbock, Eisbock, Bière de Garde', 'L17', NULL, 0, NULL),
  ('bm-yeast-m44-us-west-coast-mangrove-jack', 'US West Coast', 'ale', 'dry', 'Mangrove Jack', 'M44', 15.0, 23.3, 'high', 85.0, 80.0, 90.0, '11', 'A top fermenting ale strain suitable for American style ales. This yeast produces an exceptionally clean flavor, ideal for when you want the hop character to really punch through. Beers fermented with this strain will finish dry, and very light beers will not be thin or watery. Acidity will be low, and mouthfeel will be light and soft on the palate with a smooth non-astringent texture. As this strain is highly flocculant and resilient and not prone to autolysis, it is excellent for cask or bottle conditioning.', 'Americal Pale Ale, Double IPA, American Imperial Stout', 'WY1056,WLP001,US-05,RVA-101,A07,OYL-004,BRY-97,BBUSA1,GY001', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-vermont-ale-escarpment-labs', 'Vermont Ale', 'ale', 'liquid', 'Escarpment Labs', 'ES-VT', 18.9, 22.2, 'medium', 78.0, 73.0, 83.0, '14', 'This high-character American ale yeast produces hop-accentuating fruity esters, accentuating stone fruit and citrus character, accompanied by a smooth body. This yeast is quite popular for fruity, hazy-style IPAs. We recommend fermenting at 19-20ºC initially, then raising to 22ºC to complete the fermentation, and holding warm for several days in order to clean up. We highly recommend attention to temperature control with this yeast.', 'IPA, Pale Ales, Hazy IPAs', 'OYL-052,GY054,WLP4000,WLP095,A04,ECY29,RVA-104,LB-NE', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp4000-vermont-ale-the-yeast-bay', 'Vermont Ale', 'ale', 'liquid', 'The Yeast Bay', 'WLP4000', 17.8, 22.2, 'medium-low', 80.0, 78.0, 82.0, '11', 'Isolated from a uniquely crafted double IPA out of the Northeastern United States and originally of British lineage, this single strain of Saccharomyces cerevisiae produces a balanced fruity ester profile of peaches and light citrus that complements any aggressively hopped beer. ', 'IPA, Pale Ales, Hazy IPAs', 'OYL-052,GY054,WLP095,A04,ECY29,RVA-104,ES-VT,LB-NE', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-gy054-vermont-ipa-gigayeast', 'VERMONT IPA', 'ale', 'liquid', 'GigaYeast', 'GY054', 16.7, 23.9, 'medium-low', 80.0, 78.0, 82.0, '11', 'From one of the best examples of an east coast IPA. This yeast attenuates slightly less than NorCal Ale #1 and leaves a beer with more body and a slight fruity ester that is amazing with aromatic hops. ', 'Imperial Pale Ale, American Wheat Beer, Pale Ale, Bitter, West Coast Amber, ESB', 'OYL-052,WLP4000,WLP095,A04,ECY29,RVA-104,ES-VT,LB-NE', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-061-voss-kveik-omega-yeast', 'VOSS KVEIK', 'ale', 'liquid', 'Omega Yeast', 'OYL-061', 22.2, 36.7, 'medium', 78.5, 75.0, 82.0, '12', 'A traditional Norwegian kveik directly from the Gjernes farmstead, Voss Kveik''s orange-citrus notes present throughout its wide temperature range. So, like the mango-honey profile of Hothead (OYL-057), Voss Kveik''s orange-citrus is relatively clean across its fermentation temperature range, and pairs well with citrusy, fruity hops. Ester intensity and fermentation speed take off at higher temperatures. Non-phenolic and no fusels, even at higher temperatures.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA', 'Lallebrew Voss', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-voss-kveik-escarpment-labs', 'Voss Kveik', 'ale', 'liquid', 'Escarpment Labs', 'ES-VOSS', 25.0, 41.7, 'high', 75.5, 70.0, 81.0, '18', 'One of the most famous Norwegian Kveik yeasts. This is a single strain selected from Sigmund Gjernes'' Voss Kveik. This yeast can ferment at up to 42ºC (Sigmund pitches at 40ºC and free rises from there!) with clean flavours and a prominent citrus aroma. We recommend warm fermentation temperatures (>25ºC), highly fermentable wort and yeast nutrients to ensure complete attenuation. This strain is also very alcohol tolerant and highly flocculent, although it will still produce considerable haze in heavily dry hopped NEIPAs. ', 'IPA, Pale Ales, Hazy IPAs', 'OYL-061, LalBrew Voss', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wlp4020-wallonian-farmhouse-the-yeast-bay', 'Wallonian Farmhouse', 'ale', 'liquid', 'The Yeast Bay', 'WLP4020', 20.0, 25.6, 'high', 90.5, 81.0, 100.0, '9', 'Isolated from a unique farmhouse-style ale that hails from the Walloon region of Belgium, this strain of STA1+ Saccharomyces cerevisiae imparts a slight earthy funk and tart character to the beer, and is a very mild producer of slightly spicy and mildly smokey flavor compounds. We recommend controlling the dryness by adding malts or adjuncts to the mash tun that will lend some body and residual sweetness to the beer. This strain exhibits high diastatic activity.', NULL, NULL, 'Saccharomyces cerevisiae', 0, 1),
  ('bm-yeast-wlp4022-wallonian-farmhouse-ii-the-yeast-bay', 'Wallonian Farmhouse II', 'ale', 'liquid', 'The Yeast Bay', 'WLP4022', 20.0, 26.7, 'medium-low', 90.0, 86.0, 94.0, '14', 'This is a single strain of Saccharomyces cerevisiae isolated from the same source as our Wallonian Farmhouse strain, a well-known brewery hailing from the Walloon region of Belgium. Slightly less attenuative and exhibiting a more restrained phenolic and expressive ester profile than Wallonian Farmhouse I, this yeast exhibits a great balance of fruitiness and rustic farmhouse character.', NULL, NULL, NULL, 0, NULL),
  ('bm-yeast-wlp4023-wallonian-iii-farmhouse-the-yeast-bay', 'Wallonian III Farmhouse', 'ale', 'liquid', 'The Yeast Bay', 'WLP4023', 20.0, 26.7, 'medium-low', 90.0, 86.0, 94.0, '14', 'This is a single strain of STA1+ Saccharomyces cerevisiae isolated from a well-known brewery hailing from the Walloon region of Belgium and exhibits a balanced profile of esters and phenols. This yeast is similar to a classic saison strain offered by many other yeast manufacturers, without the slow/low attenuation and stalling issues often observed in those cultures. This strain exhibits moderate-high diastatic activity. ', NULL, NULL, 'Saccharomyces cerevisiae var dia.', 0, 1),
  ('bm-yeast-wy3068-weihenstephan-weizen-wyeast', 'Weihenstephan Weizen', 'ale', 'liquid', 'Wyeast', 'WY3068', 17.8, 23.9, 'low', 75.0, 73.0, 77.0, '10', 'The classic and most popular German wheat beer strain used worldwide. This yeast strain produces a beautiful and delicate balance of banana esters and clove phenolics. The balance can be manipulated towards ester production through increasing the fermentation temperature, increasing the wort density, and decreasing the pitch rate. Over pitching can result in a near complete loss of banana character. Decreasing the ester level will allow a higher clove character to be perceived. Sulfur is commonly produced, but will dissipate with conditioning. This strain is very powdery and will remain in suspension for an extended amount of time following attenuation. This is true top cropping yeast and requires fermentor headspace of 33%.', 'Hefeweizen, Wheats, Weissbier, Fruit Beers', 'GY107,OYL-021,OYL-022,WLP300,WLP380,WY3333,G01,WB-06,T-58,M20', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-weizen-i-escarpment-labs', 'Weizen I', 'ale', 'liquid', 'Escarpment Labs', NULL, 17.8, 23.9, 'low', 72.5, 70.0, 75.0, '11', 'The classic German Hefeweizen strain, with ample potential to create the characteristic clove and banana flavours. Clove character can be emphasized though a ferulic acid rest in the mash, as well as by using a lower fermentation temperature. Banana ester (isoamyl acetate) character can be emphasized by slightly underpitching, creating a more fermentable wort, and/or using a higher fermentation temperature.', 'Hefeweizen', 'GY107,OYL-021,OYL-022,WLP300,WLP380,WY3068,WY3333,G01,WB-06,T-58,M20', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-004-west-coast-ale-i-omega-yeast', 'West Coast Ale I', 'ale', 'liquid', 'Omega Yeast', 'OYL-004', 15.6, 22.8, 'medium-low', 76.5, 73.0, 80.0, '11', 'Chico is a reliable, versatile and popular neutral foundation for displays of malts and hops. Highly attenuating and moderately flocculating, it ferments crisp and clean with light citrus notes under 66.', 'Ales, IPA, Stouts', 'WY1056,WLP001,US-05,RVA-101,A07,BRY-97,M44,BBUSA1,GY001', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-009-west-coast-ale-ii-omega-yeast', 'WEST COAST ALE II', 'ale', 'liquid', 'Omega Yeast', 'OYL-009', 15.6, 22.2, 'medium', 74.0, 72.0, 76.0, '10', 'West Coast Ale II is a consistent, well flocculating, well attenuating and easy clearing neutral strain. Slightly fruitier than West Coast Ale I (OYL-004) and clean with a lightly perceptible nuttiness, its subtle citrus character finishes slightly tart at the cool end, and more fruit character emerges as fermentation temperatures increase.', 'Ales', 'WY1272, WLP051', NULL, 0, NULL),
  ('bm-yeast-oyl-043-west-coast-ale-iii-omega-yeast', 'WEST COAST ALE III', 'ale', 'liquid', 'Omega Yeast', 'OYL-043', 18.3, 20.0, 'medium-high', 79.5, 76.0, 83.0, '11', 'Neutral and versatile, this strain is low ester-producing with balanced flavor and aroma. Highly alcohol tolerant. Similar to West Coast Ale I (OYL-004) but faster and more flocculent.', 'Ales', 'WLP090', NULL, 0, NULL),
  ('bm-yeast-oyl-050-west-coast-ale-iv-omega-yeast', 'WEST COAST ALE IV', 'ale', 'liquid', 'Omega Yeast', 'OYL-050', 16.7, 23.3, 'medium-high', 76.5, 73.0, 80.0, '10', 'An easy to handle strain, this neutral-tasting, quick-and-good flocculator and highly productive top cropper has excellent attenuation. Any fruity esters are somewhat mild through its higher temperature range, though they do decrease at the lower end. The relatively subtle yeast-contributed flavor cedes pleasantly to hops and malts.', 'Ales', 'WY1217', NULL, 0, NULL),
  ('bm-yeast-wy1217-west-coast-ipa-wyeast', 'West Coast IPA', 'ale', 'liquid', 'Wyeast', 'WY1217', 16.7, 23.3, 'medium-high', 76.5, 73.0, 80.0, '10', 'This strain is ideally suited to the production of West Coast-style American craft beers, especially pale, IPA, red, and specialties. Thorough attenuation, temperature tolerance, and good flocculation make this an easy strain to work with. Flavor is balanced neutral with mild ester formation at warmer temperatures, allowing hops, character malts, and flavorings to show through.', 'Pale Ales, Brown Ales, IPA, Scottish Light, Double IPA', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-oyl-105-west-coast-lager-omega-yeast', 'WEST COAST LAGER', 'lager', 'liquid', 'Omega Yeast', 'OYL-105', 14.4, 20.0, 'high', 69.0, 67.0, 71.0, '9', 'A lager strain that performs very well at ale temperatures, this strain is ideal for California common beer, also known as steam beer. Malty and crystal clear, it is considered by many to be best in its upper temperature range, around 65°F / 18°C.', 'Lagers', 'WLP810', NULL, 0, NULL),
  ('bm-yeast-wy1469-west-yorkshire-ale-wyeast', 'West Yorkshire Ale', 'ale', 'liquid', 'Wyeast', 'WY1469', 17.8, 22.2, 'high', 69.0, 67.0, 71.0, '9', 'This strain produces ales with a full chewy malt flavor and character, but finishes dry, producing famously balanced beers. Expect moderate nutty and stone-fruit esters. Best used for the production of cask-conditioned bitters, ESB and mild ales. Reliably flocculent, producing bright beer without filtration.', 'English IPA, Stout, Bitters', NULL, 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wy1099-whitbread-ale-wyeast', 'Whitbread Ale', 'ale', 'liquid', 'Wyeast', 'WY1099', 17.8, 23.9, 'medium-high', 70.0, 68.0, 72.0, '10', 'A mildly malty and slightly fruity fermentation profile. It is less tart and dry than Wyeast 1098 British Ale. With good flocculation characteristics, this yeast clears well without filtration. Low fermentation temperatures will produce a clean finish with a very low ester profile.', 'Brown Ale, Stout, English IPA, Blonde Ale, Bitters', 'S-04', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-b44-whiteout-imperial-yeast', 'Whiteout', 'ale', 'liquid', 'Imperial Yeast', 'B44', 16.7, 22.2, 'medium-low', 74.0, 72.0, 76.0, '10', 'The go-to brewing yeast strain for wit beers. Whiteout produces an excellent balance of spicy phenolic character and esters. Along with the necessary aromatics, this strain produces a significant amount of acidity which is perfect for wits and other light colored Belgian ales. Whiteout can be flocculent during fermentation, then become non-flocculent at the end. This may lead to slower than normal fermentation.', 'Hefeweizen, Witbier, Belgian IPA, Trappist Single, Saison', 'GY020,WLP320,WY1010', 'Saccharomyces cerevisiae', 0, NULL),
  ('bm-yeast-wild-thing-escarpment-labs', 'Wild Thing', 'ale', 'liquid', 'Escarpment Labs', NULL, 25.0, 25.0, 'medium', 75.0, 75.0, 75.0, '9', 'This wild Ontario ale yeast was isolated from an apple in a local orchard. Wild Thing produces distinct clove, spice, and subtle banana and apple fruit aroma. The taste is dry, spicy and clean. May require temperature ramping to 25C to ensure high attenuation. NOTE: This strain contains the STA1 gene, meaning it is a diastatic yeast. Many industrial yeasts are diastatic, due to the desire for very high attenuation levels. However extra care must be taken to ensure these yeasts do not cross-contaminate non-diastatic yeasts. Contact us with any questions or concerns. ', 'Ales', NULL, NULL, 0, 1),
  ('bm-yeast-wildbrew-philly-sour-lallemand', 'WildBrew Philly Sour', 'ale', 'dry', 'Lallemand', NULL, 20.0, 25.0, 'high', 85.0, 80.0, 90.0, NULL, 'WildBrew Philly Sour is a unique species of Lachancea selected from nature by University of the Sciences in Philadelphia, PA, USA. Philly Sour produces moderate amounts of lactic acid in addition to ethanol in one simple fermentation step. This first yeast in the WildBrew series is a great choice for innovative, sessionable sour beers with refreshing acidity and notes of stone fruit. With high attenuation, high flocculation and good head retention, WildBrew Philly Sour has resistance to hops which make it perfect for Sour IPA''s.', 'Berliner Weiss, Gose, American Lambic Style, American Wild Ales, Sour IPAs', NULL, 'Lachancea spp', 0, NULL),
  ('bm-yeast-oyl-030-wit-omega-yeast', 'WIT', 'ale', 'liquid', 'Omega Yeast', 'OYL-030', 16.7, 23.9, 'medium', 74.0, 72.0, 76.0, '12', 'Enthusiastically top cropping, this essential Wit yeast is distinctive for the popular, refreshing, easy-drinking summer style. Spicy phenolics carry the flavoring, while at the same time being supported—but not overshadowed— by good ester character. Lightly tart and dry', 'Ales', 'WY3944, WLP400', NULL, 0, NULL),
  ('bm-yeast-m10-workhorse-mangrove-jack', 'Workhorse', 'lager', 'dry', 'Mangrove Jack', 'M10', 15.0, 32.2, 'medium', 85.0, 80.0, 90.0, NULL, 'A top fermenting yeast which produces a clean, crisp flavour suitable for a wide variety of styles with different fermenting temperatures. This versatile yeast is well suited to making cask or bottle conditioned beer.', 'Lager, Baltic Porter', NULL, NULL, 0, NULL),
  ('bm-yeast-wy1087-wyeast-bohemian-ale-blend-wyeast', 'Wyeast Bohemian Ale Blend', 'ale', 'liquid', 'Wyeast', 'WY1087', 17.8, 22.2, 'medium-high', 73.0, 71.0, 75.0, '11', 'Formerly known as Wyeast Ale Blend 1540-PC, this is a blend of the best ale strains to provide quick starts, good flavor, and good flocculation. The profile of these strains provides a balanced finish for British and American style ales.', 'Pale Ales, Amber Ales, Brown Ales, IPAs, Double IPAs, Stouts', NULL, 'Saccharomyces cerevisiae', 0, NULL);

